def migrateTechpackImage(techpacks: list):
    if len(techpacks) == 0:
        print("techpacks are empty")

    techpackImageController = TechpackImageController()

    for index in range(0, len(techpacks)):
        techpack = techpacks[index]
        print(f"Processing techpack at {index} ...")

        techpack_id = techpack[0]
        techpack_source = techpack[6]
        techpack_style_row = techpack[5]
        group_image_id = f"{techpack[1]}_{techpack[3]}_{techpack[2]}_{techpack[4]}"

        techpack_style_filename = re.sub(r'\[|\]|\{|\}|"|path|:', "", techpack_style_row)

        techpack_style_filenames = techpack_style_filename.split(",") if techpack_style_filename else []
        try:
            if len(techpack_style_filenames):
                start_time = time.time()
                print(f"techpack at position {index}", techpack_id)
                for techpack_style_filename in techpack_style_filenames:
                    if techpack_style_filename and allowed_file(techpack_style_filename, ALLOWED_FILE_TYPE):
                        print(f"processing file in techpack {index}", techpack_style_filename)
                        techpackImageController.save_techpack_image_to_db_v2(techpack_style_filename, techpack_id, techpack_source, "STYLE", group_image_id)
                print("techpack at %s took --- %s seconds ---" % (index, time.time() - start_time))

        except Exception as e:
            print(f"image at position {index} migrate failed", e)
            continue

        time.sleep(2)

