class MicrosoftGraphAdapter:
    def __init__(self, access_token=None):
        self.access_token = access_token

    def get_userinfo(self) -> Tuple[str, dict]:
        if self.access_token is None:
            logger.error(f"Access Token is invalid: {self.access_token}")
            return "Access Token is invalid", None


        # Call the Graph API to get user data
        headers = {
            'Authorization': f'Bearer {self.access_token}'
        }
        url = f"{DOMAIN}{USER_INFO_ENDPOINT}"
        response = requests.get(
            url,
            headers=headers
        )

        json_resp = response.json()
        if response.status_code != 200:
            error_message = json_resp.get('error').get('message', 'System error!')
            logger.error(f"[GET USERINFO] {error_message}]")
            if "token is expired" in error_message:
                return Auth.TOKEN_EXPIRED_MESSAGE, None

            return error_message, None

        res = {
            'email': json_resp.get('mail', None),
            'username': json_resp.get('displayName', None),
            "ms_id": json_resp.get('id', None),
        }
        return None, res

