class TrendEngineAdapter:
    def __init__(self):
        return super().__init__()

    def get_retail_prices(self, brand: str, product_name: str) -> (list | None):
        """
        Fetch retail prices for a given brand and product name.

        :param brand: The brand of the techpack style.
        :param product_name: The description of the techpack style.
        :return: A dictionary containing retail prices.
        """
        headers = {
            'Accept': 'application/json',
        }
        url = f"{DOMAIN}{RETAIL_PRICES_ENDPOINT}"
        res = None
        try:
            response = requests.get(
                url,
                headers=headers,
                params={
                    "brand": brand,
                    "product_name": product_name
                }
            )

            json_resp = response.json()
            if response.status_code != 200:
                error_message = json_resp.get('message', 'Unknown error')
                logger.error(f"Failed to fetch retail prices: {error_message}")
                return None

            res = json_resp.get('data', None) or None
        except requests.RequestException as e:
            logger.error(f"Request to Trend Engine failed: {e}")
            return None

        return res

