def authorize(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        current_user = None
        error_message = None

        # Techpack-02 flow: extract user information from JWT token
        sec_fetch_site = request.headers.get('sec-fetch-site') or None
        referrer = request.headers.get('Referer') or None
        # if referrer == TEHCPACK_02_REFFERER \
        #         and sec_fetch_site == Auth.SEC_FETCH_SITE_CROSS_SITE:
        if referrer == TEHCPACK_02_REFFERER:
            logger.info("Using JWT authentication flow")

            # Check if Authorization header is present
            if 'Authorization' not in request.headers:
                return jsonify({
                    "message": "Authorization header is missing."
                }), 401

            # Extract and verify the internal JWT token
            internal_token = request.headers['Authorization'].replace("Bearer ", "")
            if not internal_token:
                return jsonify({
                    "message": "Internal token has not found."
                }), 401

            if not _is_internal_jwt_token(internal_token):
                logger.error("Invalid internal token.")
                return jsonify({
                    "message": "Internal token is invalid."
                }), 401

            logger.info("Verifying Internal JWT token")
            authz_service = AuthzService()
            error_message, user_data = authz_service._verify_internal_token(internal_token)
            if error_message:
                logger.error(f"JWT auth failed: {error_message}")
                return jsonify({
                    "message": error_message
                }), 401

            # Convert User object to session format for backward compatibility
            current_user = _build_current_user_session(user_data)
            if not current_user:
                logger.error("Failed to generate current user session")
                return jsonify({
                    "message": "Failed to generate current user session"
                }), 401

            return f(current_user, *args, **kwargs)

        # Techpack-01 flow: extract user information from session
        logger.info("Using session authentication flow")
        error_message, current_user = get_current_user()
        if error_message:
            return jsonify({
                "message": error_message
            }), 401

        if current_user is None:
            return jsonify({
                "message": "Authentication required"
            }), 401

        logger.info(f"Current User: {current_user.get('info', current_user)}")

        return f(current_user, *args, **kwargs)

    return decorated_function

