def _is_internal_jwt_token(token: str) -> bool:
    """
    Check if the token is an internal JWT token by examining its issuer
    """
    try:        
        # Decode without verification to check issuer
        unverified_payload = jwt.decode(
            token,
            options={"verify_signature": False, "verify_exp": False}
        )

        authz_service = AuthzService()
        token_issuer = unverified_payload.get('iss')
        return token_issuer == authz_service.internal_jwt_issuer

    except Exception as e:
        logger.debug(f"Token is not a valid JWT: {str(e)}")
        return False

auth/decorators.py::_build_current_user_.source_code:
def _build_current_user_session(current_user: dict) -> dict:
    """
    Convert User object to session dictionary format for backward compatibility
    """
    if not current_user:
        return {}

    try:
        user_info = {
                'id': current_user.get('id'),
                'username': current_user.get('username'),
                'ms_id': current_user.get('ms_id'),
                'timezone': current_user.get('timezone'),
                'email': current_user.get('email'),
                'roles': current_user.get('roles', []),
                'permissions': current_user.get('permissions', []),
                'root': current_user.get('root')
        }
        user = User(**user_info)

        res = {
            'info': user,
            'techpack_filtration_attrs': current_user.get('resources', []),
        }
        return res
    except Exception as e:
        logger.error(f"Error converting user to session format: {str(e)}")
        return {}

