def authorize():
    # perform authorization
    error_message, current_user = authz()
    if error_message:
        logger.error(f"[Authorization Error] {error_message}]")
        if error_message == Auth.TOKEN_EXPIRED_MESSAGE:
            return jsonify({
                "message": error_message,
            }), 401

        return jsonify({
            "message": "Unauthorized",
        }), 401

    # perform post authorization actions
    is_success = PostAuthorization(current_user).perform_action(PostAuthorizationAction.SAVE_SESSION)
    if not is_success:
        return jsonify({
            "message": "Unauthorized",
        }), 401

    # return success as token is verified
    return jsonify({
        "message": "Authorized",
    }), 200

