def authorize_v2():
    # return 401 if token is not passed
    if 'Authorization' not in request.headers:
        return 'AAD access token is missing.', None

    # perform authorization
    authz_svc = AuthzService()
    access_token = request.headers['Authorization'].replace("Bearer ", "")
    error_message, internal_token = authz_svc.authenticate_with_microsoft_token(access_token)
    if error_message:
        logger.error(f"[Authorization Error] {error_message}]")
        if error_message == Auth.TOKEN_EXPIRED_MESSAGE:
            return jsonify({
                "message": error_message,
            }), 401

        return jsonify({
            "message": "Unauthorized",
        }), 401

    # return success as token is verified
    return jsonify({
        "message": "Authorized",
        "internal_access_token": internal_token,
        "token_type": "Bearer",
        "expires_in": authz_svc.internal_jwt_expiry_hours * 3600
    }), 200

