class MyStaticCache():
    def __init__(self):
        self. __cache__ = {}
        self.EXPIRES = 1
        self.VALUE = 0

    def get(self, key):
        try:
            if self.__cache__[key][self.EXPIRES] > time.time():
                return self.__cache__[key]
            else:
                del self.__cache__[key]
                return None
        except KeyError:
            return None

    def set(self, key, value, duration = 3600):
        try:
            expire = time.time() + duration
        except TypeError:
            raise TypeError("Duration must be numeric")

        self.__cache__[key] = (value, expire)

    def clean(self):
        """Remove all expired items from the cache"""
        for key in self.__cache__.keys():
            self.get(key)

    def purge(self):
        """Remove all items from the cache"""
        self.__cache__ = {}

