config/helpers.py::convert_timezone.source_code:
def convert_timezone(timestamp: datetime.datetime, tz: str, base_tz=pytz.UTC, source_tz=None):
    if not timestamp or not isinstance(timestamp, datetime.datetime):
        logger.error("[convert_timezone] Error: invalid timestamp.")
        raise ValueError("Invalid timestamp!")

    if not tz:
        return timestamp

    try:
        if source_tz:
            # Use explicit source timezone
            source_timezone = pytz.timezone(source_tz)
            base_tz_timestamp = source_timezone.localize(timestamp)
        else:
            # Use default base_tz
            base_tz_timestamp = timestamp.replace(tzinfo=base_tz)

        desired_tz_timestamp = base_tz_timestamp.astimezone(pytz.timezone(tz)).replace(tzinfo=None)
    except Exception as e:
        logger.error(f"[convert_timezone] Error converting from {base_tz} to {tz}: {e}")
        raise Exception("Cannot convert timestamp!")

    return desired_tz_timestamp

