def convert_date_to_utc_str(date_str, user_timezone, datetime_format=DATETIME_FORMAT_ISO):
    """Parse date string (full or date-only), convert to UTC, return formatted string."""
    s = date_str.strip()
    try:
        dt = datetime.datetime.strptime(s, datetime_format)
    except ValueError as e:
        if len(s) >= 10:
            logger.debug("[convert_date_to_utc_str] date-only fallback for %r: %s", s, e)
            dt = datetime.datetime.strptime(s[:10] + TIME_SUFFIX_START_OF_DAY, datetime_format)
        else:
            logger.debug("[convert_date_to_utc_str] string too short for date-only fallback (%r): %s", s, e)
            raise
    return convert_timezone(dt, 'UTC', source_tz=user_timezone).strftime(datetime_format)

