def normalize_and_convert_date_range_to_utc(params_dict, start_key, end_key, current_user):
    start_date = params_dict.get(start_key) or ''
    end_date = params_dict.get(end_key) or ''
    if start_date and end_date:
        raw_start = start_date.strip()
        raw_end = end_date.strip()
        # Only append time suffix when we have a full date (10 chars: YYYY-MM-DD)
        if len(raw_start) == 10:
            start_date = raw_start + TIME_SUFFIX_START_OF_DAY
        if len(raw_end) == 10:
            end_date = raw_end + TIME_SUFFIX_END_OF_DAY
        params_dict[start_key] = start_date
        params_dict[end_key] = end_date

        if getattr(current_user, 'timezone', None):
            if start_date:
                try:
                    params_dict[start_key] = convert_date_to_utc_str(start_date, current_user.timezone)
                except (ValueError, Exception) as e:
                    logger.warning("[normalize_and_convert_date_range_to_utc] failed to convert start_date %r: %s", start_date, e)
            if end_date:
                try:
                    params_dict[end_key] = convert_date_to_utc_str(end_date, current_user.timezone)
                except (ValueError, Exception) as e:
                    logger.warning("[normalize_and_convert_date_range_to_utc] failed to convert end_date %r: %s", end_date, e)

