class TechpackCostingController:

    def __init__(self, current_user_session=None, costing_service=None):
        self.current_user_session = current_user_session
        self.techpack_costing_repo = TechpackCostingRepository(current_user_session)
        self.techpack_security_svc = TechPackSecurity(self.current_user_session)
        self.aeo_cm_yy_estimation_svc = AeoCmYyEstimationService(self.current_user_session)
        self.azure_storage_account_svc = AzureStorageContainerService()
        self.lfapim_adapter = LFApimAdapter()
        self.costing_svc = costing_service
        self.techpack_repo = TechpackRepository(current_user_session=current_user_session)
        self.email_processing_repo = EmailProcessingRepository(current_user_session=current_user_session)
        self.ai_estimation_report_svc = AiEstimationReportService()
        self.customer_repo = CustomerRepository()

    def get_rfq_costs_query_params(self, customer_name, style_no, season, customer_department):
        if not self.techpack_security_svc.has_permission(constants.Permissions.TECHPACK_DETAIL_XTS_ORDER_VIEW):
            return jsonify({
                "error_message": "Permission denied."
            }), 403

        params = self.techpack_costing_repo.get_query_params_by_techpack_details(
            customer_name, style_no, season, customer_department)
        if not params:
            return jsonify({
                "data": {
                    "suppliers": [],
                    "factories": [],
                    "production_countries": [],
                }
            }), 200

        return jsonify({
            "data": {
                "suppliers": params and params[0] or [],
                "factories": params and params[1] or [],
                "production_countries": params and params[2] or [],
            }
        }), 200

    def get_rfq_costs_details(self, customer_name, style_no, 
                              customer_department, season, request_params, 
                              context=None):
        if not context:
            context = {}

        if not self.techpack_security_svc.has_permission(
            constants.Permissions.TECHPACK_DETAIL_XTS_ORDER_VIEW):
            return jsonify({
                "error_message": "Permission denied."
            }), 403

        curr_user = self.current_user_session['info']
        rows = self.techpack_costing_repo.get_rfq_costs_by_techpack_details(
            customer_name, style_no, customer_department, season,
            request_params, context=context)

        if not rows:
            return jsonify({
                "data": []
            }), 200

        res = []
        for row in rows:
            res.append({
                "production_country": row[9],
                "supplier": row[1],
                "factory": row[2],
                "quotation_qty": row[0] and int(row[0]) or 0,
                "cm_cost": row[3] and round(float(row[3]), 2) or 0.0,
                "wash_cost": row[4] and round(float(row[4]), 2) or 0.0,
                "fabric_cost": row[5] and round(float(row[5]), 2) or 0.0,
                "trim_cost": row[6] and round(float(row[6]), 2) or 0.0,
                "total_fob_cost": row[7] and round(float(row[7]), 2) or 0.0,
                "rfq_created_date": convert_timezone(row[8], curr_user.timezone).strftime("%Y-%m-%d"),
            })

        return jsonify({
            "data": res,
        })

    def get_rfq_costs(self, customer_name, style_no, customer_department, 
                      season, request_params, context=None):
        def group_records(records):
            grouped_records, tmp = {}, {}
            for rec in records:
                xkey = f"{rec[9]}"
                quotation_qty = rec[0] and int(rec[0]) or 0
                cm_cost = rec[3] and round(float(rec[3]), 2) or 0.0
                wash_cost = rec[4] and round(float(rec[4]), 2) or 0.0
                fabric_cost = rec[5] and round(float(rec[5]), 2) or 0.0
                trim_cost = rec[6] and round(float(rec[6]), 2) or 0.0
                total_fob_cost = rec[7] and round(float(rec[7]), 2) or 0.0
                rfq_created_date = convert_timezone(rec[8], curr_user.timezone)
                if xkey not in tmp:
                    tmp.update({
                        xkey: {
                            "quotation_qty": quotation_qty,
                            "supplier": [rec[1]],
                            "factory": [rec[2]],
                            "cm_cost": [cm_cost],
                            "wash_cost": [wash_cost],
                            "fabric_cost": [fabric_cost],
                            "trim_cost": [trim_cost],
                            "total_fob_cost": [total_fob_cost],
                            "rfq_created_date": [rec[8]],
                            "production_country": rec[9],
                        }
                    })
                    grouped_records.update({
                        xkey: tmp[xkey],
                    })
                    continue

                tmp[xkey]["quotation_qty"] += quotation_qty

                supplier = rec[1]
                if supplier:
                    tmp[xkey]["supplier"].append(supplier)

                factory = rec[2]
                if factory:
                    tmp[xkey]["factory"].append(factory)

                if cm_cost > 0:
                    tmp[xkey]["cm_cost"].append(cm_cost)

                if wash_cost > 0:
                    tmp[xkey]["wash_cost"].append(wash_cost)

                if fabric_cost > 0:
                    tmp[xkey]["fabric_cost"].append(fabric_cost)

                if trim_cost > 0:
                    tmp[xkey]["trim_cost"].append(trim_cost)

                if total_fob_cost > 0:
                    tmp[xkey]["total_fob_cost"].append(total_fob_cost)
                if rfq_created_date:
                    tmp[xkey]["rfq_created_date"].append(rfq_created_date)

                grouped_records[xkey] = tmp[xkey]

            _res = []
            for _, v in grouped_records.items():
                min_cm_cost, max_cm_cost = min(v["cm_cost"]), max(v["cm_cost"])
                v["cm_cost"] = [min_cm_cost, max_cm_cost]

                min_wash_cost, max_wash_cost = min(v["wash_cost"]), max(v["wash_cost"])
                v["wash_cost"] = [min_wash_cost, max_wash_cost]

                min_fabric_cost, max_fabric_cost = min(v["fabric_cost"]), max(v["fabric_cost"])
                v["fabric_cost"] = [min_fabric_cost, max_fabric_cost]

                min_trim_cost, max_trim_cost = min(v["trim_cost"]), max(v["trim_cost"])
                v["trim_cost"] = [min_trim_cost, max_trim_cost]

                min_total_fob_cost, max_total_fob_cost = min(v["total_fob_cost"]), max(v["total_fob_cost"])
                v["total_fob_cost"] = [min_total_fob_cost, max_total_fob_cost]

                min_rfq_created_date, max_rfq_created_date = min(v["rfq_created_date"]), max(v["rfq_created_date"])
                v["rfq_created_date"] = [min_rfq_created_date.strftime("%Y-%m-%d"), max_rfq_created_date.strftime("%Y-%m-%d")]

                _item = {}
                for k, val in v.items():
                    if k in ('cm_cost', 'wash_cost', 'fabric_cost', 'trim_cost', 'total_fob_cost', 'rfq_created_date'):
                        _item[k] = val
                        continue

                    sub_total_item = len(set(val)) if isinstance(val, list) else val
                    _item[k] = sub_total_item

                _res.append(_item)

            return _res

        if not context:
            context = {}

        if not self.techpack_security_svc.has_permission(constants.Permissions.TECHPACK_DETAIL_XTS_ORDER_VIEW):
            return jsonify({
                "error_message": "Permission denied."
            }), 403

        curr_user = self.current_user_session['info']
        normalize_and_convert_date_range_to_utc(
            request_params, 'rfq_created_from_date', 'rfq_created_to_date', curr_user,
        )

        rfq_costs = self.techpack_costing_repo.get_rfq_costs_by_techpack_details(
            customer_name, style_no, customer_department, 
            season, request_params, context=context)

        res = group_records(rfq_costs)
        return jsonify({
            'data': res
        }), 200

    def queue_cm_yy_ai_estimation_auto_daily(self, customer_name: str, days_back: int, context=None) -> jsonify:
        logger.info(f"Start queue_cm_yy_costing_techpack_auto_daily. customer_name: {customer_name}")
        result = "Failed"
        data = []
        message = "Unknown error occurred."
        if days_back < 0:
            message = "Invalid days_back parameter."
            logger.error(message)
            return jsonify({"message": message, "result": result, "data": data}), 200
        match customer_name:
            case constants.Customers.AEO_CUSTOMER_NAME:
                queued_records = self.aeo_cm_yy_estimation_svc.queue_cm_yy_ai_estimation_auto_daily(days_back=days_back)
                if queued_records is None:
                    message = "Error occurred while queuing AEO CM/YY AI estimation."
                    logger.error(message)
                    return jsonify({"message": message, "result": result, "data": data}), 200
                for item in queued_records:
                    data.append(
                        {
                            "customer_name": item["customer_name"],
                            "customer_department": item["customer_department"],
                            "style_no": item["style_no"],
                            "style_season": item["style_season"],
                            "style_description": item["style_description"],
                            "techpack_source": item["techpack_source"],
                            "timestamp_lf_captured": item["timestamp_lf_captured"],
                            "first_version": {
                                "teckpack_style_log_id": item["first_techpack_style_log_id"],
                                "customer_name": item["customer_name"],
                                "customer_department": item["customer_department"],
                                "style_season": item["style_season"],
                                "style_no": item["style_no"],
                                "style_description": item["style_description"],
                                "timestamp_lf_captured": item["first_timestamp_lf_captured"]
                            },
                            "teckpack_style_log_id": item["latest_techpack_style_log_id"],
                            "attchment_pdf_techpack": item["attchment_pdf_techpack"],
                        }
                    )
                result = "Success"
                message = f"Queued {len(data)} styles"
            case _:
                logger.info(f"Unsupport customer: {customer_name}")
                message = f"Unsupport customer: {customer_name}"

        logger.info(f"End queue_cm_yy_costing_techpack_auto_daily...")
        return jsonify({"message": message, "result": result, "data": data}), 200

    def retrieve_cm_cost(self, request_params: dict, is_manual_sync=False, context=None) -> jsonify:
        if not context:
            context = {}

        source = request_params.get('techpack_source') or None
        if not source:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_source is empty.'
            }), 400

        if source not in (constants.TechpackSource.PLM_SOURCE, 
                          constants.TechpackSource.NON_PLM_SOURCE):
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_source is invalid.'
            }), 400

        attachment_file_name = request_params.get(
            'attchment_pdf_techpack') or None
        if not attachment_file_name:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'attachment_file_name is empty.'
            }), 400

        techpack_style_log_id = request_params.get('techpack_style_log_id', None)
        if not techpack_style_log_id:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_style_log_id was missed.'
            }), 400

        timestamp_lf_captured = request_params.get('timestamp_lf_captured', None)
        if not timestamp_lf_captured:
            # timestamp_lf_captured
            current_techpack_style_db = self.techpack_repo.get_techpack_detail(techpack_style_log_id, context)
            if current_techpack_style_db:
                timestamp_lf_captured = current_techpack_style_db[8]
                request_params.update({
                    'timestamp_lf_captured': timestamp_lf_captured,
                })

        current_style = CustomerTeckpackStyleLogModel(
            customer_name=request_params.get('customer_name', '') or '',
            customer_department=request_params.get('customer_department', '') or '',
            style_no=request_params.get('style_no', '') or '',
            style_season=request_params.get('style_season', '') or '',
            style_description=request_params.get('style_description', '') or '',
            teckpack_style_log_id=techpack_style_log_id,
            timestamp_lf_captured=timestamp_lf_captured,
        )
        group_unique_id = CommonUtil.generate_techpack_group_unique_id(current_style)
        if not group_unique_id:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_group_unique_id is invalid.'
            }), 400

        current_style.techpack_group_unique_id = group_unique_id
        request_params.update({
            'techpack_group_unique_id': group_unique_id,
        })

        error_message = ''        
        if context.get('client', '') == 'app':
            production_country_names = request_params.get(
                'production_country_names', '')
            if not production_country_names:
                error_message = 'Invalid production_country_names.'

            production_quantities = request_params.get('production_quantities', -1)
            if not production_quantities:
                error_message = 'Invalid production_quantities.'

            production_complexity = request_params.get(
                'production_complexity', '')
            if not production_complexity:
                error_message = 'production_complexity'

            if error_message:
                return jsonify({
                    'result': constants.GeneralStatus.FAILED_STATUS,
                    'message': error_message,
                }), 400

        cm_costing_params = self.get_cm_costing_param_from_customer_name(request_params.get('customer_name', ''))
        request_params.update({
            'cm_costing_params': cm_costing_params,
        })

        first_version_from_request = request_params.get("first_version", None)
        if not first_version_from_request:
            first_techpack_style_log_db = self.techpack_repo.get_first_techpack_style_log_version(current_style)
            if first_techpack_style_log_db:
                request_params.update({
                    'first_version': {
                        "teckpack_style_log_id": first_techpack_style_log_db[0],
                        "customer_name": first_techpack_style_log_db[1],
                        "customer_department": first_techpack_style_log_db[2],
                        "style_season": first_techpack_style_log_db[3],
                        "style_no": first_techpack_style_log_db[4],
                        "style_description": first_techpack_style_log_db[5],
                        "customer_techpack_status": first_techpack_style_log_db[6],
                        "timestamp_lf_captured": first_techpack_style_log_db[7]
                    },
                })
        #logger.info(f"first_version info: {request_params}")
        store_params = request_params.copy()
        store_params.update({
            'status': constants.TechpackCostingStatus.PROCESSING,
        })

        # register event
        res_store = self.techpack_costing_repo.store_style_cm_cost(store_params, current_style)
        if not res_store:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_CM_SYNC, is_manual_sync=is_manual_sync)

            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': f'Failed to update status to {constants.TechpackCostingStatus.PROCESSING}'    
            }), 400

        # update result
        ts = str(round(time.time() * 1000))
        local_file_name = f"{ts}-{attachment_file_name}"
        local_file_path = os.path.join(TEMP_PDF_FILE_DIR, local_file_name)
        download_blob_result = \
            self.azure_storage_account_svc.download_techpack_style_blob_to_file(attachment_file_name, local_file_path, source)

        if download_blob_result == False:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_CM_SYNC, is_manual_sync=is_manual_sync)

            error_message = f"cannot download techpack pdf: {local_file_name}"
            logger.error(error_message)

            store_params['status'] = constants.TechpackCostingStatus.FAILED
            store_params['error_detail'] = error_message            
            self.techpack_costing_repo.store_style_cm_cost(
                data=store_params, techpack_style_log_instance=current_style)

            remove_files([local_file_path])
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Download file failed.',
            }), 400

        logger.info(f"fetching cm cost for techpack_group_unique_id: {group_unique_id}...")
        cm_cost_res = self.lfapim_adapter.get_cm_cost(
            request_params, local_file_path)
        if isinstance(cm_cost_res, str):
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_CM_SYNC, is_manual_sync=is_manual_sync)

            error_message = f"failed to fetch cm cost data: {cm_cost_res}"
            logger.error(error_message)

            store_params['status'] = constants.TechpackCostingStatus.FAILED
            store_params['error_detail'] = error_message            
            self.techpack_costing_repo.store_style_cm_cost(data=store_params, techpack_style_log_instance=current_style)

            remove_files([local_file_path])
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Retrieve CM cost failed.',
            }), 400

        standardized_cm_cost = CommonUtil.transform_keys_to_camel_case(
            cm_cost_res)
        store_params.update({
            'status': constants.TechpackCostingStatus.SUCCESS,
            'cm_cost': standardized_cm_cost,
        })
        is_stored = self.techpack_costing_repo.store_style_cm_cost(
            data=store_params, techpack_style_log_instance=current_style)
        if not is_stored:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_CM_SYNC, is_manual_sync=is_manual_sync)

            logger.error("Failed to store cm cost data.")
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Failed to store cm cost data.'
            }), 400

        remove_files([local_file_path])

        # enqueue email notification if retrieved by user
        if is_manual_sync:
            res_enqueue = self._enqueue_cm_yy_retrieval_report(
                current_style, standardized_cm_cost, email_type=EmailType.CM_SYNC)
            if not res_enqueue:
                self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_CM_SYNC, is_manual_sync=is_manual_sync)

                store_params.update({
                    'status': constants.TechpackCostingStatus.FAILED,
                    'error_detail': "Failed to enqueue email processing.",
                })
                self.techpack_costing_repo.store_style_cm_cost(
                    data=store_params, techpack_style_log_instance=current_style)

                return jsonify({
                    'result': constants.GeneralStatus.FAILED_STATUS,
                    'message': f'Failed to enqueue email processing for {EmailType.CM_SYNC.value}'
                }), 400        

        return jsonify({
            'result': constants.GeneralStatus.SUCCESS_STATUS,
            'message': constants.TechpackCostingStatus.PROCESSED
        }), 200

