                        "customer_department": first_techpack_style_log_db[2],
                        "style_season": first_techpack_style_log_db[3],
                        "style_no": first_techpack_style_log_db[4],
                        "style_description": first_techpack_style_log_db[5],
                        "customer_techpack_status": first_techpack_style_log_db[6],
                        "timestamp_lf_captured": first_techpack_style_log_db[7]
                    },
                })

        store_params = request_params.copy()
        store_params.update({
            'status': constants.TechpackCostingStatus.PROCESSING,
        })

        # register event
        res_store = self.techpack_costing_repo.store_style_yy_cost(
            data=store_params, techpack_style_log_instance=current_style)
        if not res_store:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_YY_SYNC, is_manual_sync=is_manual_sync)

            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': f'Failed to update status to {constants.TechpackCostingStatus.PROCESSING}'    
            }), 400

        # update result
        ts = str(round(time.time() * 1000))
        local_file_name = f"{ts}-{attachment_file_name}"
        local_file_path = os.path.join(TEMP_PDF_FILE_DIR, local_file_name)
        download_blob_result = \
            self.azure_storage_account_svc.download_techpack_style_blob_to_file(attachment_file_name, local_file_path, source)

        if download_blob_result == False:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_YY_SYNC, is_manual_sync=is_manual_sync)

            error_message = f"cannot download techpack pdf: {local_file_name}"
            logger.error(error_message)

            store_params['status'] = constants.TechpackCostingStatus.FAILED
            store_params['error_detail'] = error_message            
            self.techpack_costing_repo.store_style_yy_cost(
                data=store_params, techpack_style_log_instance=current_style)

            remove_files([local_file_path])
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Download file failed.',
            }), 400

        logger.info(f"fetching yy cost for techpack_group_unique_id: {group_unique_id}...")
        yy_cost_res = self.lfapim_adapter.get_yy_cost(
            request_params, local_file_path)

        if isinstance(yy_cost_res, str):
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_YY_SYNC, is_manual_sync=is_manual_sync)

            error_message = f"failed to fetch yy cost data: {yy_cost_res}"
            logger.error(error_message)

            store_params['status'] = constants.TechpackCostingStatus.FAILED
            store_params['error_detail'] = error_message            
            self.techpack_costing_repo.store_style_yy_cost(data=store_params, techpack_style_log_instance=current_style)

            remove_files([local_file_path])
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': error_message,
            }), 400

        standardized_yy_cost = CommonUtil.transform_keys_to_camel_case(
            yy_cost_res)
        store_params.update({
            'yy_cost': standardized_yy_cost,
            'marker_diagram_file_name': '',
            'marker_diagram_html_script': standardized_yy_cost.get('markerDiagramHtmlScript', ''),
            'status': constants.TechpackCostingStatus.SUCCESS,
        })
        is_stored = self.techpack_costing_repo.store_style_yy_cost(
            data=store_params, techpack_style_log_instance=current_style)
        if not is_stored:
            self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_YY_SYNC, is_manual_sync=is_manual_sync)

            logger.error("Failed to store yy cost data.")
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Failed to store yy cost data.'
            }), 400

        remove_files([local_file_path])

        # enqueue email notification if retrieved by user
        if is_manual_sync:
            res_enqueue = self._enqueue_cm_yy_retrieval_report(current_style, standardized_yy_cost, email_type=EmailType.YY_SYNC)
            if not res_enqueue:
                self._enqueue_ai_estimation_error_email(request_params, EmailType.ERROR_YY_SYNC, is_manual_sync=is_manual_sync)

                store_params.update({
                    'status': constants.TechpackCostingStatus.FAILED,
                    'error_detail': "Failed to enqueue email processing.",
                })
                self.techpack_costing_repo.store_style_yy_cost(
                    data=store_params, techpack_style_log_instance=current_style)

                return jsonify({
                    'result': constants.GeneralStatus.FAILED_STATUS,
                    'message': f'Failed to enqueue email processing for {EmailType.YY_SYNC.value}'
                }), 400        

        return jsonify({
            'result': constants.GeneralStatus.SUCCESS_STATUS,
            'message': constants.TechpackCostingStatus.PROCESSED
        }), 200

    def create_xts_rfq(self, request_params: dict, is_manual_sync=False, context=None) -> jsonify:

        # valdiation
        if not context:
            context = {}

        source = request_params.get('techpack_source') or None
        if not source:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_source is empty.'
            }), 200

        if source not in (constants.TechpackSource.PLM_SOURCE, 
                          constants.TechpackSource.NON_PLM_SOURCE):
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_source is invalid.'
            }), 200

        techpack_style_log_id = request_params.get('techpack_style_log_id', None)
        if not techpack_style_log_id:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_style_log_id was missed.'
            }), 200

        timestamp_lf_captured = request_params.get('timestamp_lf_captured', None)
        if not timestamp_lf_captured:
            # timestamp_lf_captured
            current_techpack_style_db = self.techpack_repo.get_techpack_detail(techpack_style_log_id, context)
            if current_techpack_style_db:
                timestamp_lf_captured = current_techpack_style_db[8]
                request_params.update({
                    'timestamp_lf_captured': timestamp_lf_captured,
                })

        current_style = CustomerTeckpackStyleLogModel(
            customer_name=request_params.get('customer_name', '') or '',
            customer_department=request_params.get('customer_department', '') or '',
            style_no=request_params.get('style_no', '') or '',
            style_season=request_params.get('style_season', '') or '',
            style_description=request_params.get('style_description', '') or '',
            teckpack_style_log_id=techpack_style_log_id,
            timestamp_lf_captured=timestamp_lf_captured,
        )
        group_unique_id = CommonUtil.generate_techpack_group_unique_id(current_style)
        if not group_unique_id:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'techpack_group_unique_id is invalid.'
            }), 200

        current_style.techpack_group_unique_id = group_unique_id
        request_params.update({
            'techpack_group_unique_id': group_unique_id,
        })

        error_message = ''

        first_version_from_request = request_params.get("first_version", None)
        if not first_version_from_request:
            first_techpack_style_log_db = self.techpack_repo.get_first_techpack_style_log_version(current_style)
            if first_techpack_style_log_db:
                request_params.update({
                    'first_version': {
                        "teckpack_style_log_id": first_techpack_style_log_db[0],
                        "customer_name": first_techpack_style_log_db[1],
                        "customer_department": first_techpack_style_log_db[2],
                        "style_season": first_techpack_style_log_db[3],
                        "style_no": first_techpack_style_log_db[4],
                        "style_description": first_techpack_style_log_db[5],
                        "customer_techpack_status": first_techpack_style_log_db[6],
                        "timestamp_lf_captured": first_techpack_style_log_db[7]
                    },
                })

        store_params = request_params.copy()

        # Check exist
        existed_rfq_records = self.techpack_costing_repo.get_rfq_creation_by_techpack_group_unique_id(techpack_style_log_instance=current_style)
        if existed_rfq_records:
            # If exists, return the existing RFQ records
            return jsonify({
                'result': constants.GeneralStatus.SUCCESS_STATUS,
                'message': 'RFQ already exists.',
                'data': existed_rfq_records
            }), 200
        elif existed_rfq_records is None:
            logger.error(f"Failed to retrieve existing RFQ records for style: {current_style}")

        logger.info(f"Creating RQF for techpack_group_unique_id: {group_unique_id}...")
        rfq_creation_res = self.lfapim_adapter.create_xts_rfq(
            request_params)

        if isinstance(rfq_creation_res, str):
            error_message = f"failed to create RQF: {rfq_creation_res}"
            logger.error(error_message)

            store_params['status'] = constants.TechpackCostingStatus.FAILED
            store_params['error_detail'] = error_message
            stored_rfq_id = self.techpack_costing_repo.store_style_rfq_creation(data=store_params, techpack_style_log_instance=current_style)

            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': error_message,
                "data": rfq_creation_res
            }), 200

        statusCode = rfq_creation_res.get('statusCode', None)
        processResult = rfq_creation_res.get('processResult', '')
        xtsStyleId = rfq_creation_res.get('xtsStyleId', None)
        tpUploadId = rfq_creation_res.get('tpUploadId', None)
        xtsUserId = rfq_creation_res.get('xtsUserId', '')
        styleNo = rfq_creation_res.get('styleNo', '')
        season = rfq_creation_res.get('season', '')
        rfq_status = None
        if statusCode == 200:
            if processResult == constants.TechpackCostingStatus.SUCCESS:
                rfq_status = constants.TechpackCostingStatus.SUCCESS
            elif xtsStyleId and tpUploadId:
                rfq_status = constants.TechpackCostingStatus.SUCCESS
            else:
                rfq_status = constants.TechpackCostingStatus.FAILED
        else:
            rfq_status = constants.TechpackCostingStatus.FAILED

        store_params.update({
            'xts_rfq_creation_response': rfq_creation_res,
            'xts_style_id': xtsStyleId,
            'xts_tp_upload_id': tpUploadId,
            'xts_user_id': xtsUserId,
            'xts_style_no': styleNo,
            'xts_season': season,
            'status': rfq_status,
        })
        stored_rfq_id = self.techpack_costing_repo.store_style_rfq_creation(
            data=store_params, techpack_style_log_instance=current_style)
        if stored_rfq_id is None:
            logger.error("Failed to create RFQ.")
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Failed to store RFQ creation.'
            }), 200

        return jsonify({
            'result': rfq_status,
            'message': constants.TechpackCostingStatus.PROCESSED,
            "data": rfq_creation_res
        }), 200

    def _enqueue_cm_yy_retrieval_report(self, techpack_style: CustomerTeckpackStyleLogModel, retrieved_cost: dict, email_type: EmailType, context=None) -> bool:        
        if not context:
            context = {}

        res = None

        # timestamp_lf_captured
        style = self.techpack_repo.get_techpack_detail(
            techpack_style.teckpack_style_log_id, context={'is_apim': True})
        timestamp_lf_captured = style[8] or ''
        first_timestamp_lf_captured = None
        style_description = style[6] or ''

        # display name
        display_name = None
        customer = self.customer_repo.find_customer(techpack_style.customer_name)
        if customer:
            display_name = customer[7]

        # cm
        cm_cost, cm = None, 0.00
        if retrieved_cost and email_type == EmailType.CM_SYNC:
            cm_cost = retrieved_cost
        else:
            cm_cost = self.techpack_repo.get_cm_cost_by_techpack(techpack_style)        
            try:
                if cm_cost and not isinstance(cm_cost['xts_costing_cm'], dict):
                    first_timestamp_lf_captured = cm_cost['first_timestamp_lf_captured'] or None
                    cm_cost = transform_keys_to_camel_case(json.loads(cm_cost['xts_costing_cm']))
            except json.JSONDecodeError:
                logger.error("Failed to decode JSON for CM")
                return False

        if cm_cost:
            cm_summaries = cm_cost.get('costOfMakingSummary', [])
            if cm_summaries:
                cm = cm_summaries[0].get('cm', 0.0)

        # yy
        yy_cost, yy = None, 0.00
        if retrieved_cost and email_type == EmailType.YY_SYNC:
            yy_cost = retrieved_cost
        else:
            yy_cost = self.techpack_repo.get_yy_cost_by_techpack(techpack_style)
            try:
                if yy_cost and not isinstance(yy_cost['xts_costing_yy'], dict):
                    if not first_timestamp_lf_captured:
                        first_timestamp_lf_captured = yy_cost['first_timestamp_lf_captured'] or None
                    yy_cost = transform_keys_to_camel_case(json.loads(yy_cost['xts_costing_yy']))
            except json.JSONDecodeError:
                logger.error("Failed to decode JSON for YY")
                return False

        if yy_cost:
            yy_units = yy_cost.get('units', None)
            yy_dimension = ''
            if yy_units:
                yy_dimension = yy_units.get('dimension', '')

            yy_consumption = yy_cost.get('mainFabricConsumption', {})
            if yy_consumption:
                yy_gross_length = yy_consumption.get('grossLength', 0.0)
                if yy_dimension == "in":
                    yy = yy_gross_length / 36
                else:
                    yy = yy_gross_length

        # retail prices ref
        retail_prices_ref = []
        if techpack_style.style_description:
            style_description = techpack_style.style_description
            data = self.techpack_repo.get_detail_prices_ref(
                cust_name=techpack_style.customer_name, style_desc=techpack_style.style_description)
            if data:
                try:
                    parsed_data = json.loads(data)
                    for d in parsed_data:
                        price_ref = d.get('sales_price_usd', None)
                        if not price_ref:
                            continue

                        retail_prices_ref.append(float(price_ref))
                except json.JSONDecodeError:
                    logger.error("Failed to decode JSON for detail prices reference")
                    return False

        sorted_retail_prices_ref = sorted(retail_prices_ref)
        retail_prices_ref_range = None
        if sorted_retail_prices_ref:
            min_price = sorted_retail_prices_ref[0]
            min_price_notation = f'${min_price}'
            max_price = sorted_retail_prices_ref[-1]
            max_price_notation = f'${max_price}'
            retail_prices_ref_range = " - ".join([min_price_notation, max_price_notation])

        data = {
            'techpack_style_log_id': techpack_style.teckpack_style_log_id,
            'customer_name': techpack_style.customer_name,
            'display_name': display_name,
            'customer_department': techpack_style.customer_department,
            'style_no': techpack_style.style_no,
            'style_description': style_description or '',
            'season': techpack_style.style_season,
            'customer_techpack_status': techpack_style.customer_techpack_status or '',
            'first_timestamp_lf_captured': first_timestamp_lf_captured or '',
            "timestamp_lf_captured": timestamp_lf_captured or '',
            'cm': cm and round(cm, 2) or 0.00,
            'yy': yy and round(yy, 2) or 0.00,
            'retail_prices_ref_range': retail_prices_ref_range or ''
        }

        error_message, report_data = \
            self.ai_estimation_report_svc.compute_report_data([data])
        if error_message:
            logger.error(f"Failed to compute report data: {error_message}")
            return False

        default_cm_yy_daily_email_param = None
        default_config_daily_email = self.customer_repo.get_default_cm_and_yy_costing_param_by_customer_name(
            techpack_style.customer_name)
        if default_config_daily_email:
            default_cm_yy_daily_email_param = default_config_daily_email[5]

        # Generate HTML report using the factory        
        html_generator = ReportFactory.create_generator("html")
        html_body = html_generator.generate_report(
            report_data, template_name="ai_estimation_report.html")

        # Enqueue email processing
        current_user = self.current_user_session['info']
        email_template = EmailConfig.get(email_type.value, default_cm_yy_daily_email_param)
        recipients = current_user.email
        cc = ';'.join(email_template['cc'])
        bcc = ';'.join(email_template['bcc'])
        email_processing = EmailProcessing(
            subject=EmailConfig.format_subject(
                email_type.value, default_cm_yy_daily_email_param,
                subject_email_prefix=SUBJECT_EMAIL_PREFIX,
                style_no=techpack_style.style_no),
            body=html_body,
            send_to=recipients,
            cc=cc,
            bcc=bcc,
            email_type=email_type,
            raw_data=json.dumps(report_data)
        )
        res = self.email_processing_repo.enqueue(email_processing)
        if not res:
            logger.error('Failed to enqueue email processing.')
            return False

        return True

    def async_retrieve_cm_cost(self, request_params: dict, context=None) -> jsonify:
        """
        Async CM cost retrieving - fire and forget
        """
        if not context:
            context = {}

        # Submit to costing service
        res = self.costing_svc.async_retrieve_cm_cost(
            self.retrieve_cm_cost,
            request_params,
            True,
            context
        )
        if not res:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Failed to fetch cm cost.'    
            }), 400

        return jsonify({
            'result': constants.GeneralStatus.SUCCESS_STATUS,
            'message': constants.TechpackCostingStatus.PROCESSING
        }), 200

    def async_retrieve_yy_cost(self, request_params: dict, context=None) -> jsonify:
        """
        Async YY cost retrieving - fire and forget
        """
        if not context:
            context = {}

        # Submit to costing service
        res = self.costing_svc.async_retrieve_yy_cost(
            self.retrieve_yy_cost,
            request_params,
            True,
            context
        )
        if not res:
            return jsonify({
                'result': constants.GeneralStatus.FAILED_STATUS,
                'message': 'Failed to fetch yy cost.'
            }), 400

        return jsonify({
            'result': constants.GeneralStatus.SUCCESS_STATUS,
            'message': constants.TechpackCostingStatus.PROCESSING
        }), 200

    def _enqueue_ai_estimation_error_email(self, report_data: dict[str, any], email_type: EmailType, is_manual_sync: bool = False) -> bool:
        """
        Enqueu AI estimation error notification email 
        """
        if not is_manual_sync:
            logger.warning("Action is not manual sync.")
            return False

        if not report_data or (
            'customer_name' not in report_data \
            or 'style_no' not in report_data \
            or 'style_season' not in report_data \
            or 'techpack_style_log_id' not in report_data
        ):
            logger.error("Report data is invalid.")
            return False

        # display name
        display_name = None
        customer = self.customer_repo.find_customer(report_data['customer_name'])
        if customer:
            display_name = customer[7]

        # tpm url
        tpm_url = f"{APP_DOMAIN_02}/techpack/detail/{report_data['techpack_style_log_id']}"
        report_data.update({
            'tpm_url': tpm_url,
            'cm_url': f"{APP_DOMAIN_02}/techpack/detail/{report_data['techpack_style_log_id']}#ai",
        })

        current = convert_timezone(datetime.now(), 'Asia/Hong_Kong')
        current_datetime = current.strftime('%Y-%m-%d %H:%M:%S') if current else ''
        report_data.update({
            'display_name': display_name,
            'current_datetime': current_datetime,
        })

        default_cm_yy_daily_email_param = None
        default_config_daily_email = self.customer_repo.get_default_cm_and_yy_costing_param_by_customer_name(
            report_data['customer_name'])
        if default_config_daily_email:
            default_cm_yy_daily_email_param = default_config_daily_email[5]

        # Generate HTML report using the factory        
        html_generator = ReportFactory.create_generator("html")
        html_body = html_generator.generate_report(
            [report_data], template_name="ai_estimation_error_report.html")

        # Enqueue email processing
        try:
            current_user = self.current_user_session['info']
            recipients = current_user.email
            email_template = EmailConfig.get(email_type.value, default_cm_yy_daily_email_param)
            cc = ';'.join(email_template['cc'])
            bcc = ';'.join(email_template['bcc'])
            email_processing = EmailProcessing(
                subject=EmailConfig.format_subject(
                    email_type.value, default_cm_yy_daily_email_param,
                    subject_email_prefix=SUBJECT_EMAIL_PREFIX,
                    style_no=report_data['style_no']),
                body=html_body,
                send_to=recipients,
                cc=cc,
                bcc=bcc,
                email_type=email_type,
                raw_data=json.dumps([report_data])
            )
        except Exception as e:
            logger.error(f"Error converting Email Processing object: {str(e)}")
            return False

        res = self.email_processing_repo.enqueue(email_processing)
        if not res:
            logger.error("Failed to enqueue email.")
            return False

        return True

    def get_cm_costing_param_from_customer_name(self, customer_name, context=None):
        cm_costing_params = DEFAULT_CM_COSTING_PARAMS
        cm_and_yy_costing_params_in_db = self.customer_repo.get_default_cm_and_yy_costing_param_by_customer_name(customer_name)

        # cm_and_yy_costing_params_in_db is none or empty
        if cm_and_yy_costing_params_in_db:
            cm_costing_params_in_db = cm_and_yy_costing_params_in_db[3]
            if cm_costing_params_in_db:
                cm_costing_params = json.loads(cm_costing_params_in_db)
                logger.info(f"Using stored CM costing params for customer: {customer_name}: {cm_costing_params}")
        return cm_costing_params

    def get_yy_costing_param_from_customer_name(self, customer_name):
        yy_costing_params = DEFAULT_YY_COSTING_PARAMS
        cm_and_yy_costing_params_in_db = self.customer_repo.get_default_cm_and_yy_costing_param_by_customer_name(customer_name)

        # cm_and_yy_costing_params_in_db is none or empty
        if cm_and_yy_costing_params_in_db:
            yy_costing_params_in_db = cm_and_yy_costing_params_in_db[4]
            if yy_costing_params_in_db:
                yy_costing_params = json.loads(yy_costing_params_in_db)
                logger.info(f"Using stored YY costing params for customer: {customer_name}: {yy_costing_params}")
        return yy_costing_params

