interface Props {
  className?: string;
  initValue?: string;
  label?: string;
  name: string;
  prefix?: React.ReactNode;
  placeholder?: string;
  inputProps: InputProps;
  outerInputValue?: string;
  setOuterInputValue?: (value: string) => void;
}

CommonInput = ({
  className,
  label,
  placeholder,
  prefix,
  initValue = "",
  inputProps,
  outerInputValue,
  setOuterInputValue,
}: PropsWithChildren<Props>) => {
  const [value, setValue] = useState(initValue);

  const currentValue = outerInputValue || value;
  const setCurrentValue = setOuterInputValue || setValue;

