interface Props {
  className?: string;
  defaultWidth?: number;
  isFinished: boolean;
  maxDuration?: number;
}

ProgressBar = ({
  className,
  defaultWidth = 360,
  isFinished,
  maxDuration = 120,
}: Props) => {
  const barRef = useRef<HTMLDivElement | null>(null);

  const step = Math.floor((defaultWidth * 0.8) / maxDuration);
  const endProgressingStep = defaultWidth * 0.8;
  const [progressingWidth, setProgressingWidth] = useState(0);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    if (isFinished) {
      setProgressingWidth(progressingWidth + (defaultWidth - progressingWidth));
    } else if (progressingWidth < endProgressingStep) {
      const randomStep = Math.floor(Math.random() * (step * 2 - step) + step);
      const defaultDelay = Math.floor(Math.random() * 2);

      timer = setTimeout(() => {
        setProgressingWidth(progressingWidth + randomStep);
      }, defaultDelay * 1000);
    }

    return () => {
      clearTimeout(timer);
    };
  }, [defaultWidth, endProgressingStep, isFinished, progressingWidth, step]);

  return (
    <div
      ref={barRef}
      className={cn("h-2 relative overflow-hidden", className)}
      style={{ width: defaultWidth }}
    >
      <div
        className="absolute top-0 left-0 bg-accent-blue h-full transition-all delay-300"
        style={{ width: progressingWidth }}
      />
    </div>
  );
}

