function useAxiosInterceptor() {
  const navigate = useNavigate();

  const updateIsAuthorizationCalled = useTechpackContext(
    (s) => s.updateIsAuthorizationCalled
  );

  useEffect(() => {
    const responseInterceptor = axiosInstance.interceptors.response.use(
      (response) => {
        return response;
      },
      (error) => {
        const status = error.response.status;
        const message = error.response.data.message;

        if (status === 401 && message === "Session has expired") {
          toast.error("Your login session is expired, please sign in again", {
            duration: 2000,
            position: "top-right",
          });

          updateIsAuthorizationCalled(false);

          setTimeout(() => {
            navigate("/logout");
          }, 3000);
        }

        return Promise.reject(error);
      }
    );

    return () => {
      axiosInstance.interceptors.response.eject(responseInterceptor);
    };
  }, [navigate, updateIsAuthorizationCalled]);
}

