calculateTextWidth = (text: string, font: string) => {
  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");

  if (context) {
    context.font = font;

    const width = context.measureText(text).width;
    return Math.ceil(width);
  }

  return 0;
}

