    const techpackDetailChecked = [];

    for (const key of tpCheckList) {
      if (/\d{1,}-\d{1,}/.test(key)) {
        const [row] = key.split("-");

        if (+row === activeTechpackIdx) {
          techpackDetailChecked.push(key);
        }
      }
    }

    return techpackDetailChecked.length !== 2;
  };

  const isCompareFileCtaDisabled = disabledCompareFileCta();

  const getAllTPStyles = async () => {
    const techpackStyleUrlList: SendTPPDFFIleRequest[] = [];
    const techpackStyleNotActiveIndexes: number[] = [];
    for (const key of tpCheckList) {
      if (/^\d{1,}$/.test(key)) {
        const [rowIdx] = key.split("-");

        if (Number(rowIdx) !== activeTechpackIdx) {
          techpackStyleNotActiveIndexes.push(Number(rowIdx));
        }
      }

      if (/\d{1,}-\d{1,}/.test(key)) {
        const [rowIdx, rowItemIdx] = key.split("-");

        if (Number(rowIdx) !== activeTechpackIdx) {
          continue;
        }

        techpackStyleUrlList.push({
          file_name: techpackDetail[Number(rowItemIdx)].attchment_pdf_techpack,
          source: techpackDetail[Number(rowItemIdx)].techpack_source,
          techpack_id: `${
            techpackDetail[Number(rowItemIdx)].techpack_style_log_id
          }`,
        });
      }
    }

    let techpackOtherVersions: SendTPPDFFIleRequest[] = [];

    try {
      const techpackOtherVersionsResponse = await Promise.allSettled(
        techpackStyleNotActiveIndexes.map((idx) =>
          TechpackService.getTechpackListDetail(techpackList[idx])
        )
      );

      for (const tp of techpackOtherVersionsResponse) {
        if (tp.status === "fulfilled") {
          const tpPdfFiles: SendTPPDFFIleRequest[] = tp.value.data
            .techpack_detail.length
            ? tp.value.data.techpack_detail.map((item) => {
                return {
                  file_name: item.attchment_pdf_techpack,
                  source: item.techpack_source,
                  techpack_id: `${item.techpack_style_log_id}`,
                };
              })
            : [];
          techpackOtherVersions = [...techpackOtherVersions, ...tpPdfFiles];
        }
      }
    } catch (error) {
      console.error("query tp list pdf files error", error);
    }

    return [...techpackStyleUrlList, ...techpackOtherVersions];
  };

  const getLatestTPStyles = () => {
    const techpackStyleUrlList: SendTPPDFFIleRequest[] = [];
    let isActiveTPFound = false;

    const tpStyleFoundDict: Record<string, boolean> = {};
    for (const key of tpCheckList) {
      if (/^\d{1,}$/.test(key)) {
        const [rowIdx] = key.split("-");

        if (!tpStyleFoundDict[rowIdx]) {
          techpackStyleUrlList.push({
            file_name: techpackList[Number(rowIdx)].attchment_pdf_techpack,
            source: techpackList[Number(rowIdx)].techpack_source,
            techpack_id: `${
              techpackList[Number(rowIdx)].techpack_style_log_id
            }`,
          });

          tpStyleFoundDict[rowIdx] = true;
        }
      }

      // if techpack list detail is shown
      if (/\d{1,}-\d{1,}/.test(key)) {
        const [rowIdx] = key.split("-");

        if (
          Number(rowIdx) === activeTechpackIdx &&
          !isActiveTPFound &&
          !tpStyleFoundDict[rowIdx]
        ) {
          techpackStyleUrlList.push({
            file_name: techpackList[Number(rowIdx)].attchment_pdf_techpack,
            source: techpackList[Number(rowIdx)].techpack_source,
            techpack_id: `${
              techpackList[Number(rowIdx)].techpack_style_log_id
            }`,
          });
          isActiveTPFound = true;
          tpStyleFoundDict[rowIdx] = true;
        }
      }
    }

    return techpackStyleUrlList;
  };

  const onRetrieveTechpackPdfFiles = async () => {
    const responses: {
      url: string;
      state: "all" | "latest";
    }[] = [];
    try {
      setModalConfirmDownloadPending(true);
      const latestVersions = getLatestTPStyles();
      const allVersions = await getAllTPStyles();

      const TpStyleResponses = await Promise.allSettled(
        [latestVersions, allVersions].map((item) =>
          TechpackService.retriveTechpackAttachedPDfFiles(item || [])
        )
      );

      for (const [index, TpStyleResponse] of TpStyleResponses.entries()) {
        if (TpStyleResponse.status === "fulfilled") {
          const url = `${window.location.origin}/files/pdf/${TpStyleResponse.value.data.file_name}`;
          responses.push({ url, state: index === 0 ? "latest" : "all" });
        }
      }
    } catch (error) {
      console.error("can't get blob data", error);
    } finally {
      setModalConfirmDownloadPending(false);
    }

    return responses;
  };

  const onRemoveTechpackCompressedPDfFiles = (fileNames: string[]) =>
    TechpackService.removeTechpackAttachedPDfFiles(fileNames);

  const onOpenUploadFileDialog = (state: UploadState) => {
    onOpenUploadFileModal();
    setUploadState(state);
  };

  const onGetNewTechpackId = (techpackId: string) => {
    navigate(`/techpack-detail/${techpackId}`);
  };

  const triggerSortedDate = () => {
    setSortedDateMode(sortedDateMode === "asc" ? "desc" : "asc");
    setActiveTechpackIdx(-1);
  };

  const dispatchTableFilter = ({ type, payload }: TableFilterAction) => {
    const tableFilterAction = {
      editCustomerName: (payload: string) =>
        updateTechpackCustomerName(payload),
      editSeason: (payload: string) => updateTechpackSeason(payload),
      editStyleNumber: (payload: string) => updateStyleNumbers(payload),
      editEndDate: (payload: string) => updateTechpackEndDate(payload),
      editStartDate: (payload: string) => updateTechpackStartDate(payload),
      editStyleDescription: (payload: string) =>
        updateTechpackStyleDescription(payload),
      editStyleFabric: (payload: string) => updateTechpackStyleFabric(payload),
      editSuppliers: (payload: string) => updateTechpackSuppliers(payload),
      editCustomerBrand: (payload: string) =>
        updateTechpackCustomerBrand(payload),
    };

    const tableFilterArrayAction = {
      editCustomerDepartment: (payload: string[]) =>
        updateTechpackCustomerDepartment(payload),
      editCustomerTechpackStatus: (payload: string[]) =>
        updateCustomerTechpackStatus(payload),
      editCustomerProductType: (payload: string[]) =>
        updateTechpackCustomerProductType(payload),
      editAgentId: (payload: string[]) => updateTechpackAgentId(payload),
    };

    if (type in tableFilterAction && typeof payload === "string") {
      tableFilterAction[type as keyof typeof tableFilterAction](payload);
    }

    if (type in tableFilterArrayAction && Array.isArray(payload)) {
      tableFilterArrayAction[type as keyof typeof tableFilterArrayAction](
        payload
      );
    }
    setPage(1);
  };

  const onNavigateAdvancedSearch = () => {
    navigate("/advanced-search");
  };

  const techpackCheckListValues = Object.values(tpCheckList);

  return (
    <PrivateTemplate
      dispatchTableFilter={dispatchTableFilter}
      techpackListStatus={status}
      techpackList={techpackList}
    >
      <LoadingScreen isLoading={modalConfirmDownloadPending} />
      <div className="mt-24 px-10">
        <ButtonCta
          modalConfirmDownloadPending={modalConfirmDownloadPending}
          isCompareFileCtaDisabled={isCompareFileCtaDisabled}
          isBatchDownloadDisabled={!techpackCheckListValues.length}
          onRetrieveTechpackPdfFiles={onRetrieveTechpackPdfFiles}
          onRemoveTechpackCompressedPDfFiles={
            onRemoveTechpackCompressedPDfFiles
          }
          onCompareFile={onCompareFile}
          onOpenUploadFileDialog={onOpenUploadFileDialog}
          onNavigateAdvancedSearch={onNavigateAdvancedSearch}
        />

        <ItemTable
          activeTechpackIdx={activeTechpackIdx}
          isTechpackFetchingStatus={status}
          isFetchingTechpackDetail={isFetchingTechpackDetail}
          tpCheckList={tpCheckList}
          techpackList={techpackList}
          techpackDetail={techpackDetail}
          total={total}
          page={page}
          queryParams={queryParams}
          tableFilter={{ ...fieldValues, customerName }}
          dispatchTableFilter={dispatchTableFilter}
          setPage={setPage}
          setActiveTechpackIdx={setActiveTechpackIdx}
          triggerSortedDate={triggerSortedDate}
          setTPCheckList={setTPCheckList}
          expandedTpDetails={expandedTpDetails}
          setExpandedTpDetails={setExpandedTpDetails}
        />
      </div>
      {isOpen && (
        <UploadFile
          isOpen
          uploadState={uploadState}
          onCloseUploadFileModal={onCloseUploadFileModal}
          successCallback={onGetNewTechpackId}
        />
      )}
    </PrivateTemplate>
  );
}

