formatTPQueryOptions = (
  queryParamsResponse: TTechpackQueryParams | undefined
) => {
  const techpackQueryParams: TQueryParams = {
    agentId: [],
    customerBrand: [],
    customerName: [],
    customerDepartment: [],
    customerTechpackStatus: [],
    customerProductType: [],
    styleNumber: [],
    styleSeason: [],
  };

  const mapKey: {
    [key in keyof TTechpackQueryParams]: keyof TQueryParams;
  } = {
    agent_id: "agentId",
    customer_product_type: "customerProductType",
    customer_name: "customerName",
    customer_department: "customerDepartment",
    customer_techpack_status: "customerTechpackStatus",
    style_no: "styleNumber",
    style_season: "styleSeason",
    customer_brand: "customerBrand",
  };

  for (const key in queryParamsResponse) {
    if (key in mapKey) {
      const currentKey = key as keyof TTechpackQueryParams;

      if (key !== "style_no") {
        techpackQueryParams[mapKey[currentKey]].push({
          label: "Empty",
          value: "empty",
        });
      }
      for (const item of queryParamsResponse[currentKey]) {
        if (typeof item !== "string" && currentKey === "agent_id") {
          techpackQueryParams.agentId.push({
            value: item.key,
            label: item.value,
          });
        }

        if (typeof item === "string" && currentKey !== "agent_id") {
          const isStringEmpty = checkStringEmpty(item) === "";

          if (!isStringEmpty) {
            techpackQueryParams[mapKey[currentKey]].push({
              value: item,
              label: item,
            });
          }
        }
      }
    }
  }

  // sorted season order by year
  techpackQueryParams.styleSeason.sort((a, b) => {
    const aYear = a.value.match(/\d{4,}/)?.[0] || "";
    const bYear = b.value.match(/\d{4,}/)?.[0] || "";

    if (a.value === "empty" || b.value === "empty") {
      return a.value === "empty" ? -1 : 1;
    }

    if (aYear && bYear) {
      if (aYear > bYear) {
        return -1;
      } else if (aYear < bYear) {
        return 1;
      } else {
        return a.value > b.value ? 1 : -1;
      }
    }

    return a.value > b.value ? 1 : -1;
  });

  // sorted agentId, customer department, customer product type, techpack status from A to Z
  [
    techpackQueryParams.agentId,
    techpackQueryParams.customerDepartment,
    techpackQueryParams.customerProductType,
    techpackQueryParams.customerTechpackStatus,
  ].forEach((item) =>
    item.sort((a, b) => {
      if (a.value === "empty" || b.value === "empty") {
        return a.value === "empty" ? -1 : 1;
      }

      return a.value > b.value ? 1 : -1;
    })
  );

  return techpackQueryParams;
}

formatTPOrderQueryParams = (
  queryParams: TTechpackOrderQueryParams | undefined
) => {
  const orderQueryParams: Record<keyof TTechpackOrderQueryParams, Option[]> = {
    factory_countries: [],
    factory_statuses: [],
  };

  if (!queryParams) {
    return orderQueryParams;
  }

  for (const key in queryParams) {
    const options = queryParams[key as keyof TTechpackOrderQueryParams].map(
      (item) => ({ label: item, value: item })
    );

    orderQueryParams[key as keyof TTechpackOrderQueryParams] = options;
  }

  return orderQueryParams;
}

