TechpackCompare = () => {
  const location = useLocation();

  const isAuthorizationCalled = useTechpackContext(
    (s) => s.isAuthorizationCalled
  );

  const {
    newTechpackId,
    oldTechpackId,
    styleNumber,
    styleSeason,
    styleDescription,
    code,
    attchmentPdfTechpack,
    customerName,
    oldVersion,
    newVersion,
    latestTechpackId,
  } = location.state;
  const { data, isFetching } = useQuery({
    queryKey: ["get compare file", newTechpackId, oldTechpackId],
    queryFn: () => techpackService.getCompareFile(newTechpackId, oldTechpackId),
    select: (resp) => resp.data,
    onSuccess: (data) => {
      if (data.result === "Identical") {
        toast.success(data.message, { duration: 4_000, position: "top-right" });
      }
    },
    onError: (error: TCompareError) => {
      console.error(error);

      if (error.result === "Failed") {
        toast.success(error.message, {
          duration: 4_000,
          position: "top-right",
        });
      }
    },
    enabled: Boolean(newTechpackId && oldTechpackId && isAuthorizationCalled),
    retry: false,
  });

  const { data: apimData, isFetching: isApimFetching } = useQuery({
    queryKey: [
      "get apim compare file",
      attchmentPdfTechpack,
      code,
      customerName,
      styleNumber,
      styleSeason,
      styleDescription,
    ],
    queryFn: () =>
      techpackService.getApimComparisonFile({
        attchmentPdfTechpack: attchmentPdfTechpack,
        customerDepartment: code,
        customerName,
        styleNumber,
        styleSeason,
        styleDescription,
      }),
    select: (resp) => resp.data,
    onSuccess: (data) => {
      if (data.result === "Failed") {
        toast.error(data.message, { duration: 4_000, position: "top-right" });
      }
    },
    enabled: Boolean(attchmentPdfTechpack),
    retry: false,
  });

  const response = newTechpackId && oldTechpackId ? data : apimData;
  const isQueryFetching =
    newTechpackId && oldTechpackId ? isFetching : isApimFetching;

  const imageSource =
    response?.result === "Success" ? response.pdf_diff_url : "";

  const techpackMetaDataVersion = useMemo(() => {
    if (newVersion !== -1 && oldVersion !== -1) {
      return {
        old: oldVersion,
        new: newVersion,
      };
    }
    return null;
  }, [newVersion, oldVersion]);

  return (
    <PrivateTemplate disableSearch>
      <div className="mt-24">
        <Navigation
          styleNumber={styleNumber}
          styleSeason={styleSeason}
          code={code}
          latestTechpackId={latestTechpackId}
          customerName={customerName}
        />
        <div className="mt-40">
          {techpackMetaDataVersion && (
            <div className="w-full flex items-center px-4 mb-4 z-10">
              <div className="w-1/2">
                <h2 className="text-2xl font-bold text-center">
                  Old Version: {techpackMetaDataVersion?.old}
                </h2>
              </div>
              <div className="w-1/2">
                <h2 className="text-2xl font-bold text-center">
                  New Version: {techpackMetaDataVersion?.new}
                </h2>
              </div>
            </div>
          )}
          <div className="w-full mx-auto">
            {isQueryFetching && (
              <div className="w-full flex justify-center items-center h-[calc(100vh_-_4rem)]">
                <Spinner fontSize={36} />
              </div>
            )}

