interface Props {
  tpStyleNo: string;
  tpCustomerName: string;
  tpCustomerDepartment: string;
  tpSeason: string;
  suppliers: Option[];
  factories: Option[];
}

interface TRFQCostQueryParams {
  factory: Option[];
  supplier: Option[];
}

RFQCost = ({
  tpStyleNo,
  tpCustomerName,
  tpCustomerDepartment,
  tpSeason,
  suppliers,
  factories,
}: Props) => {
  // const [toggleRFQCostCollapsed, setTogglerRFQCostColllapsed] = useState(true);
  const [RFQCostDataSource, setRFQCostDataSource] = useState<
    TRFQCostDatatype[]
  >([]);
  const [currentRFQCostDetail, setCurrentRFQCostDetail] = useState({
    key: "",
    prodCountry: "",
  });
  const [expandedRFQCostDetails, setExpandedRFQCostDetails] = useState<
    string[]
  >([]);

  const isAuthorizationCalled = useTechpackContext(
    (s) => s.isAuthorizationCalled
  );

  const {
    groupingParams: { costing: RFQCostParams },
    groupingCollapsed: { costing: toggleRFQCostCollapsed },
    setGroupingCollapsed,
  } = useContext(GroupingContext);

  const [debounceRFQCostParams] = useDebounce(
    RFQCostParams,
    Object.values(RFQCostParams).filter((param) =>
      Array.isArray(param) ? param.length : param !== ""
    ).length <= 2
      ? 500
      : 2000
  );

  const { isFetching: isRFQCostsFetching } = useQuery({
    queryKey: [
      "get-techpack-RFQ-cost",
      tpStyleNo,
      tpSeason,
      tpCustomerName,
      tpCustomerDepartment,
      ...Object.values(debounceRFQCostParams).map((item) =>
        Array.isArray(item) ? item.join("-") : item
      ),
    ],
    queryFn: () => {
      return RFQCostService.getRFQCosts({
        customerDepartment: tpCustomerDepartment,
        customerName: tpCustomerName,
        factory: RFQCostParams.factory,
        prdCountry: RFQCostParams.prdCountry,
        supplier: RFQCostParams.supplier,
        rfqCreatedFromDate: RFQCostParams.rfqCreatedFromDate,
        rfqCreatedToDate: RFQCostParams.rfqCreatedToDate,
        season: tpSeason,
        styleNo: tpStyleNo,
      });
    },
    onSuccess: (resp) => {
      let orderDataSrc: TRFQCostDatatype[] = [];
      if (resp?.data?.data.length) {
        orderDataSrc = formatGroupedDataSource(formatRFQCosts(resp.data.data));
      }
      setCurrentRFQCostDetail({
        key: "",
        prodCountry: "",
      });
      setExpandedRFQCostDetails([]);

      setRFQCostDataSource(orderDataSrc);
    },
    onError: (err: AxiosError<{ error_message: string }>) => {
      if (err.response?.status === 403) {
        setCurrentRFQCostDetail({
          key: "",
          prodCountry: "",
        });
        setExpandedRFQCostDetails([]);

        setRFQCostDataSource([]);
      }
      toast.error(err.response?.data.error_message || "Something went wrong", {
        position: "top-center",
      });
    },
    enabled: Boolean(isAuthorizationCalled && toggleRFQCostCollapsed),
  });

  const { isFetching: isRFQCostDetailFetching } = useQuery({
    queryKey: [
      "get-techpack-rfq-cost-detail",
      currentRFQCostDetail.prodCountry,
      tpStyleNo,
      tpSeason,
      tpCustomerName,
      tpCustomerDepartment,
      ...Object.values(debounceRFQCostParams).map((item) =>
        Array.isArray(item) ? item.join("-") : item
      ),
    ],
    queryFn: () => {
      return RFQCostService.getRFQCostDetails({
        customerDepartment: tpCustomerDepartment,
        customerName: tpCustomerName,
        factory: RFQCostParams.factory,
        prdCountry: RFQCostParams.prdCountry,
        supplier: RFQCostParams.supplier,
        rfqCreatedFromDate: RFQCostParams.rfqCreatedFromDate,
        rfqCreatedToDate: RFQCostParams.rfqCreatedToDate,
        season: tpSeason,
        styleNo: tpStyleNo,
      });
