checkWordExist = (wordList: string[], query: string) =>
  wordList.some((word) => {
    const onlyWord = word.replace(
      /[`~@#$%^&*()_|+\-=?;:'",.<>{\\}[\]\\/]/gi,
      ""
    );
    const QueryOnlyWord = query.replace(
      /[`~@#$%^&*()_|+\-=?;:'",.<>{\\}[\]\\/]/gi,
      ""
    );
    return (
      word.toLowerCase() === query.toLowerCase() ||
      onlyWord.toLowerCase() === QueryOnlyWord.toLowerCase()
    );
  })

groupBomDetails = (
  bomDetails: BOMDetail[]
): GroupedBOMDetail[] => {
  const groupBomDetail: GroupedBOMDetail[] = [];

  for (const bomDetail of bomDetails) {
    for (const partItem of bomDetail.part_items) {
      const bomFoundIdx = groupBomDetail.findIndex(
        (item) =>
          item.key ===
          (partItem.is_grouped ? "other" : partItem.bom_detail_name)
      );

      if (bomFoundIdx === -1) {
        groupBomDetail.push({
          key: partItem.is_grouped ? "other" : partItem.bom_detail_name,
          bomDetailItems: partItem.bom_detail_items.map((item) => ({
            ...item,
            bom_detail_name: partItem.bom_detail_name,
          })),
        });
      } else {
        groupBomDetail[bomFoundIdx].bomDetailItems = [
          ...groupBomDetail[bomFoundIdx].bomDetailItems,
          ...partItem.bom_detail_items.map((item) => ({
            ...item,
            bom_detail_name: partItem.bom_detail_name,
          })),
        ];
      }
    }
  }

  return groupBomDetail.sort((a, b) => {
    if (a.key === "other") {
      return 1;
    } else if (b.key === "other") {
      return -1;
    }
    return a.key > b.key ? 1 : -1;
  });
}

getStyleFabric = (styleFabric: string): TTechpackFabric => {
  try {
    const jsonResponse = safeJsonParse(styleFabric);

    if (jsonResponse.success) {
      return jsonResponse.data;
    }
    throw jsonResponse.data;
  } catch (error) {
    if (/(\[.+\])|(\{.+\})/.test(styleFabric)) {
      const formattedStyleFabric = styleFabric.replace(/'/g, '"');
      const jsonResponse = safeJsonParse(formattedStyleFabric);

      if (jsonResponse.success) {
        return jsonResponse.data;
      }
    }

    return styleFabric;
  }
}

formatStyleFabricObj = (fabric: Fabric) => {
  const fabricArr =
    fabric.composition || fabric.description
      ? [
          fabric.description,
          Array.isArray(fabric.composition)
            ? fabricJoinComposition(fabric.composition)
            : fabric.composition,
        ]
      : [];

  return fabric.full_desc
    ? fabric.full_desc
    : fabricArr.filter(Boolean).join(" - ");
}

highlightFabric = (fabric: string, queryStr: string) => {
  const fabricStrList = fabric.split(/\s|(\\n)|"|'|`|,/).filter(Boolean);
  const queryStrList = queryStr.split(/\s|(\\n)|"|'|`|,/).filter(Boolean);

  if (fabricStrList.length && queryStrList.length) {
    let fabricStrCnt = 0;

    while (fabricStrCnt < fabricStrList.length) {
      const fabricStr = fabricStrList[fabricStrCnt];

      // search in single fabric character
      if (checkWordExist(queryStrList, fabricStr)) {
        fabricStrList[fabricStrCnt] = highlightWord(fabricStr);
        fabricStrCnt++;
        continue;
      }
      // combine the next item and search in query array
      else {
        const queryFoundIdx = queryStrList.findIndex((query) => {
          return fabricStr.toLowerCase().indexOf(query.toLowerCase()) === 0;
        });

        // query partial match in query array and combine next item in query array
        if (queryFoundIdx !== -1 && queryFoundIdx + 1 < queryStrList.length) {
          const newQueryStr =
            queryStrList[queryFoundIdx] + queryStrList[queryFoundIdx + 1];

          if (newQueryStr.toLowerCase() === fabricStr.toLowerCase()) {
            fabricStrList[fabricStrCnt] = highlightWord(fabricStr);
          } else if (fabricStrCnt + 1 < fabricStrList.length) {
            const newFabric = fabricStr + fabricStrList[fabricStrCnt + 1];

            if (
              queryStrList[queryFoundIdx].toLowerCase() ===
              newFabric.toLowerCase()
            ) {
              fabricStrList[fabricStrCnt] = highlightWord(fabricStr);
              fabricStrList[fabricStrCnt + 1] = highlightWord(
                fabricStrList[fabricStrCnt + 1]
              );
              fabricStrCnt += 2;
              continue;
            }
          }
        }

        fabricStrCnt++;
        continue;
      }
    }
  }

  return fabricStrList.join(" ");
}

formatBOMDetailLabel = (item: GroupedBOMDetail) => {
  let label = "";
  const countDict: Record<string, number> = {};

  for (const bomDetailItem of item.bomDetailItems) {
    if (bomDetailItem.bom_detail_name in countDict) {
      countDict[bomDetailItem.bom_detail_name] += 1;
    } else {
      countDict[bomDetailItem.bom_detail_name] = 1;
    }
  }

  const countDictKeys = Object.keys(countDict);

  countDictKeys.forEach((key, index) => {
    label += `${key} (${countDict[key]})${
      index < countDictKeys.length - 1 ? " / " : ""
    }`;
  });

  return label;
}

