interface Props {
  tpStyleNo: string;
  tpCustomerName: string;
  tpCustomerDepartment: string;
  season: string;
}

XtsOrder = ({
  tpStyleNo,
  tpCustomerName,
  tpCustomerDepartment,
  season
}: Props) => {
  const [orderPage, setOrderPage] = useState(1);
  const [orderDetails, setOrderDetails] = useState<
    Record<string, TOrderDataType[]>
  >({});
  const [orderDataSource, setOrderDataSource] = useState<TOrderDataType[]>([]);
  const [currentOrderDetail, setCurrentOrderDetail] = useState({
    key: "",
    sourcingOffice: "",
    prodCountry: "",
  });
  const [expandedOrderDetails, setExpandedOrderDetails] = useState<string[]>(
    []
  );
  const [orderQueryParams, setOrderQueryParams] = useState<
    Record<keyof TTechpackXTSOrderQueryParams, Option[]>
  >({
    case_attribute1: [],
    co_name: [],
    concat_color: [],
    factory: [],
    final_dest: [],
    item_no: [],
    po_no: [],
    prod_country: [],
    season: [],
    ship_mode: [],
    sourcing_office: [],
    supplier: [],
    ultimate_customer: [],
  });
  const [isExportPOLoading, setIsExportPOLoading] = useState(false);

  const orderPerPage = useRef(10);

  const isAuthorizationCalled = useTechpackContext(
    (s) => s.isAuthorizationCalled
  );

  const {
    groupingCollapsed: { order: toggleOrderCollapsed },
    groupingParams: { order: orderParams },
    setGroupingCollapsed,
  } = useContext(GroupingContext);

  const [debounceOrderParams] = useDebounce(
    orderParams,
    Object.values(orderParams).filter((param) =>
      Array.isArray(param) ? param.length : param !== ""
    ).length <= 2
      ? 500
      : 2000
  );

  const { isFetching: isFetchingOrderQueryParams } = useQuery({
    queryKey: [
      "q-techpack-xts-order-query-params",
      tpStyleNo,
      tpCustomerDepartment,
      tpCustomerName,
    ],
    queryFn: () => {
      return techpackService.getTechpackDetailXTSOrdersQueryParams(
        tpStyleNo,
        tpCustomerName,
        tpCustomerDepartment
      );
    },
    onSuccess: (resp) => {
      if (resp.data) {
        const output: typeof orderQueryParams = { ...orderQueryParams };

        for (const key in resp.data) {
          const k = key as keyof TTechpackXTSOrderQueryParams;
          if (output[k]) {
            output[k] = resp.data[k].map((item) => ({
              value: item,
              label: item,
            }));
          }
        }

        setOrderQueryParams(output);
      }
    },
    enabled: Boolean(isAuthorizationCalled && toggleOrderCollapsed),
  });

  const { data: orderResponse, isFetching: isOrderFetching } = useQuery({
    queryKey: [
      "get-techpack-xts-order",
      tpStyleNo,
      tpCustomerDepartment,
      season,
      orderPage,
      ...Object.values(debounceOrderParams).map((item) =>
        Array.isArray(item) ? item.join("-") : item
      ),
    ],
    queryFn: () => {
      return techpackService.getTechpackDetailXTSOrders(
        tpStyleNo,
        tpCustomerName,
        tpCustomerDepartment,
        season,
        orderPage,
        orderPerPage.current,
        orderParams
      );
    },
    onSuccess: (resp) => {
      let orderDataSrc: TOrderDataType[] = [];
      if (resp.data.xts_orders.length) {
        orderDataSrc = formatGroupedDataSource(
          formatOrders(resp.data.xts_orders)
        );
      }
      setCurrentOrderDetail({
        key: "",
        sourcingOffice: "",
        prodCountry: "",
      });
      setExpandedOrderDetails([]);

      setOrderDataSource(orderDataSrc);
    },
    onError: (err: AxiosError<{ error_message: string }>) => {
      if (err.response?.status === 403) {
        setCurrentOrderDetail({
          key: "",
          sourcingOffice: "",
          prodCountry: "",
        });
        setExpandedOrderDetails([]);

        setOrderDataSource([]);
      }
      toast.error(err.response?.data.error_message || "Something went wrong", {
        position: "top-center",
      });
    },
    enabled: Boolean(isAuthorizationCalled && toggleOrderCollapsed),
  });

  const { isFetching: isFetchingOrderDetails } = useQuery({
    queryKey: [
      "get-techpack-xts-order-details",
      tpStyleNo,
      currentOrderDetail.sourcingOffice,
      tpCustomerDepartment,
      tpCustomerName,
      season,
      currentOrderDetail.prodCountry,
      ...Object.values(debounceOrderParams).map((item) =>
        Array.isArray(item) ? item.join("-") : item
      ),
    ],
    queryFn: () => {
      return techpackService.getTechpackDetailXTSOrderDetails(
        tpStyleNo,
        tpCustomerName,
        tpCustomerDepartment,
        season,
        currentOrderDetail.sourcingOffice,
        currentOrderDetail.prodCountry,
        { ...orderParams }
      );
    },
    enabled: Boolean(isAuthorizationCalled && currentOrderDetail.key),
    onSuccess: (resp) => {
      if (resp.data.order_details.length) {
        setOrderDataSource((prev) => {
          const idx = prev.findIndex(
            (item) => item.key === currentOrderDetail.key
          );

          if (idx !== -1) {
            prev[idx].children = formatGroupedDataSource(
              formatOrders(
                resp.data.order_details.map((item) => ({
                  ...item,
                  sourcing_office: "",
                  prod_country: "",
                }))
              ),
              orderPage,
              idx
            );
          }

          return prev;
        });
        setExpandedOrderDetails([
          ...expandedOrderDetails,
          currentOrderDetail.key,
        ]);
      }
      setOrderDetails((prev) => ({
        ...prev,
        [currentOrderDetail.key]: resp.data.order_details.length
          ? formatGroupedDataSource(
            formatOrders(
              resp.data.order_details.map((item) => ({
                ...item,
                sourcing_office: "",
                prod_country: "",
              }))
            )
          )
          : [],
      }));
    },
  });

  const downloadMutation = useMutation({
    mutationKey: ["ownload-PO-excel-file"],
    onMutate: () => setIsExportPOLoading(true),
    mutationFn: ({
      style_no,
      customer_name,
      customer_department,
    }: {
      style_no: string;
      customer_name: string;
      customer_department: string;
    }) => {
      return techpackService.exportPOFiles({
        style_no,
        customer_name,
        customer_department,
      });
    },
    onSuccess: (response) => {
      const url = URL.createObjectURL(response.data);
      const link = document.createElement("a");
      link.href = url;

      const content = response.headers["content-disposition"].split("; ");
      const fileName = content[1].split("=")[1] || `${Date.now()}.xlsx`;

      link.setAttribute("download", fileName);
      document.body.appendChild(link);
      link.click();

      link.remove();
    },
    onError: async (err: AxiosError) => {
      let msg = "Something went wrong";
      if (err.response?.data instanceof Blob) {
        const error = JSON.parse(await (err?.response?.data as Blob).text());

        msg = error?.error_message || msg;
      }
      toast.error(msg || "");
    },
    onSettled: () => setIsExportPOLoading(false),
  });

  const orderTotal = orderResponse?.data.total || 0;

  const onToggleCollapsedOrder = () => {
    const newOrderCollapsedState = !toggleOrderCollapsed;
    setGroupingCollapsed((prev) => ({
      ...prev,
      order: newOrderCollapsedState,
    }));

    if (!newOrderCollapsedState) {
      setOrderPage(1);
    }
  };

  const exportPOFile: MouseEventHandler = async (e) => {
    e.stopPropagation();

    setIsExportPOLoading(true);
    downloadMutation.mutate({
      style_no: tpStyleNo,
      customer_name: tpCustomerName,
      customer_department: tpCustomerDepartment,
    });
  };

  return (
    <TechpackCollapse
      title="Order Information"
      className="mx-0"
      outerToggleCollapsedFn={onToggleCollapsedOrder}
      outerToggleCollapsed={toggleOrderCollapsed}
      customCollapsedComp={
        <div className="flex items-center gap-4">
          <Button
            icon={<DownloadOutlined />}
            onClick={exportPOFile}
            loading={isExportPOLoading}
          >
            Export
          </Button>
          <div className="flex text-accent-blue gap-1 items-center">
            <p className="text-sm">Collapse</p>
            <IconArrowDown
              className={cn("duration-300", {
                "rotate-180": toggleOrderCollapsed,
              })}
              width={14}
              height={14}
              fill={"#2FAFE4"}
            />
          </div>
        </div>
      }
    >
      <Layout
        expandedOrderDetails={expandedOrderDetails}
        isLoading={
          isOrderFetching ||
          isFetchingOrderQueryParams ||
          isFetchingOrderDetails
        }
        orders={orderDataSource}
        orderPage={orderPage}
        orderTotal={orderTotal}
        orderDetails={orderDetails}
        orderQueryParams={orderQueryParams}
        onChange={(page) => {
          setOrderPage(page);
        }}
        setCurrentOrderDetail={setCurrentOrderDetail}
        setExpandedOrderDetails={setExpandedOrderDetails}
      />
    </TechpackCollapse>
  );
}

interface TXTSOrder {
  sourcingOffice: string;
  prdCountry: string;
  itemNo: string;
  PONumber: string;
  ultimateCustomer: string;
  caseAttribute1: string;
  concatColor: string;
  COName: string;
  supplier: string;
  factory: string;
  itemPrice: string;
  shipMode: string;
  schDate: string;
  finalDest: string;
  quantity: string;
}

type TOrderParam = {
  [key in keyof Omit<TTechpackXTSOrderQueryParams, "prod_country">]: string[];
} & {
  prod_country: string;
  sch_start_date: string;
  sch_end_date: string;
};

groupingOrder = (
  data: TXTSOrder[],
  fieldKeys: TGroupingKey[] = [
    "sourcingOffice",
    "prdCountry",
    // "season",
    // "itemNo",
    // "PONumber",
    // "ultimateCustomer",
    // "caseAttribute1",
  ]
): TGroupOrder[] => {
  function group(
    keys: typeof fieldKeys,
    current: (TXTSOrder & { isGroup?: boolean })[],
    groupedOrder: TGroupOrder[]
  ) {
    let count = 0;

    while (count < current.length) {
      const node = { ...current[count] };

      if (node.isGroup) {
        count++;
        continue;
      }

      const newGroupedOrder: TGroupOrder = { ...node, children: [] };

      for (let i = 0; i < current.length; i++) {
        const item = current[i];
        if (
          i !== count &&
          keys.every((key) => item[key] === node[key]) &&
          !item.isGroup
        ) {
          const newItem = { ...item };

          for (const key of keys) {
            newItem[key] = "";
          }
          newGroupedOrder.children = [
            ...(newGroupedOrder.children || []),
            newItem,
          ];
          item.isGroup = true;
        }
      }

      if (newGroupedOrder?.children?.length) {
        current[count].isGroup = true;
        groupedOrder.push(newGroupedOrder);
      }

      count++;
    }
  }
  const groupedOrder: TGroupOrder[] = [];
  const current: (TXTSOrder & { isGroup?: boolean })[] = [...data];

  // grouping order
  while (fieldKeys.length) {
    group(fieldKeys, current, groupedOrder);
    fieldKeys.pop();
  }

  // push item can't find any group
  for (const cur of current) {
    if (!cur.isGroup) {
      groupedOrder.push(cur);
    }
  }

  return groupedOrder;
}

formatGroupedDataSource = (
  groupedOrder: TXTSOrder[],
  orderPage?: number,
  orderParent?: number
): TDataType[] => {
  return groupedOrder.map((order, index) => ({
    ...order,
    key: `${orderPage || ""}${orderParent || ""}${index + 1}`,
  }));
}

countGroupingOrder = (orders: TXTSOrder[]): TXTSOrder[] => {
  // count total of the XTS order

  const orderTotalDict: {
    [k: string]: {
      [sk in keyof TXTSOrder]?: string[];
    };
  } = {};

  for (const item of orders) {
    const keyMapping = [item.sourcingOffice, item.prdCountry]
      .filter(Boolean)
      .join("-");
    // check souring office is diferent from others
    if (!orderTotalDict[keyMapping]) {
      orderTotalDict[keyMapping] = {};
    }

    // count
    for (const key in item) {
      const k = key as keyof TXTSOrder;
      const keyMapping = [item.sourcingOffice, item.prdCountry]
        .filter(Boolean)
        .join("-");
      const currentSet = orderTotalDict[keyMapping];

      if (["quantity", "itemPrice"].includes(k)) {
        if (!currentSet[k]) {
          currentSet[k] = [];
        }
        currentSet?.[k]?.push(item[k]);
      } else {
        if (!currentSet?.[k]?.length) {
          currentSet[k] = [item[k]];
        } else if (!currentSet?.[k]?.some((v) => v === item[k])) {
          currentSet?.[k]?.push(item[k]);
        }
      }
    }
  }

  const result: TXTSOrder[] = [];

  for (const key in orderTotalDict) {
    const [sourcingOffice, prdCountry] = key.split("-");

    const currentTotal = orderTotalDict[key];
    const itemPriceArr = currentTotal.itemPrice
      ? currentTotal.itemPrice.map(Number)
      : [];
    const sortedSchDate = currentTotal.schDate
      ? currentTotal.schDate.sort((a, b) => (a > b ? -1 : 1))
      : "";
    const quantity = currentTotal.quantity
      ? currentTotal.quantity.map(Number).reduce((acc, cur) => acc + cur, 0)
      : 0;

    result.push({
      sourcingOffice,
      prdCountry,
      itemNo: currentTotal.itemNo ? `${currentTotal.itemNo.length || ""}` : "",
      PONumber: currentTotal.PONumber
        ? `${currentTotal.PONumber.length || ""}`
        : "",
      ultimateCustomer: currentTotal.ultimateCustomer
        ? `${currentTotal.ultimateCustomer.length || ""}`
        : "",
      caseAttribute1: currentTotal.caseAttribute1
        ? `${currentTotal.caseAttribute1.length || ""}`
        : "",
      concatColor: currentTotal.concatColor
        ? `${currentTotal.concatColor.length || ""}`
        : "",
      COName: currentTotal.COName ? `${currentTotal.COName.length || ""}` : "",
      supplier: currentTotal.supplier
        ? `${currentTotal.supplier.length || ""}`
        : "",
      factory: currentTotal.factory
        ? `${currentTotal.factory.length || ""}`
        : "",
      itemPrice: [Math.min(...itemPriceArr), Math.max(...itemPriceArr)]
        .filter(Boolean)
        .join(" - "),
      shipMode: "",
      schDate: [sortedSchDate[sortedSchDate.length - 1], sortedSchDate[0]]
        .filter(Boolean)
        .join(" - "),
      finalDest: currentTotal.finalDest
        ? `${currentTotal.finalDest.length || ""}`
        : "",
      quantity: `${quantity || ""}`,
    });
  }

  return result;
}

concatSubTotalAndGroupedOrder = (
  formattedOrders: TXTSOrder[]
): TXTSOrder[] => {
  const orderCounts = countGroupingOrder(formattedOrders);
  const groupedOrders = groupingOrder(formattedOrders);

  for (const item of orderCounts) {
    // find grouped order base sourcing office - prd country
    const idx = groupedOrders.findIndex(
      (order) =>
        order.sourcingOffice === item.sourcingOffice &&
        order.prdCountry === item.prdCountry
    );

    if (idx !== -1) {
      groupedOrders.splice(idx, 0, item);
    }
  }

  return groupedOrders;
}

