        updateIsAuthorizationCalled: (isAuthorizationCalled) =>
          set(
            produce((state) => ({
              ...state,
              isAuthorizationCalled,
            }))
          ),
        updateTechpackUsername: (username) =>
          set(
            produce((state) => ({
              ...state,
              username,
            }))
          ),
        updateTechpackStartDate: (startDate) =>
          set(
            produce((state) => ({
              ...state,
              startDate,
            }))
          ),
        updateTechpackEndDate: (endDate) =>
          set(
            produce((state) => ({
              ...state,
              endDate,
            }))
          ),
        updateTechpackStyleDescription: (styleDescription) =>
          set(
            produce((state) => ({
              ...state,
              styleDescription,
            }))
          ),
        updateTechpackStyleFabric: (styleFabric) =>
          set(
            produce((state) => ({
              ...state,
              styleFabric,
            }))
          ),
        updateTechpackSuppliers: (suppliers) =>
          set(
            produce((state) => ({
              ...state,
              suppliers,
            }))
          ),
        resetFilterParams: () =>
          set(
            produce((state) => ({
              ...state,
              styleNumber: initState.styleNumber,
              season: initState.season,
              customerProductType: initState.customerProductType,
              customerDepartment: initState.customerDepartment,
              customerBrand: initState.customerBrand,
              styleDescription: initState.styleDescription,
              agentId: initState.agentId,
              customerTechpackStatus: initState.customerTechpackStatus,
              startDate: initState.startDate,
              endDate: initState.endDate,
              styleFabric: initState.styleFabric,
              suppliers: initState.suppliers,
            }))
          ),
        reset: () => {
          set(initState);
        },
      }),
      {
        name: "techpack-storage",
        storage: createJSONStorage(() => sessionStorage),
        partialize: (state) =>
          Object.fromEntries(
            Object.entries(state).filter(
              ([key]) => !["isAuthorizationCalled"].includes(key)
            )
          ),
      }
    )
  );
}

