handleTokenExpired = async ({
    accessToken,
    accessTokenExpiresOn,
  }: {
    accessToken: string;
    accessTokenExpiresOn: string;
  }) => {
    if (isAfter(new Date(), new Date(accessTokenExpiresOn))) {
      await axiosInstance(
        `${ENV_MODE === "localhost" ? "local" : ""}${ENDPOINT.refreshToken}`
      );

      refetch();
    }

    if (!isAuthorizationCalled) {
      axiosInstance(ENDPOINT.authorize, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
          Timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        },
        method: "POST",
      }).then(() => {
        updateIsAuthorizationCalled(true);
        sendLogging("Entry", "Login");
      });
    }
    const userProfile: JwtPayload & UserInfo = jwtDecode(accessToken);

    updateTechpackUsername(userProfile.name);
  }

onLogout = async () => {
    await techpackService.sendLogging({
      functionGroup: "Entry",
      functionName: "Logout",
      userInput: "",
    });
    axiosInstance.post(ENDPOINT.appLogout).then(() => {
      reset();

      window.location.href = `${ENV_MODE === "localhost" ? "local" : ""}${
        ENDPOINT.msLogout
      }`;
    });
  }

