def auth_middleware(app):
    @app.before_request
    def authenticate():
        # if request comes from TP-02 then bypass cookie checks, only check JWT token
        sec_fetch_site = request.headers.get('sec-fetch-site') or None
        referrer = request.headers.get('Referer') or None
        # if sec_fetch_site == Auth.SEC_FETCH_SITE_CROSS_SITE \
        #     and referrer == TEHCPACK_02_REFFERER:
        if referrer == TEHCPACK_02_REFFERER:
            return

        # if request comes from secured path then check its attached api-key
        if request.path.startswith("/api/secured-apim/"):
            api_key = request.headers.get('api-key')
            if SECURED_APIM_API_KEY != api_key:
                return jsonify({
                    "message": "Invalid secured api key."
                }), 401

            return

        # TP-01: check if user has successfully signed in via aad or not
        if APP_ENV != "DEV":
            auth_session = request.cookies.get('AppServiceAuthSession', None)
            if auth_session is None:
                return redirect(LOGIN_PATH)

        return

