class EmailProcessing:
    subject: str
    body: str
    send_to: str
    record_id: Optional[int] = None
    cc: Optional[str] = None
    bcc: Optional[str] = None
    attachments: Optional[str] = None
    status: Optional[EmailStatus] = EmailStatus.NEW
    raw_data: Optional[str] = None
    email_type: Optional[EmailType] = None
    timestamp_updated: Optional[datetime] = None
    timestamp_created: Optional[datetime] = None

    def __post_init__(self):
        if not self.subject:
            raise ValueError("Subject is required!")
        if not self.body:
            raise ValueError("Body is required!")
        if not self.send_to:
            raise ValueError("Send_to is required!")

    @classmethod
    def from_dict(cls, data: dict):
        valid_fields = {f.name for f in cls.__dataclass_fields__.values()}
        filtered_data = {k: v for k, v in data.items() if k in valid_fields}

        # Handle enum conversions
        if 'status' in filtered_data and isinstance(filtered_data['status'], str):
            try:
                filtered_data['status'] = EmailStatus(filtered_data['status'])
            except ValueError:
                filtered_data['status'] = EmailStatus.NEW

        if 'email_type' in filtered_data and isinstance(filtered_data['email_type'], str):
            try:
                filtered_data['email_type'] = EmailType(filtered_data['email_type'])
            except ValueError:
                filtered_data['email_type'] = None

        return cls(**filtered_data)

    def to_dict(self):
        """Convert to dict, excluding None values"""
        result = {}
        for k, v in self.__dict__.items():
            if v is not None:
                if isinstance(v, (EmailStatus, EmailType)):
                    result[k] = v.value
                else:
                    result[k] = v

        return result

