            recipients = os.environ.get('DEFAULT_EMAIL_RECIPIENTS', DEFAULT_EMAIL_RECIPIENTS)
            return recipients and recipients.split(';') or []
        except (json.JSONDecodeError, Exception) as e:
            logger.error(f"Failed to load DEFAULT_EMAIL_RECIPIENTS: {e}")
            return []

    @classmethod
    def _load_templates_from_env(cls, default_cm_yy_daily_email_param: str = None) -> Dict:
        """Load email templates from environment variable"""
        # EMAIL_TEMPLATES_CONFIG = """{
        #         "ai_assistant": {
        #             "subject": "[{app_env}] Notification: Daily Summeriazation For New Styles Ready For Quotation",
        #             "send_to": ["v_BinhLam@lifung.com", "v_tannguyen@lifung.com", "V_TamDuong@lifung.com"],
        #             "cc": [],
        #             "bcc": []
        #         },
        #         "cm_sync": {
        #             "subject": "[{app_env}] Notification: Style #{style_no} CM Cost Re-estimation Completed",
        #             "send_to": [],
        #             "cc": [],
        #             "bcc": ["v_BinhLam@lifung.com", "v_tannguyen@lifung.com"]
        #         },
        #         "yy_sync": {
        #             "subject": "[{app_env}] Notification: Style #{style_no} Fabric Cost Re-estimation Completed",
        #             "send_to": [],
        #             "cc": [],
        #             "bcc": ["v_BinhLam@lifung.com", "v_tannguyen@lifung.com"]
        #         }
        #     }"""
        try:
            if default_cm_yy_daily_email_param and default_cm_yy_daily_email_param.strip():
                try:
                    return json.loads(default_cm_yy_daily_email_param)
                except Exception as e:
                    logger.error(f"Failed to parse default_cm_yy_daily_email_param: {e}")
            default_cm_yy_daily_email_param = os.environ.get('EMAIL_TEMPLATES_CONFIG', '{}')
            #templates_json = EMAIL_TEMPLATES_CONFIG
            return json.loads(default_cm_yy_daily_email_param)
        except (json.JSONDecodeError, Exception) as e:
            logger.error(f"Failed to load EMAIL_TEMPLATES_CONFIG: {e}")
            return {}

    @classmethod
    def _get_default_templates(cls) -> Dict:
        """Get default email templates"""
        return {
            EmailType.AI_ASSISTANT.value: {
                'subject': '[{app_env}] AI Analysis: Daily Ingestion',
                'send_to': cls._load_default_email_recipients_from_env(),
                'cc': [],
                'bcc': []
            },
            EmailType.CM_SYNC.value: {
                'subject': '[{app_env}] CM Costing Analysis',
                'send_to': [],
                'cc': cls._load_default_email_recipients_from_env(),
                'bcc': []
            },
            EmailType.YY_SYNC.value: {
                'subject': '[{app_env}] YY Costing Analysis',
                'send_to': [],
                'cc': cls._load_default_email_recipients_from_env(),
                'bcc': []
            },
            EmailType.ERROR_CM_SYNC.value: {
                'subject': '[{app_env}] CM Costing Analysis Error',
                'send_to': [],
                'cc': cls._load_default_email_recipients_from_env(),
                'bcc': []
            },
            EmailType.ERROR_YY_SYNC.value: {
                'subject': '[{app_env}] CM Costing Analysis Error',
                'send_to': [],
                'cc': cls._load_default_email_recipients_from_env(),
                'bcc': []
            },
        }

    @classmethod
    def get(cls, email_type: str, default_cm_yy_daily_email_param: str = None) -> Dict:
        """
        Get complete email template configuration for the specified email type

        :param email_type: Email type (e.g., EmailType.AI_ASSISTANT.value)
        :param customer_name: Name of the customer
        :return: Dict with subject, send_to, cc, bcc
        """
        # Load from environment first, fallback to defaults
        env_templates = cls._load_templates_from_env(default_cm_yy_daily_email_param)
        default_templates = cls._get_default_templates()

        # Get template from env or default
        if email_type in env_templates:
            template = env_templates[email_type]
        else:
            template = default_templates.get(email_type, {})

        # Ensure all required keys exist with defaults
        return {
            'subject': template.get('subject', 'Default Subject'),
            'send_to': template.get('send_to', []),
            'cc': template.get('cc', []),
            'bcc': template.get('bcc', [])
        }

    @classmethod
    def format_subject(cls, email_type: str, default_cm_yy_daily_email_param: str = None, **kwargs) -> str:
        """Format subject template with provided parameters"""
        template = cls.get(email_type, default_cm_yy_daily_email_param)
        subject_template = template['subject']

        if "subject_email_prefix" not in subject_template:
            kwargs.pop("subject_email_prefix", None)

        return subject_template.format(**kwargs)

    @classmethod
    def format_subject_v2(cls, subject_template: str = None, **kwargs) -> str:
        """Format subject template with provided parameters"""

        if "subject_email_prefix" not in subject_template:
            kwargs.pop("subject_email_prefix", None)

        return subject_template.format(**kwargs)

