class User:
    id: int
    email: str
    username: str
    timezone: str
    status: str = "Active"
    roles: list = None
    ms_id: str = ""
    permissions: list = None
    root: str = ""

    def __post_init__(self):
        if not self.email or "@" not in self.email:
            raise ValueError("Invalid email address!")

    def __repr__(self):
        return str({
            "ms_id": self.ms_id,
            "email": self.email,
            "timezone": self.timezone,
            "roles": self.roles,
            "permissions": self.permissions,
            "root": self.root,
        })

    @staticmethod
    def _get_role(role):
        return role.value

    def is_staff(self):
        if not self.roles:
            return True

        staff_role = self._get_role(Role.Staff)
        if staff_role in self.roles:
            return True

        return False

    def is_coordinator(self):
        if not self.roles:
            return False

        coordinator_role = self._get_role(Role.Coordinator)
        if coordinator_role in self.roles:
            return True

        return False

    def is_admin(self):
        if not self.roles:
            return False

        if self.is_staff() or self.is_coordinator():
            return False

        admin_role = self._get_role(Role.Admin)
        if admin_role in self.roles:
            return True

        return False

