def compute_techpack_search_clause(techpack_params, context=None):
    if context is None:
        context = {}

    search_clause, search_params = "", []
    customer_name = techpack_params.get('customer_name') or ''
    if customer_name:
        search_clause += " AND customer_name = %s"
        search_params.append(customer_name)

    po_associated = techpack_params.get("po_associated", False)
    cost_range = techpack_params.get("cost_range") or {}
    if po_associated and cost_range:
        min_cost = cost_range.get("from", 0)
        max_cost = cost_range.get("to", 0)
        if max_cost >= min_cost:
            search_clause += f" AND (po.min_cost >= {min_cost} AND po.max_cost <= {max_cost + 0.01})"

    num_prod_countries = techpack_params.get("num_prod_countries") or ''
    if po_associated and num_prod_countries:
        if num_prod_countries == 'single':
            search_clause += f" AND po.num_prod_countries = 1"

        elif num_prod_countries == 'multiple':
            search_clause += f" AND po.num_prod_countries > 1"

    quotattion_associated = techpack_params.get("quotation_associated", False)
    fob_range = techpack_params.get("fob_range") or {}
    if quotattion_associated and fob_range:
        min_cost = fob_range.get("from", 0)
        max_cost = fob_range.get("to", 0)
        if max_cost >= min_cost:
            search_clause += f" AND (rfq.min_cost >= {min_cost} AND rfq.max_cost <= {max_cost + 0.01})"


    suppliers = techpack_params.get("suppliers") or ''
    if suppliers:
        if suppliers == 'empty':
            suppliers = ''

    return search_clause, search_params

