class BaseExtractor(ABC):
    """Abstract base class for all PDF extractors."""

    def __init__(self, pdf_path: str):
        self.pdf_path = pdf_path
        self.pdf = None
        if not Path(pdf_path).exists():
            raise PDFNotFoundError(pdf_path)

    @abstractmethod
    def extract(self) -> Any:
        raise NotImplementedError

    def _open_pdf(self) -> None:
        try:
            self.pdf = pdfplumber.open(self.pdf_path)
        except Exception as e:
            raise PDFParseError(self.pdf_path, str(e))

    def _close_pdf(self) -> None:
        if self.pdf:
            self.pdf.close()
            self.pdf = None

    def _find_field_value(self, page, field_name: str, **kwargs) -> Optional[str]:
        return extract_field_value(page, field_name, **kwargs)

    def __enter__(self):
        self._open_pdf()
        return self

    def __exit__(self, *args):
        self._close_pdf()
        return False

class HeaderExtractor(BaseExtractor):
    """Extractor for header information from Tech Pack PDFs."""

    # 标准字段映射到模型属性
    STANDARD_FIELD_MAPPINGS = {
        "STYLE #": "StyleNo",
        "STYLE NAME": "StyleDescription",
        "SEASON": "Season",
        "DIVISION": "Department",
        "STAGE": "Status",
        "CATEGORY": "ProductCategory",
    }

    # 自定义字段 - 使用 PDF 字段名作为 JSON key
    CUSTOM_FIELDS = ["FACTORY", "COUNTRY OF ORIGIN"]

    # 需要拼接的字段 (FABRIC GROUP NAME / FABRIC CONTENT)
    FABRIC_FIELDS = ["FABRIC GROUP NAME", "FABRIC CONTENT"]

    def extract(self) -> TechPackHeader:
        log_info("Extracting header...")
        if not self.pdf:
            self._open_pdf()
        if not self.pdf:
            log_warn("PDF not opened")
            return TechPackHeader(StyleNo="", StyleDescription="", Season="") # type: ignore
        if not self.pdf.pages:
            log_warn("PDF has no pages")
            return TechPackHeader(StyleNo="", StyleDescription="", Season="") # type: ignore

        result: Dict[str, str] = {}
        fabric_values = {}

        # 合并所有字段用于查找
        all_fields = list(self.STANDARD_FIELD_MAPPINGS.keys()) + self.CUSTOM_FIELDS + self.FABRIC_FIELDS
        found_fields = set()  # 记录已找到的字段

        try:
            # 遍历所有页面查找字段
            for page_idx in range(len(self.pdf.pages)):
                # 如果所有字段都找到了，停止搜索
                if len(found_fields) == len(all_fields):
                    break

                page = self.pdf.pages[page_idx]
                tables = page.extract_tables()
                if not tables:
                    continue

                # 遍历当前页的所有表格查找字段
                for table in tables:
                    if not table:
                        continue

                    # Find field positions in this table
                    for row_idx, row in enumerate(table):
                        for col_idx, cell in enumerate(row or []):
                            if not cell:
                                continue
                            cell_str = str(cell).strip().rstrip(":").upper()
                            for pdf_field in all_fields:
                                # 只查找还没找到的字段
                                if pdf_field.upper() == cell_str and pdf_field not in found_fields:
                                    value = self._get_next_value(row, col_idx, all_fields)
                                    if value:
                                        found_fields.add(pdf_field)
                                        # 标准字段使用映射
                                        if pdf_field in self.STANDARD_FIELD_MAPPINGS:
                                            result[self.STANDARD_FIELD_MAPPINGS[pdf_field]] = value
                                        # FABRIC 字段暂存，后面拼接
                                        elif pdf_field in self.FABRIC_FIELDS:
                                            fabric_values[pdf_field] = value
                                        # 其他自定义字段使用原始字段名
                                        else:
                                            result[pdf_field] = value
                                        log_success(f"Header: {pdf_field} = {value[:30]}{'...' if len(value) > 30 else ''}")
                                    break

            # 拼接 FABRIC GROUP NAME / FABRIC CONTENT
            self._combine_fabric_fields(result, fabric_values)

            return TechPackHeader(**result) if result else TechPackHeader(StyleNo="", StyleDescription="", Season="") # type: ignore

        except Exception as e:
            log_warn(f"Header extraction error: {e}")
            return self._fallback_extraction(self.pdf.pages[0])

    def _combine_fabric_fields(self, result: Dict[str, str], fabric_values: Dict[str, str]) -> None:
        """拼接 FABRIC GROUP NAME 和 FABRIC CONTENT 为 'a / b' 格式"""
        group_name = clean_value(fabric_values.get("FABRIC GROUP NAME", ""))
        content = clean_value(fabric_values.get("FABRIC CONTENT", ""))

        if group_name and content:
            result["FABRIC GROUP NAME & FABRIC CONTENT"] = f"{group_name} / {content}"
        elif group_name:
            result["FABRIC GROUP NAME & FABRIC CONTENT"] = group_name
        elif content:
            result["FABRIC GROUP NAME & FABRIC CONTENT"] = content

    def _get_next_value(self, row: List, col_idx: int, all_fields: List[str]) -> Optional[str]:
        """Get value from next non-field cell."""
        for i in range(col_idx + 1, len(row)):
            cell = row[i]
            if not cell:
                continue
            cell_str = str(cell).strip()
            if cell_str and cell_str.rstrip(":").upper() not in [f.upper() for f in all_fields]:
                return cell_str
        return None

    def _fallback_extraction(self, page) -> TechPackHeader:
        result = {}
        all_fields = list(self.STANDARD_FIELD_MAPPINGS.keys()) + self.CUSTOM_FIELDS + self.FABRIC_FIELDS
        fabric_values = {}
        for pdf_field in all_fields:
            value = self._find_field_value(page, pdf_field)
            if value:
                if pdf_field in self.STANDARD_FIELD_MAPPINGS:
                    result[self.STANDARD_FIELD_MAPPINGS[pdf_field]] = value
                elif pdf_field in self.FABRIC_FIELDS:
                    fabric_values[pdf_field] = value
                else:
                    result[pdf_field] = value

        # 拼接 FABRIC 字段
        self._combine_fabric_fields(result, fabric_values)
        return TechPackHeader(**result) if result else TechPackHeader(StyleNo="", StyleDescription="", Season="") # type: ignore

def _get_pom_header_only_column_header() -> List[str]:
    """获取只有 header 的 POM 表的 ColumnHeader"""
    if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
        return POM_COLUMN_HEADER_PREFIX + [""] * POM_CUSTFIELD_COUNT
    return POM_COLUMN_HEADER_PREFIX

class POMExtractor(BaseExtractor):
    """Extractor for POM (Point of Measure) tables."""

    SIZE_KEYWORDS_SET = {"xxs", "xs", "s", "m", "l", "xl", "xxl"}
    TOL_KEYWORDS = {"target", "factory", "diff", "revised"}
    HEADER_MAPPINGS = {"SIZE RANGE": "SizeRange", "BASE SIZE": "BaseSize"}

    def extract(self) -> List[POMTable]:
        log_info("Extracting POM tables...")
        all_pom_data = []  # 收集所有 POM 数据
        merged_header = None
        merged_column_header = None
        found_pom_header = None  # 用于存储找到的 POM header 信息
        if not self.pdf:
            log_warn("PDF not opened")
            return []
        for page_idx, page in enumerate(self.pdf.pages, start=1):
            tables = page.extract_tables() or []
            for table in tables:
                if not table or len(table) < 3:
                    continue
                pom_table = self._extract_pom_table(table, page_idx)
                if pom_table:
                    log_success(f"POM table found on page {page_idx}: {len(pom_table.ColumnMeasurementData)} rows")
                    # 合并数据
                    all_pom_data.extend(pom_table.ColumnMeasurementData)
                    # 使用第一个找到的 header 和 column_header
                    if not merged_header:
                        merged_header = pom_table.Header
                    if not merged_column_header:
                        merged_column_header = pom_table.ColumnHeader
                else:
                    # 尝试从表格中提取 POM header 信息 (BASE SIZE, SIZE RANGE)
                    if not found_pom_header:
                        header_info = self._extract_pom_header(table)
                        if header_info.BaseSize or header_info.SizeRange:
                            found_pom_header = header_info

        # 如果找到了 POM 数据，合并成一个 POM 表
        if all_pom_data:
            return [POMTable(
                Seq=1,
                Header=merged_header or POMHeader(),
                ColumnHeader=merged_column_header or _get_pom_header_only_column_header(),
                ColumnMeasurementData=all_pom_data,
            )]

        # 如果没有找到 POM 表但找到了 header 信息，创建一个只有 header 的 POM 表
        if found_pom_header:
            log_info(f"Creating POM table with header only (BaseSize: {found_pom_header.BaseSize}, SizeRange: {found_pom_header.SizeRange})")
            return [POMTable(
                Seq=1,
                Header=found_pom_header,
                ColumnHeader=_get_pom_header_only_column_header(),
                ColumnMeasurementData=[],
            )]

        log_warn("No POM tables found")
        return []

    def _extract_pom_table(self, table: List[List[str|None]], page_idx: int) -> Optional[POMTable]:
        # Check if this is a GRADING/POM table
        table_text = " ".join(" ".join(str(c) for c in row if c) for row in table).lower()

        # 首先检查是否包含 GRADING 关键词
        has_grading = "grading" in table_text
        has_pom = "pom" in table_text or "point of measure" in table_text

        if not has_grading and not has_pom:
            return None

        # Find header row - 查找 GRADING 行后面的 POM 行
        header_row_idx = None
        grading_row_idx = None

        for i, row in enumerate(table[:20]):
            row_text = " ".join(str(c).lower() for c in row if c)
            # 先找 GRADING 行
            if grading_row_idx is None and "grading" in row_text:
                grading_row_idx = i
            # 找 POM 行（在 GRADING 行之后，或者没有 GRADING 时直接找）
            if "pom" in row_text or "point of measure" in row_text:
                # 如果有 GRADING，POM 行必须在 GRADING 之后
                if grading_row_idx is None or i > grading_row_idx:
                    header_row_idx = i
                    break

        if header_row_idx is None:
            return None

        header_row = table[header_row_idx]
        header_text = " ".join(str(c).lower() for c in header_row if c)

        # Check table type (skip tolerance-based tables)
        size_count = sum(1 for kw in self.SIZE_KEYWORDS_SET if kw in header_text)
        tol_count = sum(1 for kw in self.TOL_KEYWORDS if kw in header_text)

        if tol_count >= 2:
            log_info(f"Skipping tolerance-based POM table on page {page_idx}")
            return None
        if size_count < 3 and not has_grading:
            # 如果有 GRADING 关键词，放宽尺码数量要求
            return None

        # Extract column headers and data
        column_headers = [str(cell).strip() if cell else "" for cell in header_row]
        measurement_data = self._extract_measurement_data(table, header_row_idx, column_headers)

        if not measurement_data:
            return None

        # Parse and build POM table
        pom_header = self._extract_pom_header(table)
        column_mapping, size_columns = self._build_column_mapping(column_headers)
        parsed_data = self._parse_rows(measurement_data, column_mapping, size_columns)

        # 动态生成 ColumnHeader，使用实际尺码名称
        size_headers = [col_name.upper() for col_name in size_columns]
        if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
            padding = [""] * (POM_CUSTFIELD_COUNT - len(size_headers))
            dynamic_column_header = POM_COLUMN_HEADER_PREFIX + size_headers + padding
        else:
            dynamic_column_header = POM_COLUMN_HEADER_PREFIX + size_headers

        return POMTable(
            Header=pom_header,
            ColumnHeader=dynamic_column_header,
            ColumnMeasurementData=parsed_data,
        )


    def _extract_measurement_data(self, table: List[List[str|None]], header_row_idx: int, column_headers: List[str]) -> List[List[str]]:
        """Extract and filter measurement data rows."""
        measurement_data = []
        for row in table[header_row_idx + 1:]:
            row_data = [str(cell).strip() if cell else "" for cell in row]
            if not any(row_data):
                continue
            first_cell = row_data[0].upper() if row_data else ""
            if first_cell and len(first_cell) < 30 and sum(1 for c in row_data[1:] if c) <= 1:
                continue
            measurement_data.append(row_data)
        return measurement_data

    def _extract_pom_header(self, table: List[List[str|None]]) -> POMHeader:
        """Extract POM header metadata."""
        result = {}
        for row in table[:10]:
            if not row:
                continue
            for col_idx, cell in enumerate(row):
                if not cell:
                    continue
                cell_str = str(cell).strip().rstrip(":").upper()
                if cell_str in self.HEADER_MAPPINGS:
                    for i in range(col_idx + 1, len(row)):
                        if row[i] and str(row[i]).strip():
                            result[self.HEADER_MAPPINGS[cell_str]] = str(row[i]).strip()
                            break
        return POMHeader(**result)

    def _build_column_mapping(self, headers: List[str]) -> Tuple[Dict[str, int], List[str]]:
        """Build column index mapping and return size column names."""
        mapping = {}
        size_columns = []  # 存储实际的尺码名称

        for col_idx, header in enumerate(headers):
            if not header:
                continue
            header_lower = header.strip().lower().replace('\n', ' ')

            if any(skip in header_lower for skip in SKIP_COLUMNS):
                continue

            # Check standard columns
            matched = False
            for pdf_col, model_field in POM_COLUMN_MAPPINGS.items():
                if pdf_col in header_lower:
                    if pdf_col == "tol":
                        mapping["TolMinus"] = col_idx
                        mapping["TolPlus"] = col_idx
                    else:
                        mapping[model_field] = col_idx
                    matched = True
                    break

            # Check size columns - 保存实际的尺码名称
            if not matched and header_lower in SIZE_KEYWORDS and len(size_columns) < 8:
                size_columns.append(header.strip())
                mapping[f"Size_{len(size_columns)}"] = col_idx

        return mapping, size_columns

    def _parse_rows(self, data: List[List[str]], mapping: Dict[str, int], size_columns: List[str]) -> List[List[str]]:
        """Parse measurement rows according to field order."""
        # 动态生成字段顺序：固定前缀 + 尺码列
        field_order = POM_FIELD_ORDER_PREFIX + [f"Size_{i+1}" for i in range(len(size_columns))]
        result = []
        for data_row in data:
            row_values = [
                clean_value(data_row[mapping[field]]) if field in mapping and mapping[field] < len(data_row) and data_row[mapping[field]] else ""
                for field in field_order
            ]
            # 根据配置决定是否填充空字符串
            if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
                padding_count = POM_CUSTFIELD_COUNT - len(size_columns)
                row_values.extend([""] * padding_count)
            result.append(row_values)
        return result

def _get_bom_column_header() -> List[str]:
    """获取 BOM 的 ColumnHeader（无 colorway 列名时使用）"""
    if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
        custfields = [""] * 5 + [""] + [""] * 8
        return BOM_COLUMN_HEADER_BASE + custfields
    return BOM_COLUMN_HEADER_BASE

def _get_bom_column_header_with_colorway(colorway_names: List[str]) -> List[Any]:
    """获取 BOM 的 ColumnHeader，使用实际的 colorway 列名"""
    # colorway 列名用 {"Colorway": [...]} 格式包裹
    colorway_header: Any = {"Colorway": colorway_names} if colorway_names else ""

    if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
        custfields: List[Any] = [""] * 5 + [colorway_header] + [""] * 8
        return BOM_COLUMN_HEADER_BASE + custfields

    if colorway_names:
        return BOM_COLUMN_HEADER_BASE + [colorway_header]
    return BOM_COLUMN_HEADER_BASE

def _get_bom_field_order() -> List[str]:
    """获取 BOM 的字段顺序"""
    if PADDING_NULL_CUSTFIELDS_WITH_EMPTY_STRING:
        return BOM_FIELD_ORDER_BASE + [f"CustField{i}" for i in range(1, BOM_CUSTFIELD_COUNT + 1)]
    return BOM_FIELD_ORDER_BASE + ["CustField6"]

class BOMExtractor(BaseExtractor):
    """Extractor for BOM (Bill of Materials) tables."""

    def extract(self) -> List[BOMTable]:
        log_info("Extracting BOM tables...")
        all_bom_data = []
        merged_column_header = None
        if not self.pdf:
            log_warn("PDF not opened")
            return []

        for page_idx, page in enumerate(self.pdf.pages, start=1):
            tables = page.extract_tables() or []
            for table in tables:
                if not table or len(table) < 2:
                    continue
                bom_table = self._extract_bom_table(table, page_idx)
                if bom_table:
                    log_success(f"BOM table found on page {page_idx}: {len(bom_table.Data)} rows")
                    all_bom_data.extend(bom_table.Data)
                    if not merged_column_header:
                        merged_column_header = bom_table.ColumnHeader

        if all_bom_data:
            return [BOMTable(
                Seq=1,
                ColumnHeader=merged_column_header or _get_bom_column_header(),
                Data=all_bom_data,
            )]

        log_warn("No BOM tables found")
        return []

    def _extract_bom_table(self, table: List[List[str | None]], page_idx: int) -> Optional[BOMTable]:
        table_text = " ".join(" ".join(str(c) for c in row if c) for row in table[:10]).lower()
        if sum(1 for kw in BOM_KEYWORDS if kw in table_text) < 2:
            return None

        header_row_idx = self._find_header_row(table)
        if header_row_idx is None:
            return None

        raw_headers = [str(cell).strip() if cell else "" for cell in table[header_row_idx]]
        column_mapping, colorway_names = self._build_column_mapping(raw_headers)

        # 提取 pdfplumber 的 placement 数据
        pdfplumber_placements = self._get_pdfplumber_placements(table, header_row_idx, column_mapping)

        # 获取 camelot 修正数据（用于修正 Quantity 和 Colorway）
        camelot_corrections = self._get_camelot_corrections(page_idx, pdfplumber_placements)

        category_map = self._extract_category_rows(table, header_row_idx)
        data_rows = self._extract_data_rows(table, category_map, column_mapping, camelot_corrections)

        if not data_rows:
            return None

        for cat, indices in category_map.items():
            if cat:
                log_info(f"  Category '{cat}': {len(indices)} items")

        column_header = _get_bom_column_header_with_colorway(colorway_names)
        return BOMTable(ColumnHeader=column_header, Data=data_rows)

    def _find_header_row(self, table: List[List[str | None]]) -> Optional[int]:
        for i, row in enumerate(table[:15]):
            row_text = " ".join(str(cell).lower() for cell in row if cell)
            has_desc = "description" in row_text
            has_vendor = any(kw in row_text for kw in ["vendor", "supplier", "mill"])
            has_article = "article" in row_text
            if has_desc and (has_vendor or has_article):
                return i
        return None

    def _build_column_mapping(self, headers: List[str]) -> Tuple[Dict[str, int], List[str]]:
        mapping = {}
        colorway_cols = []
        colorway_names = []

        for col_idx, header in enumerate(headers):
            if not header:
                continue
            header_lower = header.strip().lower().replace("\n", " ")

            matched = False
            for pdf_col, model_field in BOM_COLUMN_MAPPINGS.items():
                if pdf_col in header_lower and model_field not in mapping:
                    mapping[model_field] = col_idx
                    matched = True
                    break

            if not matched and "color" in header_lower:
                colorway_cols.append(col_idx)
                colorway_names.append(clean_value(header.strip()))

        if colorway_cols:
            mapping["_colorway_columns"] = colorway_cols

        return mapping, colorway_names

    def _extract_category_rows(self, table: List[List[str | None]], header_row_idx: int) -> Dict[str, List[int]]:
        category_map: Dict[str, List[int]] = {}
        current_category = "FABRIC"

        for row_idx, row in enumerate(table[header_row_idx + 1 :], start=header_row_idx + 1):
            row_data = [str(cell).strip() if cell else "" for cell in row]
            if not any(row_data):
                continue

            first_cell = row_data[0].upper() if row_data else ""

            if first_cell in MATERIAL_CATEGORIES:
                non_empty = sum(1 for c in row_data[1:] if c)
                if non_empty <= 1:
                    current_category = first_cell
                    if current_category not in category_map:
                        category_map[current_category] = []
                    continue

            cat_key = current_category or ""
            if cat_key not in category_map:
                category_map[cat_key] = []
            category_map[cat_key].append(row_idx)

        return category_map

    def _get_camelot_corrections(self, page_idx: int, pdfplumber_placements: Dict[str, str]) -> Dict[str, Dict[str, str]]:
        """使用 camelot 获取正确的 Quantity 和 Colorway 值

        Camelot stream 模式会把 PLACEMENT 和 COLOR 1 合并到一列
        如果有 \n 分隔，最后部分是 colorway
        如果没有 \n，整个值是 placement，colorway 在前后延续行
        """
        try:
            tables = camelot.read_pdf(self.pdf_path, pages=str(page_idx), flavor="stream")
            if not tables:
                return {}

            df = tables[0].df
            corrections: Dict[str, Dict[str, str]] = {}

            # 找 header 行和列
            header_idx = None
            qty_col = None
            desc_col = None
            placement_color_col = None

            for idx in range(min(15, len(df))):
                row = df.iloc[idx].tolist()
                row_text = " ".join(str(c).lower() for c in row if c)
                if "description" in row_text and ("vendor" in row_text or "article" in row_text):
                    header_idx = idx
                    for col_idx, cell in enumerate(row):
                        cell_str = str(cell) if cell else ""
                        cell_lower = cell_str.lower()
                        if "yield" in cell_lower or "qty" in cell_lower:
                            qty_col = col_idx
                        if "description" in cell_lower:
                            desc_col = col_idx
                        # 只取第一个包含 placement 的列（PLACEMENT\nCOLOR 1）
                        if placement_color_col is None and "placement" in cell_lower:
                            placement_color_col = col_idx
                    break

            if header_idx is None or desc_col is None:
                return {}

            # 收集所有行信息（包括延续行的 colorway）
            rows_info = []
            for idx in range(header_idx + 1, len(df)):
                row = df.iloc[idx].tolist()
                desc_val = str(row[desc_col]).strip() if desc_col < len(row) and row[desc_col] else ""
                qty_val = str(row[qty_col]).strip() if qty_col and qty_col < len(row) and row[qty_col] else ""

                # 获取合并列的值
                merged_val = ""
                if placement_color_col and placement_color_col < len(row) and row[placement_color_col]:
                    merged_val = str(row[placement_color_col]).strip()

                # 判断 colorway
                colorway_val = ""
                has_newline = "\n" in merged_val

                if merged_val and desc_val:
                    # 数据行
                    if has_newline:
                        # 有换行符，最后部分是 colorway
                        parts = merged_val.split("\n")
                        colorway_val = parts[-1].strip()
                    else:
                        # 没有换行符，整个值是 placement，colorway 在延续行
                        colorway_val = ""
                elif merged_val and not desc_val:
                    # 延续行，整个值可能是 colorway（不含位置关键词）
                    placement_keywords = ["BACK", "FRONT", "SLEEVE", "GARMENT", "ATTACH", "CORNER", "PACKED", "ENTIRE", "WEARER", "HANGTAG", "GLASSINE", "BAG"]
                    if not any(kw in merged_val.upper() for kw in placement_keywords):
                        colorway_val = merged_val.replace("\n", " ").strip()

                non_empty = sum(1 for c in row if c)
                rows_info.append({
                    "idx": idx,
                    "desc": desc_val,
                    "qty": qty_val,
                    "colorway": colorway_val,
                    "non_empty": non_empty,
                    "has_newline": has_newline,
                })

            # 处理数据行，合并前后延续行的 colorway
            for i, ri in enumerate(rows_info):
                if ri["desc"]:
                    colorway_parts = []

                    # 如果没有换行符，检查前一行是否有 colorway（前置延续行）
                    if not ri["has_newline"] and i > 0:
                        prev_ri = rows_info[i - 1]
                        if not prev_ri["desc"] and prev_ri["colorway"]:
                            colorway_parts.append(prev_ri["colorway"])

                    # 当前行的 colorway
                    if ri["colorway"]:
                        colorway_parts.append(ri["colorway"])

                    # 收集后续延续行的 colorway
                    j = i + 1
                    while j < len(rows_info):
                        next_ri = rows_info[j]
                        if next_ri["desc"]:
                            break
                        if next_ri["colorway"]:
                            colorway_parts.append(next_ri["colorway"])
                        j += 1

                    merged_colorway = " ".join(colorway_parts).strip()
                    corrections[ri["desc"].upper()] = {
                        "qty": ri["qty"],
                        "colorway": merged_colorway,
                    }

            return corrections

        except Exception as e:
            log_warn(f"Camelot correction failed: {e}")
            return {}

    def _extract_data_rows(self, table: List[List[str | None]], category_map: Dict[str, List[int]], mapping: Dict[str, int], camelot_corrections: Dict[str, Dict[str, str]]) -> List[List[str]]:
        result = []
        field_order = _get_bom_field_order()

        for category, row_indices in category_map.items():
            for row_idx in row_indices:
                row = table[row_idx]
                row_data = [clean_value(str(cell)) if cell else "" for cell in row]

                # 获取 description 用于查找 camelot 修正
                desc_val = self._get_mapped_value(row_data, mapping, "MaterialType")
                correction = camelot_corrections.get(desc_val.upper()) if desc_val else None

                row_values = []
                for field in field_order:
                    value: Any = ""
                    if field == "BomHeader":
                        value = "BOM"
                    elif field == "MaterialCategory":
                        value = category
                    elif field == "MaterialDescription":
                        size_val = self._get_mapped_value(row_data, mapping, "Size")
                        type_val = self._get_mapped_value(row_data, mapping, "MaterialType")
                        value = f"{size_val} {type_val}".strip() if size_val or type_val else ""
                    elif field == "Quantity":
                        pdfplumber_qty = self._get_mapped_value(row_data, mapping, field)
                        # 只有当 pdfplumber 的 Quantity 有溢出问题时才用 camelot 修正
                        # 溢出特征：包含连续字母（如 "2 INSIDE BA"），而不是简单的 "3+ 1" 格式
                        if correction and correction.get("qty") and pdfplumber_qty:
                            import re
                            # 检查是否有连续2个以上字母（溢出的文本）
                            has_overflow = bool(re.search(r'[A-Za-z]{2,}', pdfplumber_qty))
                            if has_overflow:
                                value = correction["qty"]
                            else:
                                value = pdfplumber_qty
                        else:
                            value = pdfplumber_qty
                    elif field == "CustField6":
                        # 先获取 pdfplumber 的 colorway
                        pdfplumber_colorway = ""
                        if "_colorway_columns" in mapping:
                            colorway_vals = [clean_value(row_data[i]) for i in mapping["_colorway_columns"] if i < len(row_data) and row_data[i]]  # type: ignore
                            if colorway_vals:
                                pdfplumber_colorway = colorway_vals[0]

                        # 只有当 pdfplumber colorway 看起来有问题时才用 camelot 修正
                        # 问题特征：包含乱码字符（如连续大写字母组成的无意义词）
                        use_camelot = False
                        if correction and correction.get("colorway") and pdfplumber_colorway:
                            # 检查是否有乱码（如 INEW, BHAIGTE 等）
                            import re
                            # 乱码通常是连续的大写字母，不是常见英文单词
                            words = re.findall(r'\b[A-Z]{4,}\b', pdfplumber_colorway)
                            uncommon_words = [w for w in words if w not in ['WITH', 'BLACK', 'WHITE', 'NATURAL', 'SELF', 'PRINT', 'GROUND', 'LABEL', 'ROUGE', 'FLEURS']]
                            if uncommon_words:
                                use_camelot = True

                        if use_camelot:
                            colorway_obj = {"Colorway": [correction["colorway"]]}
                            value = json.dumps(colorway_obj) if COLORWAY_AS_JSON_STRING else colorway_obj
                        elif pdfplumber_colorway:
                            colorway_vals = [clean_value(row_data[i]) for i in mapping["_colorway_columns"] if i < len(row_data) and row_data[i]]  # type: ignore
                            colorway_obj = {"Colorway": colorway_vals}
                            value = json.dumps(colorway_obj) if COLORWAY_AS_JSON_STRING else colorway_obj
                    elif field.startswith("CustField") and field != "CustField6":
                        value = ""
                    elif field in mapping:
                        value = self._get_mapped_value(row_data, mapping, field)
                    row_values.append(value)

                if any(v for v in row_values if v and v != "BOM"):
                    result.append(row_values)

        return result

    def _get_mapped_value(self, row_data: List[str], mapping: Dict[str, int], field: str) -> str:
        if field in mapping:
            col_idx = mapping[field]
            if col_idx < len(row_data):
                return row_data[col_idx]
        return ""

    def _get_pdfplumber_placements(self, table: List[List[str | None]], header_row_idx: int, mapping: Dict[str, int]) -> Dict[str, str]:
        """从 pdfplumber 表格中提取 description -> placement 映射"""
        placements: Dict[str, str] = {}
        desc_col = mapping.get("MaterialType")
        placement_col = mapping.get("Placement")

        if desc_col is None or placement_col is None:
            return placements

        for row in table[header_row_idx + 1:]:
            row_data = [str(cell).strip() if cell else "" for cell in row]
            desc_val = row_data[desc_col] if desc_col < len(row_data) else ""
            placement_val = row_data[placement_col] if placement_col < len(row_data) else ""

            if desc_val and desc_val.upper() not in MATERIAL_CATEGORIES:
                placements[desc_val.upper()] = placement_val

        return placements

