class EtamUndizExtractionService(BaseExtractionService):
    """
    Undiz extraction service
    """

    # === Temporary feature: Directory traversal ===
    # Set ENABLE_BATCH_PROCESS = True to enable batch processing,
    # False to use the original single file processing logic
    ENABLE_BATCH_PROCESS = True  # Temporary feature, can be changed to False to restore original logic

    def __init__(self):
        super().__init__(customer_name="Undiz")

    def standardize_dataframe(self, df, mapping, fixed_headers, drop_extra_columns=False):
        """Generic function: Standardize DataFrame column names and order (active extraction mode)

        Args:
            df: Original DataFrame
            mapping: {original_column_name: target_column_name} mapping dictionary
            fixed_headers: Target column name list (standard order)
            drop_extra_columns: Whether to drop columns not in fixed_headers (default False)

        Returns:
            Standardized DataFrame
        """
        df = self.clean_columns(df.copy())

        # Build new data dictionary
        new_data = {}
        source_cols_used = set()  # Track original columns already used

        # 1. Active extraction: Iterate through standard headers and find data from source table
        for target_col in fixed_headers:
            found_source_col = None

            # A. Try reverse lookup through mapping
            if mapping:
                for src, dst in mapping.items():
                    if dst == target_col and src in df.columns:
                        found_source_col = src
                        break

            # B. If mapping doesn't find it, try direct same-name column lookup
            if not found_source_col and target_col in df.columns:
                found_source_col = target_col

            # C. Get value or fill empty
            if found_source_col:
                new_data[target_col] = df[found_source_col]
                source_cols_used.add(found_source_col)
            else:
                # Create a Series with empty strings matching the DataFrame length
                import pandas as pd
                new_data[target_col] = pd.Series([""] * len(df), index=df.index)

        # 2. Handle remaining columns (if drop_extra_columns=False)
        #    This is important for POM because size columns are usually not in fixed_headers
        if not drop_extra_columns:
            for col in df.columns:
                if col not in source_cols_used:
                    # If this column hasn't been used to fill any standard column, preserve it as extra column
                    # (Note: if an original column was mapped, it's already been used above, no duplicate here)
                    new_data[col] = df[col]

        # 3. Generate new DataFrame
        #    Note: Dictionary key order is preserved in Python 3.7+, so fixed_headers will be first
        return pd.DataFrame(new_data)

    def extract_field_all(self, pdf_source, field_name, max_width=180, x_tolerance=2, line_tol=2, same_line_top_tol=5,
                          same_line_x_tol=0):
        """Extract text to the right of a field (supports multi-word matching)

        Args:
            pdf_source: PDF file path or PDF object
            field_name: Field name (supports multiple words)
            max_width: Maximum extraction width
            x_tolerance: X direction tolerance
            line_tol: Line tolerance
            same_line_top_tol: Top distance threshold for same-line judgment (default 5)
            same_line_x_tol: X distance threshold for same-line judgment (default 0)
        """
        result = ""
        tokens = field_name.split()
        n = len(tokens)

        def _extract_from_pages(pages_iter, cache):
            nonlocal result
            for page in pages_iter:
                if cache is not None:
                    page_id = id(page)
                    words = cache.setdefault(page_id, page.extract_words() or [])
                else:
                    words = page.extract_words() or []
                texts = [w["text"].strip() for w in words]
                for i in range(len(texts) - n + 1):
                    if all(texts[i + j].lower() == tokens[j].lower() for j in range(n)):
                        fw = words[i + n - 1]  # Last word of field name
                        next_index = i + n
                        if next_index < len(words):
                            next_w = words[next_index]
                            # If next word is on same line and x distance is small → exclude (e.g., "Size Chart Review")
                            if abs(next_w["top"] - fw["top"]) < same_line_top_tol and 0 <= (
                                    next_w["x0"] - fw["x1"]) < same_line_x_tol:
                                continue  # Not a field name, skip
                        # ⚙️ Use last word's geometry as field reference
                        hw = words[i]
                        t_f = fw["top"]
                        x_start = fw["x1"]
                        x_end = x_start + max_width
                        below = [
                            w for w in words
                            if w["top"] > hw["bottom"]
                               and hw["x0"] - x_tolerance <= w["x0"] <= hw["x1"] + x_tolerance
                        ]
                        next_top = min((w["top"] for w in below), default=float("inf"))
                        picked = [
                            w for w in words
                            if x_start - 2 <= w["x0"] <= x_end
                               and t_f - line_tol <= w["top"] < next_top - line_tol
                        ]
                        picked.sort(key=lambda w: (w["top"], w["x0"]))
                        if picked:
                            result = " ".join(w["text"] for w in picked).strip()
                        return result
            return result

        if isinstance(pdf_source, str):
            with pdfplumber.open(pdf_source) as pdf:
                return _extract_from_pages(pdf.pages, {})
        elif hasattr(pdf_source, "pages"):
            cache = _PDF_WORD_CACHE.setdefault(pdf_source, {})
            return _extract_from_pages(pdf_source.pages, cache)
        else:
            return _extract_from_pages(pdf_source, {})
        return result
    def replace_newlines_in_json(self, obj):
        """Recursively replace newlines with spaces in all strings in JSON object"""
        if isinstance(obj, dict):
            return {key: self.replace_newlines_in_json(value) for key, value in obj.items()}
        elif isinstance(obj, list):
            return [self.replace_newlines_in_json(item) for item in obj]
        elif isinstance(obj, str):
            return obj.replace("\n", " ")
        else:
            return obj
    def _norm_text(self, s: str) -> str:
        s = re.sub(r"[^0-9A-Za-z]+", " ", str(s) if s is not None else "")
        return re.sub(r"\s+", " ", s).strip().lower()

    def find_title_bboxes(self, page, targets):
        """Find bbox areas of specified titles"""
        words = page.extract_words(x_tolerance=2, y_tolerance=2) or []
        if not words:
            return []
        toks_norm = [w["text"] for w in words]
        results = []
        for target in targets:
            parts = [p for p in target.split(" ") if p]
            n = len(parts)
            for i in range(len(toks_norm) - n + 1):
                if toks_norm[i: i + n] == parts:
                    x0 = min(words[i + j]["x0"] for j in range(n))
                    x1 = max(words[i + j]["x1"] for j in range(n))
                    top = min(words[i + j]["top"] for j in range(n))
                    bottom = max(words[i + j]["bottom"] for j in range(n))
                    if x0 < 50:
                        results.append({"target": target, "bbox": (x0, top, x1, bottom)})
                        break
        return results

    def extract_tables_below(self, page, y_threshold):
        """Extract tables below the title"""
        bbox = (0, y_threshold, page.width, page.height)
        cropped = page.within_bbox(bbox)
        for ts in [
            {"vertical_strategy": "lines", "horizontal_strategy": "lines"},
            {"vertical_strategy": "text", "horizontal_strategy": "text"},
        ]:
            try:
                tables = cropped.extract_tables(table_settings=ts) or []
            except Exception:
                tables = []
            if tables:
                return tables
        return []

    def table_to_df(self, table):
        """Convert list to DataFrame"""
        try:
            return pd.DataFrame(table[1:], columns=table[0])
        except Exception:
            return pd.DataFrame(table)

    def load_RPA_json(self, rpa_filename, tamp_json):
        """Load RPA file and append [GET_BY_RPA] suffix"""
        with open(rpa_filename, "r", encoding="utf-8") as f:
            rpa_json = json.load(f)

        def suffix(v): return (str(v).strip() + "[GET_BY_RPA]") if v else ""

        tamp_json["CUSTOMER"] = rpa_json.get("customer_name", "")
        tamp_json["STYLE_NO"] = rpa_json.get("style_no", "")
        tamp_json["STYLE_DESCRIPTION"] = rpa_json.get("style_description", "")
        tamp_json["DEPARTMENT"] = rpa_json.get("customer_department", "")
        tamp_json["SEASON"] = rpa_json.get("style_season", "")
        tamp_json["TECH_PACK_STATUS"] = rpa_json.get("customer_techpack_status", "")
        return tamp_json, rpa_json

    def df_to_bom_json(
            self,
            df,
            column_mapping,
            fixed_column_header,
            seq=1,
            type_name="BOM",
            header=None,
            increment_display=None
    ):
        """DataFrame → BOM/POM JSON"""
        df = df.copy()
        df.columns = [c.replace("\n", " ").strip() for c in df.columns]
        cols = list(df.columns)

        def _to_float(value):
            if pd.isna(value):
                return None
            try:
                return float(str(value).replace(",", "").strip())
            except (TypeError, ValueError):
                return None

        # 保留原顺序并映射
        if column_mapping:
            column_header = [column_mapping.get(col, col) for col in cols]
        else:
            column_header = cols.copy()
        dst_idx = None
        if "DST comments" in df.columns:
            dst_idx = df.columns.get_loc("DST comments")
            right_cols = cols[dst_idx + 1:]
            if right_cols:
                merged_name = ", ".join(right_cols)
                column_header = column_header[:dst_idx + 1] + [merged_name]

        # 生成 Data
        data_rows = []
        for _, row in df.iterrows():
            row_data = []
            if dst_idx is not None:
                left_cols = cols[:dst_idx + 1]
                right_cols = cols[dst_idx + 1:]
            else:
                left_cols = cols
                right_cols = []
            for col in left_cols:
                val = "" if pd.isna(row[col]) else str(row[col])
                if val == "\ue5ca": val = "Y"
                row_data.append(val)
            colorway_list = [str(row[c]).strip() for c in right_cols if not pd.isna(row[c]) and str(row[c]).strip()]
            if colorway_list:
                # colorway_json = json.dumps(colorway_list, ensure_ascii=False)
                row_data.append(colorway_list)
            data_rows.append(row_data)
        converted_rows = []
        if (
                type_name == "POM"
                and increment_display == "Grading Standart"
                and "Hide" in df.columns
        ):
            grad_idx = df.columns.get_loc("Hide")
            size_cols = list(df.columns[grad_idx + 1:])
            base_col = "M" if "M" in size_cols else None
            if base_col:
                converted_df = df.copy()
                for idx in converted_df.index:
                    base_val = _to_float(converted_df.at[idx, base_col])
                    if base_val is None:
                        continue
                    converted_df.at[idx, base_col] = f"{base_val:.2f}"
                    base_idx = size_cols.index(base_col)
                    row_deltas = {
                        col: _to_float(df.at[idx, col])
                        for col in size_cols
                        if col != base_col
                    }
                    running = base_val
                    for col in size_cols[base_idx + 1:]:
                        delta = row_deltas.get(col)
                        if delta is None:
                            continue
                        running += delta
                        converted_df.at[idx, col] = f"{running:.2f}"
                    running = base_val
                    for col in reversed(size_cols[:base_idx]):
                        delta = row_deltas.get(col)
                        if delta is None:
                            continue
                        running += delta
                        converted_df.at[idx, col] = f"{running:.2f}"
                for _, row in converted_df.iterrows():
                    row_data = []
                    if dst_idx is not None:
                        left_cols = cols[:dst_idx + 1]
                        right_cols = cols[dst_idx + 1:]
                    else:
                        left_cols = cols
                        right_cols = []
                    for col in left_cols:
                        val = "" if pd.isna(row[col]) else str(row[col])
                        row_data.append(val)
                    colorway_list = [
                        str(row[c]).strip()
                        for c in right_cols
                        if not pd.isna(row[c]) and str(row[c]).strip()
                    ]
                    if colorway_list:
                        row_data.append(colorway_list)
                    converted_rows.append(row_data)
                if converted_rows:
                    print("ℹ️ Grading Standart data converted to standard size values based on M size")

        if type_name == "POM":
            if increment_display == "Grading Standart":
                print("⚠️ Size increment is Grading Standart, please confirm if the Gradation field in POM needs adjustment")
                return {
                    "Seq": seq,
                    "Type": type_name,
                    "Name": type_name,
                    "Header": header or {},
                    "ColumnHeader": column_header,
                    "ColumnGradingData": data_rows,
                    "ColumnMeasurementData": converted_rows
                }
            else:
                return {
                    "Seq": seq,
                    "Type": type_name,
                    "Name": type_name,
                    "Header": header or {},
                    "ColumnHeader": column_header,
                    "ColumnGradingData": data_rows,
                    "ColumnMeasurementData": []
                }
        else:
            return {
                "Seq": seq,
                "Type": type_name,
                "Name": type_name,
                "Header": header or {},
                "ColumnHeader": column_header,
                "Data": data_rows
            }

    def clean_columns(self, df):
        """Clean column names, handle None values, ensure column name uniqueness"""
        cleaned_cols = []
        for c in df.columns:
            if c is None:
                cleaned_cols.append("Unnamed")
            else:
                cleaned_cols.append(str(c).replace("\n", " ").strip())

        # Ensure column name uniqueness: if there are duplicate column names, add suffix _1, _2, ...
        seen = {}
        unique_cols = []
        for col in cleaned_cols:
            if col in seen:
                seen[col] += 1
                unique_cols.append(f"{col}_{seen[col]}")
            else:
                seen[col] = 0
                unique_cols.append(col)

        df.columns = unique_cols
        return df

    def filter_invalid_rows(self, df):
        """Filter invalid rows: delete rows containing 'Displaying' or '(Blanks)'"""
        if df.empty:
            return df

        # Create a boolean index marking rows to keep
        mask = pd.Series([True] * len(df), index=df.index)

        # Check all cells in each row
        for idx in df.index:
            row = df.loc[idx]
            # Convert all row values to strings and check for invalid text
            row_str = ' '.join([str(val) for val in row if pd.notna(val)])
            row_lower = row_str.lower()

            if 'displaying' in row_lower or '(blanks)' in row_lower or 'blanks' in row_lower:
                mask[idx] = False

        return df[mask]


    def find_pdf_rpa_pairs(self, directory="."):
        """Find all PDF files and corresponding RPA json files in directory"""
        directory = Path(directory)
        pdf_files = list(directory.glob("*.pdf"))
        pairs = []

        for pdf_file in pdf_files:
            # Find corresponding -rpa.json file
            pdf_stem = pdf_file.stem
            rpa_file = directory / f"{pdf_stem}-rpa.json"

            if rpa_file.exists():
                pairs.append((str(pdf_file), str(rpa_file)))
            else:
                print(f"⚠️ RPA file not found: {rpa_file}")

        return pairs

