    def process_pdf_rpa_pair(self, pdf_path, rpa_path):
        print(f"\nProcessing file pair:")
        print(f"  PDF: {pdf_path}")
        print(f"  RPA: {rpa_path}")

        tamp_json, rpa_json = self.load_RPA_json(rpa_path, self.init_tamp_json())
        all_tables = {t: [] for t in target_titles}

        try:
            field_values = {}
            with pdfplumber.open(pdf_path) as pdf:
                for page in pdf.pages:
                    hits = self.find_title_bboxes(page, target_titles)
                    for hit in hits:
                        y1 = hit["bbox"][3]
                        tables = self.extract_tables_below(page, y1 - 15)
                        if tables:
                            df = self.table_to_df(tables[0])
                            if not df.empty:
                                all_tables[hit["target"]].append(df)
                field_values = {
                    "increment_display": self.extract_field_all(pdf, "Increment Display:", max_width=100),
                    "pom_description": self.extract_field_all(pdf, "Size Chart", same_line_x_tol=60),
                    "grading_uom": self.extract_field_all(pdf, "Units:", max_width=10),
                    "base_size": self.extract_field_all(pdf, "Base Size"),
                    "size_range": self.extract_field_all(pdf, "Size Range"),
                    "commentaires_modeliste": self.extract_field_all(pdf, "Commentaires Modéliste"),
                    "cup_abc": self.extract_field_all(pdf, "Cup ABC"),
                    "cup_def": self.extract_field_all(pdf, "Cup DEF"),
                    "wire_abc": self.extract_field_all(pdf, "Wire ABC"),
                    "wire_def": self.extract_field_all(pdf, "Wire DEF"),
                    "vendor": self.extract_field_all(pdf, "Production Supplier"),
                    "NewCarryOverRepeated": self.extract_field_all(pdf, "Repeat Order"),
                }
        except Exception as e:
            print(f"⚠️ Error processing PDF: {e}")
            return False

        # Process Multi- table merging: if the first column is "color", merge to previous Multi- table
        # Before building merged_tables, complete processing of all Multi- tables
        # Color table has 2 header rows, except for the first table, others start from row 3 (skip first 2 header rows)
        if "Multi-" in all_tables and len(all_tables["Multi-"]) > 0:
            multi_tables = all_tables["Multi-"]
            merged_multi = []

            for df in multi_tables:
                if df is None or df.empty:
                    continue

                # Clean column names
                df_cleaned = self.clean_columns(df.copy())

                # Check if first column is "color" (case-insensitive and whitespace-insensitive)
                if len(df_cleaned.columns) > 0:
                    first_col = str(df_cleaned.columns[0]).strip().lower()
                    first_col_clean = re.sub(r'\s+', ' ', first_col).strip()
                    is_color_table = first_col_clean == "color"

                    # If first column is "color" and previous table exists, merge directly (add columns)
                    if is_color_table and merged_multi:
                        # Color table has 2 header rows, keep complete table structure (including 2 header rows)
                        # Use axis=1 for horizontal merge (add columns), preserve color table's 2 header rows
                        merged_multi[-1] = pd.concat([merged_multi[-1], df_cleaned], axis=1, sort=False)
                    else:
                        # First table added normally (including header)
                        merged_multi.append(df_cleaned)

            # Update Multi- table list in all_tables
            all_tables["Multi-"] = merged_multi

        # After all table processing, build merged_tables
        # Multi- table needs special handling because color table header has 2 rows, already merged in previous step
        merged_tables = {}

        # First process non-Multi- tables
        for t, dfs in all_tables.items():
            if t != "Multi-" and dfs:
                merged_tables[t] = self.filter_invalid_rows(pd.concat(dfs, ignore_index=True).dropna(how="all"))

        # Separately process Multi- table (already merged, use directly, no more concat merge)
        if "Multi-" in all_tables and all_tables["Multi-"]:
            multi_dfs = all_tables["Multi-"]
            # If only one table, use directly; if multiple tables (not merged), need to merge
            if len(multi_dfs) == 1:
                merged_tables["Multi-"] = self.filter_invalid_rows(multi_dfs[0].dropna(how="all"))
            elif len(multi_dfs) > 1:
                # Multiple Multi- tables need merging (vertical merge, add rows)
                # Keep first table's first 2 header rows, other tables start from row 3 (skip first 2 header rows)
                first_df = multi_dfs[0].copy()
                other_dfs = []

                for df in multi_dfs[1:]:
                    if df is None or df.empty:
                        continue
                    # Other tables start from row 3 (index 2 onwards, skip first 2 header rows)
                    if len(df) > 1:
                        df_data = df.iloc[1:].copy()
                        other_dfs.append(df_data)

                # Vertical merge: first table completely kept (including first 2 header rows), other tables only data rows
                if other_dfs:
                    merged_df = pd.concat([first_df] + other_dfs, ignore_index=True)
                else:
                    merged_df = first_df

                merged_tables["Multi-"] = self.filter_invalid_rows(merged_df.dropna(how="all"))

        pom_header = {
            "**ToleranceModel": "",
            "**PomDescription": field_values.get("pom_description", ""),
            "**GradingMethod": "",
            "**GradingModel": "",
            "**GradingUom": field_values.get("grading_uom", ""),
            "**BaseSize": field_values.get("base_size", ""),
            "**SizeRange": field_values.get("size_range", ""),
        }

        # Dynamically allocate Seq, start numbering from 1 based on actual tables
        pom_json = colorways_json = multi_json = {}
        seq_counter = 1

        if "Dimensions" in merged_tables:
            # === Use generic function to standardize POM table ===
            pom_df = self.standardize_dataframe(
                merged_tables["Dimensions"],
                POM_COLUMN_MAPPING,
                POM_FIXED_HEADERS
            )

            # Call generation function (Mapping passed None because already mapped)
            pom_json = self.df_to_bom_json(
                pom_df,
                None,
                None,
                seq=seq_counter,
                type_name="POM",
                header=pom_header,
                increment_display=field_values.get("increment_display")
            )
            seq_counter += 1
        else:
            print("⚠️ Dimensions table not found, skipping POM")

        if "Colorways" in merged_tables:
            # === Use generic function to standardize Colorways table ===
            # Colorway table usually doesn't need dynamic columns, strictly output by header, so drop_extra_columns=True
            colorways_df = self.standardize_dataframe(
                merged_tables["Colorways"],
                COLORWAY_COLUMN_MAPPING,
                COLORWAY_FIXED_HEADERS,
                drop_extra_columns=True
            )

            colorways_json = self.df_to_bom_json(
                colorways_df,
                None,
                None,
                seq=seq_counter,
                type_name="Colorway",
                header={}
            )
            seq_counter += 1
        else:
            print("⚠️ Colorways table not found, skipping Colorway")

        if "Multi-" in merged_tables:
            # Multi- table special processing: columns after color in ColumnHeader are Colorway
            multi_df = self.clean_columns(merged_tables["Multi-"].copy())

            # Build special ColumnHeader
            color_col_idx = None
            for idx, col in enumerate(multi_df.columns):
                col_str = str(col).strip().lower()
                if 'color' in col_str:
                    color_col_idx = idx
                    break

            # Build ColumnHeader: columns before color are normal, find "List of Materials Product Color Color Specification" from columns after color
            custom_column_header = []
            colorway_list = []
            colorway_col_indices = []  # List of all colorway column indices (all columns after color column before last column)
            color_spec_row_idx = None  # Row index of "List of Materials Product Color Color Specification"
            color_spec_col_indices = []  # List of column indices corresponding to "List of Materials Product Color Color Specification"

            if color_col_idx is not None:
                # BOM_header: use globally defined BOM_FIXED_HEADERS
                # Copy a copy from global list as default columns
                default_columns = list(BOM_FIXED_HEADERS)
                custom_column_header.extend(default_columns)

                # Build mapping of actual table column names to indices (for data extraction)
                actual_column_to_idx = {}
                for idx in range(color_col_idx + 1):
                    col_name = str(multi_df.columns[idx]).strip()
                    actual_column_to_idx[col_name] = idx

                # Find all colorway columns (all columns after color column before last column)
                start_idx = color_col_idx + 1
                end_idx = len(multi_df.columns) - 1  # Exclude last column
                colorway_col_indices = list(range(start_idx, end_idx))

                # Find "List of Materials Product Color Color Specification" from columns after color
                # Iterate through all possible header rows (usually first few rows)
                if len(multi_df) > 0 and colorway_col_indices:
                    for row_idx in range(min(3, len(multi_df))):
                        found_in_this_row = False
                        for col_idx in colorway_col_indices:
                            val = multi_df.iloc[row_idx, col_idx]
                            if pd.notna(val) and str(val).strip():
                                val_str = str(val).strip()
                                if 'List of\nMaterials\nProduct\nColor Color\nSpecification' in val_str:
                                    if color_spec_row_idx is None:
                                        color_spec_row_idx = row_idx
                                        colorway_list.append(val_str)
                                    # Record all column indices containing "List of Materials Product Color Color Specification"
                                    if col_idx not in color_spec_col_indices:
                                        color_spec_col_indices.append(col_idx)
                                    found_in_this_row = True
                        if found_in_this_row:
                            break

                # If "List of Materials Product Color Color Specification" column found, add Colorway object
                if colorway_list:
                    custom_column_header.append({"Colorway": colorway_list})

                # Add last column

            else:
                # If color column not found, use all column names
                custom_column_header = list(multi_df.columns)

            # Manually build JSON (because need custom ColumnHeader)
            # Identify product rows and colorway rows, merge colorways of same product into one data row
            data_rows = []
            if len(multi_df) > 1 and color_col_idx is not None:
                # Find Product column index (usually first column, index 0)
                product_col_idx = 0

                current_product_row = None
                current_product_data = None
                current_colorway_values = []

                for idx in range(1, len(multi_df)):
                    row = multi_df.iloc[idx]

                    # Get value of Product column
                    product_val = row.iloc[product_col_idx] if product_col_idx < len(row) else None
                    product_str = str(product_val).strip() if pd.notna(product_val) else ""

                    # Check if invalid row (grouping row, footer, etc.)
                    if product_str and ("(Blanks)" in product_str or "Displaying" in product_str):
                        continue

                    # Check if product row (Product column has value and not None)
                    is_product_row = product_str and product_str.lower() != "none"

                    # Check if colorway row (Product column is None or empty, but Color column has value)
                    is_colorway_row = False
                    if not is_product_row and color_spec_col_indices:
                        # Check if Color column has value
                        for col_idx in color_spec_col_indices:
                            color_val = row.iloc[col_idx] if col_idx < len(row) else None
                            if pd.notna(color_val) and str(color_val).strip():
                                is_colorway_row = True
                                break

                    if is_product_row:
                        # If previous product row exists, save it first
                        if current_product_data is not None:
                            # Add colorway values
                            if current_colorway_values:
                                current_product_data.append({"Colorway": current_colorway_values})
                            else:
                                current_product_data.append({"Colorway": []})
                            data_rows.append(current_product_data)

                        # Start new product row
                        current_product_row = idx
                        current_colorway_values = []

                        # Extract product row data
                        row_data = []
                        # Columns before color: extract values from actual table based on mapping and fixed header
                        # Use BOM_COLUMN_MAPPING
                        for target_col in default_columns:
                            val = ""  # Default empty value

                            # 1. Try to find actual column through Mapping
                            # Reverse lookup Mapping: Value(target_col) -> Key(actual_col)
                            found_col = False
                            for actual_col_name, mapped_name in BOM_COLUMN_MAPPING.items():
                                if mapped_name == target_col:
                                    if actual_col_name in actual_column_to_idx:
                                        col_idx = actual_column_to_idx[actual_col_name]
                                        val = row.iloc[col_idx]
                                        if val == "\ue5ca": val = "Y"
                                        val = str(val) if pd.notna(val) else ""
                                        found_col = True
                                    break

                            # 2. If not found in Mapping, try direct lookup with target_col (assume not renamed)
                            if not found_col and target_col in actual_column_to_idx:
                                col_idx = actual_column_to_idx[target_col]
                                val = row.iloc[col_idx]
                                val = str(val) if pd.notna(val) else ""

                            row_data.append(val)

                        # Check if product row has colorway values (color content on same row as product name)
                        if colorway_list and color_spec_col_indices and color_spec_row_idx is not None:
                            # Iterate colorway columns to find columns with values in this row
                            for col_idx in color_spec_col_indices:
                                # Check if this column has value in product row (value of "List of Materials Product Color Color Specification")
                                val = row.iloc[col_idx] if col_idx < len(row) else None
                                if pd.notna(val) and str(val).strip():
                                    colorway_val = str(val).strip()
                                    # Only add non-empty values, avoid duplicates
                                    if colorway_val and colorway_val not in current_colorway_values:
                                        current_colorway_values.append(colorway_val)

                        current_product_data = row_data

                    elif is_colorway_row and current_product_data is not None:
                        # This is colorway row, extract colorway values and add to current product's colorway list
                        # For each colorway row, need to find corresponding colorway column and extract "List of Materials Product Color Color Specification" value
                        if colorway_list and color_spec_col_indices and color_spec_row_idx is not None:
                            # Iterate colorway columns to find columns with values in this row
                            # Each colorway row may correspond to multiple colorway columns (one colorway per column), need to extract all columns with values
                            for col_idx in color_spec_col_indices:
                                # Check if this column has value in colorway row (value of "List of Materials Product Color Color Specification")
                                val = row.iloc[col_idx] if col_idx < len(row) else None
                                if pd.notna(val) and str(val).strip():
                                    colorway_val = str(val).strip()
                                    # Only add non-empty values, avoid duplicates
                                    if colorway_val and colorway_val not in current_colorway_values:
                                        current_colorway_values.append(colorway_val)

                # Save last product row
                if current_product_data is not None:
                    # Add colorway values
                    if current_colorway_values:
                        current_product_data.append({"Colorway": current_colorway_values})
                    else:
                        current_product_data.append({"Colorway": []})
                    data_rows.append(current_product_data)

            multi_json = {
                "Seq": seq_counter,
                "Type": "BOM",
                "Name": "BOM",
                "Header": {},
                "ColumnHeader": custom_column_header,
                "Data": data_rows
            }
            seq_counter += 1
            print(f"✅ Processed Multi- table, extracted {len(colorway_list)} Colorway(s) to ColumnHeader")
        else:
            print("⚠️ Multi- table not found, skipping Multi-level Placements")

        tech_pack_extraction_json = {
            "TECH_PACK_EXTRACTION": {
                "TechPackHeader": {
                    "**Customer": tamp_json["CUSTOMER"],
                    "**StyleNo": tamp_json["STYLE_NO"],
                    "**StyleDescription": "",
                    "**Season": tamp_json["SEASON"],
                    "**Status": tamp_json["TECH_PACK_STATUS"],
                    "**Department": tamp_json["DEPARTMENT"],
                    "**Vendor": field_values.get("vendor", ""),
                    "**ProductCategoryGroup": "",
                    "**ProductCategory": "",
                    "**RepeatOrderSeason": "",
                    "**NewCarryOverRepeated": field_values.get("NewCarryOverRepeated", ""),
                    "**ReferenceStyleNo": "",
                    "**PrimaryMaterial": "",
                    "**InDC": "",
                    "**Fit": "",
                    "**Wash": "",
                    "**Color": "",
                    "**Size": "",
                    "**Brand": "",
                    "customer_product_type": rpa_json.get("customer_product_type", "")

                },
                "Table": [t for t in [pom_json, colorways_json, multi_json] if t]
            },
            "TECH_PACK_FILE": {
                "TECH_PACK_FILE_CONTAINER_NAME": "teckpackdoc",
                "TECH_PACK_FILE_FILE_NAME": os.path.basename(pdf_path),
                "TECH_PACK_FILE_STORAGE_NAME": "salftseanpteckpack01"
            },
            "TP_MGMT_RECORD_ID": ""
        }

        tamp_json["TECH_PACK_EXTRACTION"] = tech_pack_extraction_json["TECH_PACK_EXTRACTION"]
        tamp_json = self.replace_newlines_in_json(tamp_json)
        return tamp_json

