class ExtractionServiceFactory:
    """
    Factory class to create appropriate extraction service based on customer code   
    """

    _services: Dict[str, Type[BaseExtractionService]] = {
        "LandsEnd": LandsEndExtractionService,
        "Etam Lingerie": EtamLingerieExtractionService,
        "The William Carter Company": OAExtractionService,
        "Undiz": EtamUndizExtractionService,
        "WALMART": WalmartExtractionService,
        "DOEN": DOENExtractionService,
        # Add more customer services here
    }

    @classmethod
    def create_service(cls, customer_name: str) -> BaseExtractionService:
        """
        Create extraction service for specific customer

        Args:
            customer_name: Customer identifier (e.g., 'LandsEnd', 'AEO')

        Returns:
            Appropriate extraction service instance
        """
        service_class = cls._services.get(customer_name)

        if service_class:
            return service_class()
        else:
            # Return default service or raise exception
            raise ValueError(
                f"No extraction service found for customer: {customer_name}")

    @classmethod
    def register_service(
        cls, customer_code: str, service_class: Type[BaseExtractionService]):
        """Register a new customer extraction service"""
        cls._services[customer_code.upper()] = service_class

    @classmethod
    def get_supported_customers(cls) -> List[str]:
        """Get list of supported customer names"""
        return list(cls._services.keys())

