def clean_text(text: str) -> str:
    """清理文本中的 PDF 字符引用 (cid:X)"""
    if not text:
        return ""
    return re.sub(r'\(cid:\d+\)', '', text).strip()

def clean_cell(cell) -> str:
    if cell is None:
        return ""
    text = str(cell).strip().replace("\n", " ")
    # 清理 PDF 中未解析的字符引用 (cid:X)
    return clean_text(text)

class BaseExtractor(ABC):
    def __init__(self, pdf_path: str):
        self.pdf_path = pdf_path
        self.pdf = None
        if not Path(pdf_path).exists():
            raise FileNotFoundError(f"PDF not found: {pdf_path}")

    @abstractmethod
    def extract(self, stats: Optional[ExtractionStats] = None) -> Any:
        raise NotImplementedError

    def _open_pdf(self) -> None:
        self.pdf = pdfplumber.open(self.pdf_path)

    def _close_pdf(self) -> None:
        if self.pdf:
            self.pdf.close()
            self.pdf = None

    def __enter__(self):
        self._open_pdf()
        return self

    def __exit__(self, *args):
        self._close_pdf()
        return False

class WalmartHeaderExtractor(BaseExtractor):
    def extract(self, stats: Optional[ExtractionStats] = None) -> WalmartTechPackHeader:
        if not self.pdf:
            self._open_pdf()
        if not self.pdf:
            return WalmartTechPackHeader()  # type: ignore
        if not self.pdf.pages:
            return WalmartTechPackHeader()  # type: ignore

        page = self.pdf.pages[0]
        company_id = self._extract_company_id(page)
        full_text = page.extract_text() or ""

        lines = full_text.split("\n")
        header_lines = []
        for line in lines:
            if "SKETCH:" in line or "MATERIALS /" in line or "MATERIALS/" in line:
                break
            header_lines.append(line)

        header_text = " ".join(header_lines)
        result = self._parse_text(header_text.strip(), company_id)

        if stats:
            stats.header_fields = result

        return WalmartTechPackHeader(**result)

    def _extract_company_id(self, page) -> str:
        tables = page.extract_tables() or []
        if not tables:
            return ""
        for row in tables[0][1:5]:
            non_empty = [c.strip() for c in row if c and c.strip()]
            if non_empty:
                last = non_empty[-1]
                if last.isupper() and 2 <= len(last) <= 10 and ':' not in last and '#' not in last:
                    return last
        return ""

    def _parse_text(self, text: str, company_id: str = "") -> Dict[str, str]:
        result: Dict[str, str] = {}
        label_positions = []
        for label_text, field_name in HEADER_LABELS:
            idx = text.find(label_text)
            if idx != -1:
                label_positions.append((idx, idx + len(label_text), field_name))
        label_positions.sort(key=lambda x: x[0])

        is_vertical = "\n" in company_id if company_id else False
        id_chars = company_id.split("\n") if is_vertical else []
        char_idx = 0

        for i, (start_label, end_label, field_name) in enumerate(label_positions):
            if field_name in result:
                continue
            value_start = end_label
            value_end = label_positions[i + 1][0] if i + 1 < len(label_positions) else len(text)
            value = text[value_start:value_end].strip()
            # 横排：整个 company_id 粘在某个值末尾
            if company_id and not is_vertical and value.endswith(company_id):
                value = value[:-len(company_id)].strip()
            # 竖排：company_id 各字符按顺序散落在不同字段值末尾
            if is_vertical and char_idx < len(id_chars) and value:
                parts = value.rsplit(None, 1)
                if len(parts) == 2 and parts[-1] == id_chars[char_idx]:
                    value = parts[0].strip()
                    char_idx += 1
                elif len(parts) == 1 and parts[0] == id_chars[char_idx]:
                    value = ""
                    char_idx += 1
            if value:
                result[field_name] = value
        return result

class WalmartBOMExtractor(BaseExtractor):
    def extract(self, stats: Optional[ExtractionStats] = None) -> List[WalmartBOMTable]:
        all_bom_data = []
        colorway_names = []
        tables = []

        for flavor in ['lattice', 'stream']:
            try:
                tables = camelot.read_pdf(self.pdf_path, pages='all', flavor=flavor)
                if tables:
                    if stats:
                        stats.camelot_flavor = flavor
                        stats.tables_found = len(tables)
                    break
            except Exception:
                continue

        if not tables:
            return []

        for table in tables:
            df = table.df
            table_text = " ".join(" ".join(str(c) for c in row) for _, row in df.iterrows()).upper()

            if "MATERIALS" in table_text and ("FABRICATION" in table_text or "BOM" in table_text):
                if stats:
                    stats.bom_tables += 1
                data = self._extract_bom_from_camelot(df, stats)
                all_bom_data.extend(data)

            if "CLRWAY" in table_text or "COMBO" in table_text:
                if stats:
                    stats.colorway_tables += 1
                colors = self._extract_colorway_from_camelot(df)
                colorway_names.extend(colors)
                if stats:
                    stats.colorways.extend(colors)

        if all_bom_data:
            unique_data = self._deduplicate_bom_data(all_bom_data)
            if stats:
                stats.data_rows = len(unique_data)

            column_header = list(BOM_COLUMN_HEADER)
            # 不在 BOM 表格中添加 Colorway，Colorway 单独作为一个表格
            return [WalmartBOMTable(Seq=1, ColumnHeader=column_header, Data=unique_data)] # type: ignore
        return []

    def _extract_bom_from_camelot(self, df, stats: Optional[ExtractionStats] = None) -> List[List[str]]:
        result = []
        current_category = ""
        column_map = {}
        pending_row = None
        in_bom_section = False

        for idx, row in df.iterrows():
            cells = [clean_text(str(c).strip()) for c in row]
            first_cell = cells[0].upper() if cells[0] else ""
            row_text = " ".join(cells).upper()

            if not any(cells):
                continue

            if first_cell == "BOM" or row_text.strip() == "BOM":
                in_bom_section = True
                continue

            if not in_bom_section:
                continue

            rest_empty = all(not c for c in cells[1:])
            if first_cell and rest_empty and self._is_category_row(first_cell):
                if pending_row:
                    result.append(pending_row)
                    pending_row = None
                current_category = first_cell
                column_map = {}
                if stats and current_category not in stats.categories_detected:
                    stats.categories_detected.append(current_category)
                continue

            if "COMPONENT" in row_text and ("CODE" in row_text or "DESCRIPTION" in row_text):
                column_map = self._build_column_map(cells)
                if stats:
                    stats.headers_detected.append("COMPONENT/CODE")
                continue
            if "STITCH TYPE" in row_text and "LOCATION" in row_text:
                column_map = self._build_column_map(cells)
                if stats:
                    stats.headers_detected.append("STITCH TYPE/LOCATION")
                continue

            if not current_category:
                continue

            if not cells[0] and any(cells[1:]):
                # 检查是否是噪音数据行（只有单个短字符如 "0"）
                non_empty_cells = [c for c in cells[1:] if c]
                if len(non_empty_cells) == 1 and len(non_empty_cells[0]) <= 2:
                    # 跳过噪音数据行
                    continue
                if pending_row:
                    for i, cell in enumerate(cells):
                        if cell:
                            field = self._get_field_by_col(column_map, i)
                            if field:
                                field_idx = BOM_FIELD_ORDER.index(field) if field in BOM_FIELD_ORDER else -1
                                if field_idx >= 0:
                                    if pending_row[field_idx]:
                                        pending_row[field_idx] += " " + cell
                                    else:
                                        pending_row[field_idx] = cell
                continue

            if pending_row:
                result.append(pending_row)

            pending_row = self._parse_data_row(cells, current_category, column_map)

        if pending_row:
            result.append(pending_row)

        return result

    def _is_category_row(self, text: str) -> bool:
        text_upper = text.upper().strip()
        header_keywords = ["COMPONENT", "CODE", "DESCRIPTION", "PLACEMENT", "LOCATION", "QUANTITY", "SIZE", "STITCH TYPE"]
        for kw in header_keywords:
            if kw in text_upper:
                return False
        if ":\n" in text:
            return False
        if "\n" in text and text.strip().endswith(":"):
            return False
        if len(text_upper) > 50:
            return False
        if re.search(r'\d+[/\-]\d+.*["\']', text_upper):
            return False
        return True

    def _build_column_map(self, header_cells: List[str]) -> Dict[str, int]:
        column_map = {}
        first_cell = header_cells[0] if header_cells else ""
        if "\n" in first_cell and "COMPONENT" in first_cell.upper():
            return {"MaterialType": 0, "MaterialDescription": 1, "Placement": 3, "Quantity": 4, "Size": 5}

        header_text = " ".join(str(c).upper() for c in header_cells)
        is_stitch_header = "STITCH TYPE" in header_text  # noqa: F841

        header_field_map = {
            "COMPONENT": "MaterialType", "STITCH TYPE": "MaterialType",
            "CODE": "MaterialDescription", "CONTENT": "MaterialDescription",
            "DESCRIPTION": "MaterialDescription", "CODE/CONTENT/DESCRIPTION": "MaterialDescription",
            "PLACEMENT": "Placement",
            "LOCATION": "Placement",  # LOCATION 始终映射到 Placement
            "PLACEMENT / LOCATION": "Placement", "QUANTITY": "Quantity", "SIZE": "Size",
        }

        for i, cell in enumerate(header_cells):
            cell_upper = cell.upper()
            for key, field in header_field_map.items():
                if key in cell_upper and field not in column_map:
                    column_map[field] = i
                    break
        return column_map

    def _get_field_by_col(self, column_map: Dict[str, int], col_idx: int) -> Optional[str]:
        for field, idx in column_map.items():
            if idx == col_idx:
                return field
        return None

    def _parse_data_row(self, cells: List[str], category: str, column_map: Dict[str, int]) -> Optional[List[str]]:
        material_type = description = placement = quantity = size = ""
        first_cell = cells[0] if cells else ""

        if "MATERIALS" in category.upper() and '\n' in first_cell and ':' in first_cell:
            if first_cell.strip().endswith(':'):
                parts = first_cell.rsplit('\n', 1)
                description = parts[0].strip()
                material_type = parts[1].rstrip(':').strip() if len(parts) > 1 else ""
            else:
                parts = first_cell.split('\n', 1)
                material_type = parts[0].rstrip(':').strip()
                description = parts[1].strip() if len(parts) > 1 else ""
        elif column_map:
            material_type = cells[column_map.get('MaterialType', 0)] if 'MaterialType' in column_map else ""
            desc_col = column_map.get('MaterialDescription', -1)
            if 0 <= desc_col < len(cells):
                description = cells[desc_col]
            placement_col = column_map.get('Placement', -1)
            if 0 <= placement_col < len(cells):
                placement = cells[placement_col]
            qty_col = column_map.get('Quantity', -1)
            if 0 <= qty_col < len(cells):
                quantity = cells[qty_col]
            size_col = column_map.get('Size', -1)
            if 0 <= size_col < len(cells):
                size = cells[size_col]
        else:
            material_type = cells[0] if len(cells) > 0 else ""
            description = cells[1] if len(cells) > 1 else ""

        material_type = material_type.rstrip(":").strip()
        if not material_type or material_type.upper() in ["BOM", "COMPONENT", "CODE", "STITCH TYPE"]:
            return None

        if '\n' in description and not placement:
            parts = description.split('\n', 1)
            description = parts[0].strip()
            placement = parts[1].strip() if len(parts) > 1 else ""

        row = [""] * len(BOM_FIELD_ORDER)
        field_values = {
            "BomHeader": "BOM", "MaterialCategory": category, "MaterialType": material_type,
            "MaterialDescription": description, "Quantity": quantity, "Placement": placement, "Size": size,
        }
        for i, field in enumerate(BOM_FIELD_ORDER):
            if field in field_values:
                row[i] = field_values[field]
        return row

    def _extract_colorway_from_camelot(self, df) -> List[str]:
        colorway_names = []
        for _, row in df.iterrows():
            for cell in row:
                cell_str = clean_text(str(cell))
                # 处理多个 CLRWAY NAME 合并在一个单元格的情况
                # 如: "CLRWAY NAME: ABLUE CLRWAY NAME: BRED"
                if "CLRWAY" in cell_str.upper():
                    parts = re.split(r'(?=CLRWAY\s*NAME)', cell_str, flags=re.I)
                    for part in parts:
                        if part.strip():
                            match = re.search(r'CLRWAY\s*NAME[:\s]*(.+)', part.strip(), re.I)
                            if match:
                                name = match.group(1).strip()
                                if name and name != ":":
                                    colorway_names.append(name)
        return colorway_names

    def _deduplicate_bom_data(self, data: List[List[str]]) -> List[List[str]]:
        seen = set()
        result = []
        for row in data:
            # 使用 MaterialCategory, MaterialType, MaterialDescription, Placement 作为去重 key
            # 不同分类下的相同内容不应该被去重
            key = (
                row[1] if len(row) > 1 else "",  # MaterialCategory
                row[3] if len(row) > 3 else "",  # MaterialType
                row[4] if len(row) > 4 else "",  # MaterialDescription
                row[9] if len(row) > 9 else ""   # Placement
            )
            if key not in seen and any(key[1:3]):
                seen.add(key)
                result.append(row)
        return result

class WalmartColorwayExtractor(BaseExtractor):
    def extract(self, stats: Optional[ExtractionStats] = None) -> List[WalmartColorwayTable]:
        """使用 camelot 提取 Colorway 表格"""
        colorway_data = []

        # 使用 camelot 提取表格
        tables = []
        for flavor in ['lattice', 'stream']:
            try:
                tables = camelot.read_pdf(self.pdf_path, pages='all', flavor=flavor)
                if tables:
                    break
            except Exception:
                continue

        if not tables:
            return []

        for table in tables:
            df = table.df
            table_text = " ".join(" ".join(str(c) for c in row) for _, row in df.iterrows()).upper()

            if "COMBO" in table_text and "CLRWAY" in table_text:
                colorways = self._extract_colorways_from_camelot(df)
                colorway_data.extend(colorways)

        if colorway_data:
            unique_colorways = list(dict.fromkeys(colorway_data))
            return [WalmartColorwayTable(Seq=1, ColumnHeader=COLORWAY_COLUMN_HEADER,
                                         Data=[[name, code, ""] for name, code in unique_colorways])]
        return []

    def _extract_colorways_from_camelot(self, df) -> List[Tuple[str, str]]:
        """从 camelot DataFrame 提取 colorway 信息 - 处理合并单元格"""
        colorways = []

        # 找到 COMBO 行和 CLRWAY 行
        combo_row = None
        clrway_row = None

        for _, row in df.iterrows():
            row_text = " ".join(clean_text(str(c)) for c in row).upper()
            if "COMBO" in row_text:
                combo_row = [clean_text(str(c).strip()) for c in row]
            if "CLRWAY NAME" in row_text:
                clrway_row = [clean_text(str(c).strip()) for c in row]

            # 如果两行都找到了，进行配对
            if combo_row is not None and clrway_row is not None:
                # 提取所有 COMBO（按出现顺序，处理合并）
                # 格式: "COMBO#1 - Tonal Leaves" 或 "COMBO #1" 或 "COMBO#1"
                combo_list = []
                for cell in combo_row:
                    # 按 COMBO 分割处理多个 COMBO 在同一单元格的情况
                    parts = re.split(r'(?=COMBO)', cell, flags=re.I)
                    for part in parts:
                        part = part.strip()
                        if part and part.upper().startswith('COMBO'):
                            # 清理末尾的 " -" 或 "-"
                            combo_name = re.sub(r'\s*-\s*$', '', part).strip()
                            combo_list.append(combo_name)

                # 提取所有 CLRWAY（按出现顺序，处理合并）
                clrway_list = []
                for cell in clrway_row:
                    if "CLRWAY" in cell.upper():
                        parts = re.split(r'(?=CLRWAY\s*NAME)', cell, flags=re.I)
                        for part in parts:
                            if part.strip():
                                m = re.search(r'CLRWAY\s*NAME[:\s]*(.*)', part.strip(), re.I)
                                if m:
                                    name = m.group(1).strip()
                                    clrway_list.append(name if name and name != ":" else "")

                # 智能配对：如果 COMBO 数量多于 CLRWAY，取后面的 COMBO（跳过 Style# 区域的）
                if len(combo_list) > len(clrway_list):
                    combo_list = combo_list[-len(clrway_list):]

                # 按顺序配对
                for i, combo_name in enumerate(combo_list):
                    clrway_name = clrway_list[i] if i < len(clrway_list) else ""
                    colorways.append((combo_name, clrway_name))

                # 重置
                combo_row = None
                clrway_row = None

        return colorways

