class PostAuthorization:
    def __init__(self, user):
        self.current_user = user
        self.techpack_mgmt_svc = TechPackManagementService()

    def perform_action(self, action):
        match action:
            case PostAuthorizationAction.SAVE_SESSION:
                return self._save_session()
            case PostAuthorizationAction.RETRIEVE_SCOPE:
                return self._retrieve_scope()
            case _:
                return False


    def _save_session(self):
        try:
            techpack_filtration_attrs, techpack_permissions = (
                self.techpack_mgmt_svc.build_techpack_filtration_attributes(self.current_user))

            if self.current_user:
                self.current_user.permissions = techpack_permissions
        except Exception as err:
            logger.exception(err)
            logger.error("[save session] TraceBack: " + str(traceback.format_exc()))
            return False

        session["user"] = {
            "info": self.current_user,
            "techpack_filtration_attrs": techpack_filtration_attrs
        }

        return True

    def _retrieve_scope(self):
        """
        Retrieve granted permissions for the current user
        """
        if not self.current_user:
            return []

        try:
            techpack_filtration_attrs, techpack_permissions = (
                self.techpack_mgmt_svc.build_techpack_filtration_attributes(self.current_user))

            if self.current_user:
                self.current_user.permissions = techpack_permissions
        except Exception as err:
            logger.exception(err)
            logger.error("[save session] TraceBack: " + str(traceback.format_exc()))
            return False

        return {
            "info": self.current_user,
            "techpack_filtration_attrs": techpack_filtration_attrs
        }

