class BoundedThreadPoolExecutor(ThreadPoolExecutor):
    """ThreadPoolExecutor with bounded queue for costing operations"""

    def __init__(self, max_workers=None, thread_name_prefix='', *args, **kwargs):
        super().__init__(max_workers, thread_name_prefix, *args, **kwargs)
        self._work_queue = queue.Queue(maxsize=ASYNC_COSTING_QUEUE_MAX_SIZE)

    def submit_nonblocking(self, fn, *args, **kwargs):
        """Submit task without blocking if queue is full"""
        try:
            future = super().submit(fn, *args, **kwargs)
            return future
        except queue.Full:
            logger.warning(
                f"Costing queue is full (max size: {ASYNC_COSTING_QUEUE_MAX_SIZE}). "
                f"Dropping task: {fn.__name__}"
            )
            return None

    def get_queue_size(self):
        return self._work_queue.qsize()

