class CostingService:
    _instance = None
    _lock = threading.Lock()
    _initialized = False

    def __new__(cls, *args, **kwargs):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super(CostingService, cls).__new__(cls)
        return cls._instance

    def __init__(self, max_workers=2):
        if self._initialized:
            logger.warning("CostingService already initialized.")
            return

        with self._lock:
            if self._initialized:
                return

            # Fewer workers for heavy costing operations
            self.executor = BoundedThreadPoolExecutor(
                max_workers=max_workers,
                thread_name_prefix="costing_worker"
            )

            atexit.register(self.shutdown)
            self._register_signal_handlers()
            self._initialized = True

            logger.info(f"CostingService initialized with {max_workers} workers")

    def _register_signal_handlers(self):
        """Register signal handlers for graceful shutdown"""
        import signal

        def signal_handler(signum, frame):
            logger.info(f"Received signal {signum} - shutting down costing service")
            self.shutdown()

            # Exit the application
            sys.exit(0)

        try:
            signal.signal(signal.SIGTERM, signal_handler)
            signal.signal(signal.SIGINT, signal_handler)
            logger.info("Signal handlers registered")
        except ValueError:
            logger.warning("Could not register signal handlers (not main thread)")

    @classmethod
    def get_instance(cls):
        if cls._instance is None:
            cls._instance = cls(max_workers=ASYNC_COSTING_MAX_WORKERS)
        return cls._instance

    def async_retrieve_cm_cost(self, retrieve_cm_cost_func, request_params: dict, is_manual_sync, context=None):
        """
        Submit CM cost retrieval task - fire and forget

        :param retrieve_cm_cost_func: The function to execute
        :param request_params: Parameters for CM cost retrieval
        :param context: Additional context
        :return: Future object or None if queue is full
        """
        try:
            future = self.executor.submit_nonblocking(
                retrieve_cm_cost_func,
                request_params,
                is_manual_sync,
                context
            )

            if future:
                queue_size = self.executor.get_queue_size()
                logger.info(
                    f"CM cost retrieval task submitted. "
                    f"Queue size: {queue_size}/{ASYNC_COSTING_QUEUE_MAX_SIZE}"
                )
            else:
                logger.warning("Failed to submit CM cost retrieval task - queue full")

            return future

        except Exception as e:
            logger.error(f"Failed to submit CM cost retrieval task: {e}")
            return None

    def async_retrieve_yy_cost(self, retrieve_yy_cost_func, request_params: dict, is_manual_sync, context=None):
        """
        Submit YY cost retrieval task - fire and forget
        """
        try:
            future = self.executor.submit_nonblocking(
                retrieve_yy_cost_func,
                request_params,
                is_manual_sync,
                context
            )

            if future:
                queue_size = self.executor.get_queue_size()
                logger.info(
                    f"YY cost retrieval task submitted. "
                    f"Queue size: {queue_size}/{ASYNC_COSTING_QUEUE_MAX_SIZE}"
                )
            else:
                logger.warning("Failed to submit YY cost retrieval task - queue full")

            return future

        except Exception as e:
            logger.error(f"Failed to submit YY cost retrieval task: {e}")
            return None

    def get_status(self):
        """Get service status for monitoring"""
        return {
            'queue_size': self.executor.get_queue_size(),
            'max_queue_size': ASYNC_COSTING_QUEUE_MAX_SIZE,
            'max_workers': ASYNC_COSTING_MAX_WORKERS,
            'active_threads': threading.active_count()
        }

    def shutdown(self):
        """Graceful shutdown"""
        try:
            logger.info("Shutting down costing service...")
            self.executor.shutdown(wait=False)
            logger.info("Costing service shutdown complete")
        except Exception as e:
            logger.error(f"Error during costing service shutdown: {e}")

