class TechPackManagementService:
    def __init__(self, current_user_session=None):
        self.current_user_session = current_user_session
        self.techpack_repo = TechpackRepository()
        self.techpack_image_repo = TechpackImageRepository(current_user_session)
        self.techpack_image_svc = TechPackImageService(current_user_session)
        self.techpack_comparison_repo = TechpackComparisonLogRepository()

    def search_composition_similar_style_fabric(self, techpack_group_unique_id, partial_query: dict,
                                                context=None):
        if context is None:
            context = {}

        try:
            logger.info(f"partial query str: {partial_query}")
            compositions = partial_query.get("composition", [])
            logger.info(f'compositions str: {json.dumps(compositions)}')
            if isinstance(compositions, str):
                return []

            full_search_regex = ''
            for com in compositions:
                if com.strip() == '':
                    continue

                escaped_str = re.escape(r'\d{1,2}%')
                logger.info(f'Search composition: {com}, {escaped_str}')
                search_regex = re.sub(r'\d+(\.\d+)?%', r'\\d{1,2}\\%', com)
                if full_search_regex == '':
                    full_search_regex = f'"{search_regex}"'
                else:
                    full_search_regex += f',"{search_regex}"'
            if full_search_regex == '':
                return []
            full_search_regex = f'\[{full_search_regex}\]'
            logger.info(f'Search composition similar: {full_search_regex}')
            customer_techpack_latest_repository = CustomerTechpackStyleLatestRepository(
                current_user_session=self.current_user_session)

            return customer_techpack_latest_repository.get_fabric_similarity_similar_to_search(
                techpack_group_unique_id, full_search_regex, context=context)
        except TypeError as ex:
            logger.exception(ex)
            logger.error("TraceBack: " + str(traceback.format_exc()))
        except Exception as e:
            logger.exception(e)
            logger.error("TraceBack: " + str(traceback.format_exc()))
        return []

    #6. any item within the list, trim only composition & origin, partial composition elements & percentage match
    def search_composition_any_style_fabric(self, techpack_group_unique_id, partial_query: dict, context=None):
        if context is None:
            context = {}

        try:
            logger.info(f"partial query str: {partial_query}")
            compositions = partial_query.get("composition", [])
            logger.info(f'compositions str: {json.dumps(compositions)}')
            if isinstance(compositions, str):
                return []

            full_search_regex = ''
            for com in compositions:
                if com.strip() == '':
                    continue

                if full_search_regex == '':
                    full_search_regex = f'"{com}"'
                else:
                    full_search_regex += f'|"{com}"'
            if full_search_regex == '':
                return []
            full_search_regex = f'({full_search_regex})'.replace("%", "\%")
            logger.info(f'Search composition similar: {full_search_regex}')
            customer_techpack_latest_repository = CustomerTechpackStyleLatestRepository(
                current_user_session=self.current_user_session)

            return customer_techpack_latest_repository.get_fabric_similarity_similar_to_search(
                techpack_group_unique_id, full_search_regex, context=context)
        except TypeError as ex:
            logger.exception(ex)
            logger.error("TraceBack: " + str(traceback.format_exc()))
        except Exception as e:
            logger.exception(e)
            logger.error("TraceBack: " + str(traceback.format_exc()))
        return []

    def build_techpack_filtration_attributes(self, curr_user):
        # if current user is null then raise error
        if curr_user is None:
            error_message = "[build_techpack_filtration_attributes] ERROR: User is not found."
            raise Exception(error_message)

        # if current user is admin then no need to restrict access
        if curr_user.is_admin():
            return [], []

        # else, retrieve granted techpack attributes for current user
        techpack_repo = TechpackRepository()
        error_message, records = techpack_repo.get_techpack_filtration_attributes(curr_user)
        if error_message:
            raise Exception(error_message)

        filtration_attrs, permissions = [], []
        for record in records:
            cust_name = record[0]
            perms = record[1]

            if cust_name not in filtration_attrs:
                filtration_attrs.append(cust_name)

            if not permissions:
                continue

            for perm in perms:
                if perm not in permissions:
                    permissions.append(perm)

        return filtration_attrs, permissions

    def eval_techpack_fabric_attr(self, data):
        if not data:
            return ""

        if isinstance(data, str):
            return data.strip()

        if isinstance(data, list) and len(data) > 0:
            return data[0]

        return ""

    def build_techpack_bom(self, data):
        if not data:
            raise Exception("[build_techpack_bom] Error: invalid data.")

        material = self.eval_techpack_fabric_attr(data.get("material_name", "") or "")
        material_no = data.get("material_no", "")
        compositions = data.get("composition", [])
        origin = data.get("origin", "")
        fabric_material_no, fabric_material, fabric_fiber, fabric_coo = None, None, None, None
        if material_no:
            fabric_material_no = FabricProperty(
                weight=MatchTypeWeight.MATERIAL_NO,
                items=[FabricPropertyItem(value=material_no.strip())]
            )

        if material:
            component = data.get('component', '')
            if component:
                material = f'{material}-{component}'

            fabric_material = FabricProperty(
                weight=MatchTypeWeight.MATERIAL,
                items=[FabricPropertyItem(value=material.strip())]
            )

        if compositions:
            fabric_prop_items = []
            for comp in compositions:
                fiber_percentage = comp.get('fiber_pecentage') or None
                if not fiber_percentage:
                    continue

                fiber_content = comp.get('fiber_content') or None
                if not fiber_content:
                    continue

                fiber = f'{fiber_percentage} {fiber_content.strip()}'
                fabric_prop_items.append(FabricPropertyItem(value=fiber))
                origin = comp.get('fiber_coo') or ''

            fabric_fiber = FabricProperty(
                weight=MatchTypeWeight.FIBER,
                items=fabric_prop_items
            )

        if origin:
            fabric_coo = FabricProperty(
                weight=MatchTypeWeight.COO,
                items=[FabricPropertyItem(value=origin.strip())]
            )

        return Fabric(
            material=fabric_material,
            material_no=fabric_material_no,
            fiber=fabric_fiber,
            coo=fabric_coo
        )

    def build_techpack_fabric(self, data):
        if not data:
            raise Exception("[build_techpack_fabric] Error: invalid data.")

        if isinstance(data, list):
            data = data[0]

        full_description = self.eval_techpack_fabric_attr(data.get("full_desc") or "")
        material = self.eval_techpack_fabric_attr(data.get("description") or "")
        compositions = data.get("composition") or []
        origin = self.eval_techpack_fabric_attr(data.get("origin") or "")

        fabric_material_no, fabric_material, fabric_fiber, fabric_coo = None, None, None, None
        material_no = material.split(" ") and material.split(" ")[0] or ""
        if material_no.strip() == "" or not material_no.isdigit():
            material_no = full_description.split("-") and full_description.split("-")[0] or ""

        if material_no:
            fabric_material_no = FabricProperty(
                weight=MatchTypeWeight.MATERIAL_NO,
                items=[FabricPropertyItem(value=material_no.strip())]
            )

        if material:
            fabric_material = FabricProperty(
                weight=MatchTypeWeight.MATERIAL,
                items=[FabricPropertyItem(value=material.strip())]
            )

        if compositions:
            fabric_fiber = FabricProperty(
                weight=MatchTypeWeight.FIBER,
                items=[FabricPropertyItem(value=comp.strip()) for comp in compositions]
            )

        if origin:
            fabric_coo = FabricProperty(
                weight=MatchTypeWeight.COO,
                items=[FabricPropertyItem(value=origin.strip())]
            )

        return Fabric(
            material=fabric_material,
            material_no=fabric_material_no,
            fiber=fabric_fiber,
            coo=fabric_coo
        )

    def compare_techpack_fabric(self, source: Fabric, target: Fabric):
        def _compare(src_prop, tar_prop):
            source_props = sorted([item.value for item in src_prop.items])
            target_props = sorted([item.value for item in tar_prop.items])
            if source_props == target_props:
                src_prop.match_type = MatchType.EXACT_MATCH
                src_prop.score = src_prop.weight.value
                return

            if any(item in target_props for item in src_prop.items):
                src_prop.match_type = MatchType.PARTIAL_MATCH
                src_prop.score = src_prop.weight.value / 2
                return

            for src_item in source_props:
                for tg_item in target_props:
                    if is_similar_text(src_item, tg_item):
                        src_prop.match_type = MatchType.PARTIAL_MATCH
                        src_prop.score = src_prop.weight.value / 2
                        return

            src_prop.match_type = MatchType.NO_MATCH
            return

        if source.material_no and target.material_no:
            _compare(source.material_no, target.material_no)

        if source.material and target.material:
            _compare(source.material, target.material)

        if source.fiber and target.fiber:
            _compare(source.fiber, target.fiber)

        if source.coo and target.coo:
            _compare(source.coo, target.coo)

        return source.compute_total_score()

    def sort_techpack_bom_similarity(self, found_techpacks: list, partial_query: dict, context=None):
        tuple_found_techpacks = [(techpack, 0) for techpack in found_techpacks]
        if not partial_query:
            return tuple_found_techpacks

        queried_bom_detail_name = context.get('queried_bom_detail_name', '')
        if not queried_bom_detail_name:
            return tuple_found_techpacks

        res, search_fabric = [], None
        try:
            search_fabric = self.build_techpack_fabric(partial_query)
        except Exception as e:
            logger.error(f"[sort_techpack_bom_similarity] Error: {str(e)}")
            return tuple_found_techpacks

        for techpack in found_techpacks:
            bom_str = techpack[14] or ""
            if not bom_str:
                continue

            max_score = 0
            for bom_item in json.loads(bom_str):
                bom_details = bom_item.get('details') or []
                if not bom_details:
                    continue

                try:
                    for bom_detail in bom_details:
                        bom_detail_name = bom_detail.get('bom_detail_name', '')
                        if not bom_detail_name:
                            continue

                        if bom_detail_name.lower() != queried_bom_detail_name.lower():
                            continue

                        techpack_bom = self.build_techpack_bom(bom_detail)
                        compared_score = self.compare_techpack_fabric(techpack_bom, search_fabric)
                        max_score = max(max_score, compared_score)

                except Exception as e:
                    logger.error(f"[sort_techpack_bom_similarity] Error: {str(e)}")
                    continue

            res.append((techpack, max_score))

        logger.info("[sort_techpack_bom_similarity] %s"
                    % [f"techpack_style_log_id: {item[0][0]} - total_score: {item[1]}" for item in res])

        result = [items for items in sorted(res, key=lambda x: x[1], reverse=True) if items[1] > 0]
        return result

    def sort_techpack_fabric_similarity(self, found_techpacks: list, partial_query: dict):
        tuple_found_techpacks = [(techpack, 0) for techpack in found_techpacks]
        if not partial_query:
            return tuple_found_techpacks

        res, search_fabric = [], None
        try:
            search_fabric = self.build_techpack_fabric(partial_query)
        except Exception as e:
            logger.error(f"[sort_techpack_fabric_similarity] Error: {str(e)}")
            return tuple_found_techpacks

        for techpack in found_techpacks:
            fabric_str = techpack[8] or ""
            if not fabric_str:
                continue

            try:
                max_score = 0
                for fabric_item in json.loads(fabric_str):
                    techpack_fabric = self.build_techpack_fabric(fabric_item)
                    compared_score = self.compare_techpack_fabric(techpack_fabric, search_fabric)
                    max_score = max(max_score, compared_score)

                res.append((techpack, max_score))
            except Exception as e:
                logger.error(f"[sort_techpack_fabric_similarity] Error: {str(e)}")
                continue

        logger.info("[sort_techpack_fabric_similarity] %s"
                    % [f"techpack_style_log_id: {item[0][0]} - total_score: {item[1]}" for item in res])
        result = [items for items in sorted(res, key=lambda x: x[1], reverse=True) if items[1] > 0]
        return result

    def group_techpack_bom_details(self, data, customer_name=None):
        def get_bom_detail_displayed_name(bom_detail_name, bom_detail_secs):
            sections = [item for item in bom_detail_secs if item['bom_detail_name'].lower() == bom_detail_name.lower()]
            if not sections:
                return bom_detail_name, False

            displayed_name = sections and sections[0]['label']
            is_section_grouped = sections and sections[0].get('is_grouped', False) or False
            return displayed_name, is_section_grouped

        bom_detail_visible, bom_detail_sections = self.get_bom_detail_configs(customer_name)
        if not bom_detail_visible:
            return {}, []

        res = {}
        grouped_bom_detail_names = []
        try:
            bom_data = json.loads(data)
        except Exception as e:
            logger.error(f"[get_bom_details] Error: {str(e)}")
            return res, []

        for data in bom_data:
            part = data.get('part') or ''
            if not part:
                continue

            bom_detail_obj, part_obj = {}, {part: {}}
            for d in data.get('details') or []:
                bom_detail_name = d['bom_detail_name'] or ""
                if not bom_detail_name:
                    continue

                bom_detail_name, is_grouped = get_bom_detail_displayed_name(bom_detail_name, bom_detail_sections)
                if is_grouped:
                    if bom_detail_name not in grouped_bom_detail_names:
                        grouped_bom_detail_names.append(bom_detail_name)

                style_fabric = self._standardize_fabric_formation(d)
                usage = d.get('usage') or ''
                placement = d.get("placement") or ""
                customers_accept_placement = CUSTOMERS_BOM_ACCEPT_PLACEMENT.split("&_")
                if style_fabric:
                    bom_detail_vals = {
                        "style_fabric": json.dumps([style_fabric]),
                        "use": placement if usage == "" and customer_name in customers_accept_placement else usage,
                    }

                    if bom_detail_name not in bom_detail_obj:
                        bom_detail_obj[bom_detail_name] = [bom_detail_vals]
                    else:
                        bom_detail_obj[bom_detail_name].append(bom_detail_vals)

            part_obj[part] = bom_detail_obj
            res.update(part_obj)

        return res, grouped_bom_detail_names

    def compute_techpack_bom_details(self, data, customer_name=None):
        res = []
        try:
            grouped_bom_details, grouped_bom_detail_names = self.group_techpack_bom_details(
                data, customer_name=customer_name)
        except Exception as e:
            logger.error(f"[compute_techpack_bom_details] Error: {str(e)}")
            return res

        if not grouped_bom_details:
            return res

        bom_details_length = len(grouped_bom_details)
        res = [None] * bom_details_length
        left_idx, right_idx = 0, bom_details_length - 1
        for key, val in grouped_bom_details.items():
            if not key or not val:
                continue

            part = {
                "part_name": key,
                "part_items": []
            }
            num_grouped = 0
            for k, v in val.items():
                is_grouped = True if k in grouped_bom_detail_names else False
                if is_grouped:
                    num_grouped += 1

                part["part_items"].append({
                    'bom_detail_name': k,
                    'bom_detail_items': v,
                    'is_grouped': is_grouped
                })

            if left_idx > right_idx:
                break

            if num_grouped == len(part["part_items"]):
                res[right_idx] = part
                right_idx -= 1
            else:
                res[left_idx] = part
                left_idx += 1

        res = [item for item in res if item]
        return res

    def get_bom_detail_configs(self, customer_name):
        customer_vals = CustomerRepository().find_customer(customer_name)
        if not customer_vals:
            raise Exception("Customer %s not found" % customer_name)

        layout_cfgs = customer_vals[5] or None
        if not layout_cfgs:
            return False, None

        try:
            layout_cfgs = json.loads(layout_cfgs)
        except Exception as e:
            logger.error(f"[get_bom_detail_displayed_name] Error: {str(e)}")
            raise Exception("Cannot parse json value")

        page_detail_layout_cfgs = [item for item in layout_cfgs if item['page'] == 'home.tp-detail']
        page_detail_layout_cfg_components = page_detail_layout_cfgs and page_detail_layout_cfgs[0]['components']
        bom_detail_cfgs = [item for item in page_detail_layout_cfg_components if
                           item['componentId'] == 'home.tp-detail.bom']
        bom_detail_visible = bom_detail_cfgs and bom_detail_cfgs[0]['visible']
        bom_detail_sections = bom_detail_cfgs and bom_detail_cfgs[0]['sections']

        return bom_detail_visible, bom_detail_sections

    def _standardize_fabric_formation(self, bom_detail: dict) -> dict:
        res = {}
        full_desc_items, desc_items, comp_items, coo = [], [], [], ''
        material_no = bom_detail.get('material_no', '')
        if material_no:
            material_no = material_no.replace(',', '').replace('.', '')
            material_no = material_no.strip()
            if material_no not in full_desc_items:
                full_desc_items.append(material_no)

            if material_no not in desc_items:
                desc_items.append(material_no)

        material_name = bom_detail.get('material_name', '')
        if material_name:
            material_name = material_name.strip()
            if material_name not in full_desc_items:
                full_desc_items.append(material_name)

            if material_name not in desc_items:
                desc_items.append(material_name)

        component = bom_detail.get('component', '')
        if component:
            component = component.strip()
            if component not in full_desc_items:
                full_desc_items.append(component)

            if component not in desc_items:
                desc_items.append(component)

        compositions = bom_detail.get('composition', []) or []
        if not compositions:
            compositions = bom_detail.get('compositions', []) or []

        for comp in compositions:
            fiber_percentage = comp.get('fiber_pecentage', '') or ''
            fiber_content = comp.get('fiber_content', '') or ''
            if not fiber_content and not fiber_percentage:
                continue 

            fibers = []
            fiber_percentage = str(fiber_percentage)
            if fiber_percentage:
                if '%' not in fiber_percentage:
                    fiber_percentage += '%'
                fibers.append(fiber_percentage)

            if fiber_content:
                fibers.append(fiber_content)

            fiber = ''
            if fibers:
                fiber = ' '.join(fibers)    

            if fiber not in full_desc_items:
                full_desc_items.append(fiber)

            if fiber not in comp_items:
                comp_items.append(fiber)

            coo = comp.get('fiber_coo', '')
            coo = coo and coo.strip() or ''

        if full_desc_items:
            full_desc = ' - '.join(full_desc_items)
            res.update({
                'full_desc': full_desc,
            })

        if desc_items:
            desc = ' - '.join(desc_items)
            res.update({
                'description': desc,
            })

        if comp_items:
            res.update({
                'composition': comp_items,
            })

        if coo:
            res.update({
                'origin': coo,
            })

        return res

    def get_bom_sections_mapping_by_customer(self, customer_name):
        if not customer_name:
            return None

        bom_detail_visible, bom_detail_sections = self.get_bom_detail_configs(customer_name)
        if not bom_detail_visible:
            return None

        res = {}
        for item in bom_detail_sections:
            bom_label = item.get('label', '')
            if not bom_label or not isinstance(bom_label, str):
                continue

            bom_detail_name = item.get('bom_detail_name', '')
            if not bom_detail_name or not isinstance(bom_detail_name, str):
                continue

            bom_label = bom_label.strip()
            bom_detail_name = bom_detail_name.strip()
            res.update({
                bom_label: bom_detail_name,
            })

        return res

    def download_techpack_attachment_pdf(self, pdf_filenames, customer_name=None):
        azureStorageContainerService = AzureStorageContainerService()
        attachment_pdf_folder_dir = "./TEMP/Pdf/"
        output_filename = f"TECHPACK_{customer_name}" if customer_name else "TECHPACK"

        if customer_name and NUM_TECHPACK_FILE_DOWNLOADABLE_PER_CUSTOMER:
            try:
                num_file_downloadable_per_customer = json.loads(NUM_TECHPACK_FILE_DOWNLOADABLE_PER_CUSTOMER)

                default_num_file_downloadable = num_file_downloadable_per_customer.get("default", None)
                if not default_num_file_downloadable:
                    return jsonify({
                        "error_message": "Default allowed download file count is not configured."
                    }), 400

                num_file_downloadable = num_file_downloadable_per_customer.get(customer_name, default_num_file_downloadable)
                if num_file_downloadable and len(pdf_filenames) > num_file_downloadable:
                    logger.error(f"[download_techpack_attachment_pdf] Number of requested files {len(pdf_filenames)} exceeds the allowed download file count {num_file_downloadable} for customer {customer_name}.")
                    return jsonify({
                        "error_message": f"Number of requested files exceeds the allowed download file count of {num_file_downloadable} for customer {customer_name}."
                    }), 400

            except Exception as e:
                logger.error(f"[download_techpack_attachment_pdf] Error parsing allowed download file count: {str(e)}")
                return jsonify({
                    "error_message": "Error parsing allowed download file count configuration."
                }), 400

        attachment_pdf_folder_file_paths = []
        for pdf_file in pdf_filenames:
            tp_source = pdf_file["source"]
            blob_name_split = pdf_file["file_name"].split("/")[1:]
            ts = str(round(time.time() * 1000))
            blob_name = "/".join(blob_name_split)
            local_attachment_pdf_file_path = os.path.join(attachment_pdf_folder_dir, f"{ts}-{blob_name_split[-1]}")
            download_blob_result = azureStorageContainerService.download_techpack_style_blob_to_file(
                blob_name, local_attachment_pdf_file_path, tp_source)

            if download_blob_result == False:
                logger.error("retrieve_techpack_attachment_files:: cannot download new techpack pdf")
                azureStorageContainerService.clean_local_files([local_attachment_pdf_file_path])
            else:
                attachment_pdf_folder_file_paths.append(local_attachment_pdf_file_path)

        output_filename = output_filename + "_" + str(round(time.time() * 1000)) + ".zip"
        with ZipFile(os.path.join(attachment_pdf_folder_dir, output_filename), "w") as zip:
            for attachment_pdf_folder_file in attachment_pdf_folder_file_paths:
                zip.write(attachment_pdf_folder_file)

        azureStorageContainerService.clean_local_files(attachment_pdf_folder_file_paths)
        return jsonify({
            "file_name": output_filename
        })

    def store_style_retail_prices_ref(
            self, cust_name: str, style_desc: str, 
            techpack_style_log_id: int = None) -> Tuple[bool, str]:
        """
        Fetch retail prices for the techpack style.

        :return: A list containing retail prices.
        """        

        err_message = ""
        if not cust_name or not style_desc:
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: cust_name or style_desc is missing in the request."
            logger.error(err_message)
            return False, err_message

        trend_engine_adapter = TrendEngineAdapter()
        retail_prices_ref = trend_engine_adapter.get_retail_prices(
            cust_name, style_desc)
        if not retail_prices_ref:
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: TEP response data is empty."
            logger.error(err_message)
            return False, err_message

        # if retail product image sorting is disabled, store the original retail prices ref
        is_sorting_disable = eval(IS_RETAIL_PRODUCT_IMAGES_SORTING_DISABLED)
        if is_sorting_disable:
            logger.warning(f"techpack_style_log_id - {techpack_style_log_id}: Retail product image sorting is disabled.")

            # store first original retail prices ref
            filtered_retail_prices_ref = [retail_prices_ref[0]]
            is_stored = self.techpack_repo.store_style_retail_prices_ref(
                cust_name, style_desc, 
                retail_prices_ref,
                filtered_retail_prices_ref)
            if not is_stored:
                err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to store retail prices ref."
                logger.error(err_message)
                return False, err_message

            return True, ""

        logger.info(f"Sorting Retail Products of {cust_name} - {style_desc} - {techpack_style_log_id}...")

        # download tp images
        downloaded_tp_img_paths = self.techpack_image_svc.download_techpack_product_images(techpack_style_log_id)

        # if cannot download any techpack image, store the original retail prices ref
        if not downloaded_tp_img_paths or (isinstance(downloaded_tp_img_paths, list) and len(downloaded_tp_img_paths) == 0):
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to download techpack product images. Style ID: {techpack_style_log_id}"
            logger.info(err_message)

        classified_tp_img_paths = self.techpack_image_svc.classify_images(downloaded_tp_img_paths)

        # if cannot classify any techpack image, store the original retail prices ref
        if not classified_tp_img_paths or (isinstance(classified_tp_img_paths, list) and len(classified_tp_img_paths) == 0):
            # clean up local files
            self.techpack_image_svc.clean_local_files(downloaded_tp_img_paths)
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to classify techpack product images. Style ID: {techpack_style_log_id}"
            logger.error(err_message)

            # store first original retail prices ref
            filtered_retail_prices_ref = [retail_prices_ref[0]]
            is_stored = self.techpack_repo.store_style_retail_prices_ref(
                cust_name, style_desc,
                retail_prices_ref,
                filtered_retail_prices_ref)
            if not is_stored:
                err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to store retail prices ref."
                logger.error(err_message)
                return False, err_message

            return True, ""

        classified_tp_img_path = classified_tp_img_paths[0]

        # download tep images
        downloaded_img_data = self.techpack_image_svc.download_retail_product_images(retail_prices_ref)

        # if cannot download any TEP image, store the original detail prices ref
        if not downloaded_img_data or (isinstance(downloaded_img_data, list) and len(downloaded_img_data) == 0):
            # clean up local files
            self.techpack_image_svc.clean_local_files(downloaded_tp_img_paths)
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to download TEP product images. Style Desc: {style_desc}"
            logger.error(err_message)

            # store first original retail prices ref
            filtered_retail_prices_ref = [retail_prices_ref[0]]
            is_stored = self.techpack_repo.store_style_retail_prices_ref(
                cust_name, style_desc, 
                retail_prices_ref,
                filtered_retail_prices_ref)
            if not is_stored:
                err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to store retail prices ref."
                logger.error(err_message)
                return False, err_message

            return True, ""

        # sort retail products by images        
        sorted_retail_products = self.techpack_image_svc.sort_retail_products_by_images(
            style_desc, downloaded_img_data, 
            classified_tp_img_path)

        # If cannot sort retail products, then get the first retail product as result and return
        if not sorted_retail_products or (isinstance(sorted_retail_products, list) and len(sorted_retail_products)) == 0:
            logger.info(f"techpack_style_log_id - {techpack_style_log_id}: No sorted retail products found. Get first retail product result from TEP.")
            filtered_retail_prices_ref = [retail_prices_ref[0]]

            # clean up local files
            local_img_paths = [item['local_img_path'] for item in downloaded_img_data if item.get('local_img_path')]
            local_img_paths.extend(downloaded_tp_img_paths)
            self.techpack_image_svc.clean_local_files(local_img_paths)

            # store results
            is_stored = self.techpack_repo.store_style_retail_prices_ref(
            cust_name, style_desc, 
            retail_prices_ref,
            filtered_retail_prices_ref)
            if not is_stored:
                err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to store retail prices ref."
                logger.error(err_message)
                return False, err_message

            return True, ""

        # clean up local files
        local_img_paths = [item['local_img_path'] for item in downloaded_img_data if item.get('local_img_path')]
        local_img_paths.extend(downloaded_tp_img_paths)
        self.techpack_image_svc.clean_local_files(local_img_paths)

        # re-order retail prices ref follows sorted retail products
        filtered_retail_prices_ref = []
        _uniq_items = set()
        for item in sorted_retail_products:
            original_img_url = item[0]
            for item in retail_prices_ref:
                if item.get('pic_url', '') != original_img_url:
                    continue

                if item.get('pic_url', '') in _uniq_items:
                    continue

                _uniq_items.add(item.get('pic_url', ''))
                filtered_retail_prices_ref.append(item)

        # apply iqr to find relevant items
        filtered_retail_prices_ref = self.filter_products_by_price_iqr(filtered_retail_prices_ref, outlier_factor=RETAIL_PRODUCT_IQR_OUTLIER_FACTOR)

        is_stored = self.techpack_repo.store_style_retail_prices_ref(
            cust_name, style_desc, 
            retail_prices_ref,
            filtered_retail_prices_ref)
        if not is_stored:
            err_message = f"techpack_style_log_id - {techpack_style_log_id}: Failed to store retail prices ref."
            logger.error(err_message)
            return False, err_message

        return True, ""

    def filter_products_by_price_iqr(self, retail_prices_ref: list, 
                                   outlier_factor: float = 1.5) -> list:
        """
        Simple IQR filtering based on prices

        Args:
            sorted_retail_products: List of tuples (url, path, rank, combined_score, reasoning)
            retail_prices_ref: List of price dictionaries with 'sales_price_usd'
            outlier_factor: IQR multiplier for outlier detection (default: 1.5)

        Returns:
            Filtered list of price dictionaries
        """
        if not retail_prices_ref or len(retail_prices_ref) < 4:
            logger.info("Not enough products for IQR filtering")
            return retail_prices_ref

        # Extract valid prices
        valid_products = []
        prices = []

        for product in retail_prices_ref:
            price = product.get('sales_price_usd')
            if price is not None and price > 0:
                try:
                    price_float = float(price)
                    prices.append(price_float)
                    valid_products.append(product)
                except (ValueError, TypeError):
                    continue

        if len(prices) < 4:
            logger.info("Not enough valid prices for IQR filtering")
            return retail_prices_ref

        # Calculate IQR
        prices_array = np.array(prices, dtype=np.float64)
        q1 = np.percentile(prices_array, 25, method='linear')
        q3 = np.percentile(prices_array, 75, method='linear')
        iqr = q3 - q1

        # Define outlier bounds
        lower_bound = q1 - (outlier_factor * iqr)
        upper_bound = q3 + (outlier_factor * iqr)

        # Filter products
        filtered_products = []
        for product in valid_products:
            price = float(product.get('sales_price_usd', 0))
            if lower_bound <= price <= upper_bound:
                filtered_products.append(product)

        logger.info("Success applied IQR filtering.")
        return filtered_products

