    def retrieve_techpack_images(self, techpack_style: CustomerTeckpackStyleLogModel, pdf_file_path=None, context=None) -> list:
        def embed_image(local_file_path):
            if not local_file_path or not os.path.exists(local_file_path):
                logger.error("[embed_image] Error: Local file path does not exist: %s" % local_file_path)
                return []

            # convert original image to vector
            is_success = True
            try:
                vector = self.techpack_image_svc.convert_origin_image_to_vector(local_file_path)
                faiss.normalize_L2(vector)
                logger.info("[embed_image] Embeded original image: %s" % local_file_path)

                return vector.ravel().tolist()
            except Exception as e:
                logger.error("[embed_image] Error: Unable to embed original image to vector: %s - %s" % (local_file_path, str(e)))
                is_success = False

            # if failed to convert original image, try to convert blob image
            if not is_success:
                try:
                    vector = self.techpack_image_svc.convert_blob_to_vector(local_file_path)
                    faiss.normalize_L2(vector)
                    logger.info("[embed_image] Embeded blob image: %s" % local_file_path)

                    return vector.ravel().tolist()
                except Exception as e:
                    logger.error("[embed_image] Error: Unable to embed sketch image to vector: %s - %s" % (local_file_path, str(e)))
                    return []

            return []

        if not context:
            context = {}

        non_plm_controller = NonplmTechpackController()

        # extract images from local file
        images_files = non_plm_controller.extract_unique_images_from_pdf(
            pdf_file_path, ADVANCED_SEARCH_LOCAL_WORKING_FOLDER_IMAGES)
        try:
            json_images_files = json.loads(images_files)
        except Exception as e:
            logger.error(f"[retrieve_techpack_images] ERROR: {e}")
            return []

        image_paths = [item['path'] for item in json_images_files if item.get('path')]
        if not image_paths:
            return []

        # classify images
        classified_image_paths = self.techpack_image_svc.classify_images(
            image_paths=image_paths, context=context)

        customer_name = techpack_style.customer_name or ''
        customer_department = techpack_style.customer_department or ''
        style_no = techpack_style.style_no or ''
        style_season = techpack_style.style_season or ''
        formatted_time = datetime.now().strftime('%Y%m%d%H%M%S')
        filename_prefix = '-'.join([item for item in [customer_name, customer_department,
                                                      style_no, style_season, formatted_time] if item])
        group_image_id = '_'.join([customer_name, customer_department, style_no, style_season])

        # Replace any character that is not a letter, number, hyphen, space or underscore
        filename_prefix = re.sub(r'[^A-Za-z0-9-_ ]+', '', filename_prefix)
        group_image_id = re.sub(r'[^A-Za-z0-9-_ ]+', '', group_image_id)

        # store extracted images
        insert_vals = []
        for img_path in classified_image_paths:
            image_id = f'{filename_prefix}_{(os.path.basename(img_path))}'
            original_image_embedded = embed_image(img_path)
            if not original_image_embedded:
                continue

            insert_vals.append({
                "image_id": image_id,
                "container_name": AZURE_STORAGE_CONTAINER_ADVANCED_SEARCH_INPUT_IMAGES,
                "storage_account_name": AZURE_STORAGE_ACCOUNT,
                "group_image_id": group_image_id,
                "original_image_embedding": original_image_embedded
            })

        if not insert_vals:
            logger.error("[retrieve_techpack_images] No embedding images found.")
            return []

        is_success = self.techpack_image_repo.insert_uploaded_images(insert_vals)
        if not is_success:
            return []

        # upload extracted images
        uploaded_images = non_plm_controller.upload_file_to_blobs_container(
            filename_prefix, pdf_file_path, classified_image_paths,
            context={
                'blob_container_pdf': AZURE_STORAGE_CONTAINER_ADVANCED_SEARCH_INPUT_PDF,
                'blob_container_image': AZURE_STORAGE_CONTAINER_ADVANCED_SEARCH_INPUT_IMAGES
            }
        )
        if not uploaded_images:
            return []

        uploaded_image_uris = [f"{AZURE_STORAGE_HOST}{AZURE_STORAGE_CONTAINER_ADVANCED_SEARCH_INPUT_IMAGES}/{img}"
                               for img in uploaded_images]

        return uploaded_image_uris

    def _collect_receipiant_emails(self, mr_receipiant_mapping_info, mr_receipiant_mapping_result, default_send_to):
        receipiant_emails_set = set()
        default_send_to_list = []
        if default_send_to:
            default_send_to_list = [t.strip().lower() for t in default_send_to]
            receipiant_emails_set.update(default_send_to_list)

        if mr_receipiant_mapping_result is None or mr_receipiant_mapping_result.strip() == '':
            logger.info(f"missed mr_receipiant_mapping_info: {mr_receipiant_mapping_info}; and mr_receipiant_mapping_result: {mr_receipiant_mapping_result}")
            return sorted(receipiant_emails_set)

        try:
            mr_receipiant_mapping_result_json = json.loads(mr_receipiant_mapping_result)
            lf_staff = mr_receipiant_mapping_result_json.get('lf_staff', '')
            lf_org_coordinator = mr_receipiant_mapping_result_json.get('lf_org_coordinator', '')
            if lf_staff:
                lf_staff_list = [t.strip().lower() for t in lf_staff.split(";")]
                receipiant_emails_set.update(lf_staff_list)
            if lf_org_coordinator:
                lf_org_coordinator_list = [t.strip().lower() for t in lf_org_coordinator.split(";")]            
                receipiant_emails_set.update(lf_org_coordinator_list)
            if receipiant_emails_set:
                return sorted(receipiant_emails_set)
            else:
                return None
        except json.JSONDecodeError as e:
            # e.msg, e.lineno, e.colno, e.pos, e.doc are available
            logger.error(f"Invalid JSON exception {e}")
            logger.error(f"missed mr_receipiant_mapping_info: {mr_receipiant_mapping_info}; and mr_receipiant_mapping_result: {mr_receipiant_mapping_result}")
            return None

    def _collect_receipiant_emails_base_on_type(self, mr_receipiant_mapping_info, mr_receipiant_mapping_result, default_send_to, email_type="lf_org_coordinator"):
        receipiant_emails_set = set()
        default_send_to_list = []
        if default_send_to:
            default_send_to_list = [t.strip().lower() for t in default_send_to]
            receipiant_emails_set.update(default_send_to_list)

        if mr_receipiant_mapping_result is None or mr_receipiant_mapping_result.strip() == '':
            logger.info(f"missed mr_receipiant_mapping_info: {mr_receipiant_mapping_info}; and mr_receipiant_mapping_result: {mr_receipiant_mapping_result}")
            return sorted(receipiant_emails_set)

        try:
            mr_receipiant_mapping_result_json = json.loads(mr_receipiant_mapping_result)
            lf_emails = None
            if 'lf_staff' == email_type:
                lf_emails = mr_receipiant_mapping_result_json.get('lf_staff', '')
            else:
                lf_emails = mr_receipiant_mapping_result_json.get('lf_org_coordinator', '')
            if lf_emails:
                lf_emails_list = [t.strip().lower() for t in lf_emails.split(";")]
                receipiant_emails_set.update(lf_emails_list)
            if receipiant_emails_set:
                return sorted(receipiant_emails_set)
            else:
                return None
        except json.JSONDecodeError as e:
            # e.msg, e.lineno, e.colno, e.pos, e.doc are available
            logger.error(f"Invalid JSON exception {e}")
            logger.error(f"missed mr_receipiant_mapping_info: {mr_receipiant_mapping_info}; and mr_receipiant_mapping_result: {mr_receipiant_mapping_result}")
            return None

    def compute_daily_ingestion_data(self, target_customer: str, days_back=1, default_send_to=None, context=None) -> Tuple[str, list]:
        if not context:
            context = {}

        res = []
        _uniq_keys_set = set()

        logger.info("Compute daily ingestion data...")

        # get daily ingestion data
        error_message, daily_ingestion_data = self.techpack_repo.fetch_daily_ingestion_data(target_customer=target_customer, days_back=days_back)
        if not daily_ingestion_data:
            return error_message, None

        # build data
        for item in daily_ingestion_data:
            techpack_style_log_id = item['latest_techpack_style_log_id'] or None
            customer_name = item['customer_name'] or ''
            customer_department = item['customer_department'] or ''
            display_name = item['display_name'] or ''
            season = item['style_season'] or ''
            style_no = item['style_no'] or ''
            style_desc = item['style_description'] or ''
            first_timestamp_lf_captured = item['first_timestamp_lf_captured'] or None
            mr_receipiant_mapping_info = item['mr_receipiant_mapping_info'] or ''
            mr_receipiant_mapping_result = item['mr_receipiant_mapping_result'] or ''
            receipiant_emails = self._collect_receipiant_emails(mr_receipiant_mapping_info, mr_receipiant_mapping_result, default_send_to)
            cm_yy_final_receipiant_result_str = None
            if receipiant_emails:
                cm_yy_final_receipiant_result_str = ";".join(receipiant_emails)

            #logger.info(f"Processing cm_yy_final_receipiant_result_str: {cm_yy_final_receipiant_result_str}")
            #logger.info(f"Processing cm_yy_final_receipiant_result_str: {receipiant_emails}")

            techpack_style_log_instance = CustomerTeckpackStyleLogModel(
                customer_name=customer_name,
                customer_department=customer_department,
                style_season=season,
                style_no=style_no,
                style_description=style_desc,
                teckpack_style_log_id=techpack_style_log_id,
                mr_receipiant_mapping_info=mr_receipiant_mapping_info,
                mr_receipiant_mapping_result=mr_receipiant_mapping_result
            )

            if (not techpack_style_log_id \
                    or not customer_name):
                continue

            techpack_style_log_instance.techpack_group_unique_id = generate_techpack_group_unique_id(techpack_style_log_instance)

            if error_message:
                logger.error(f"Failed to get last updated style log: {error_message}")
                return error_message, None

            # cm
            cm_cost = self.techpack_repo.get_cm_cost_by_techpack(techpack_style_log_instance)        
            cm = 0.0
            try:
                if cm_cost:
                    if not first_timestamp_lf_captured:
                        first_timestamp_lf_captured = cm_cost['first_timestamp_lf_captured'] or None
                    cm_res = transform_keys_to_camel_case(json.loads(cm_cost['xts_costing_cm']))
                    if cm_res:
                        cm_summaries = cm_res.get('costOfMakingSummary', [])
                        if cm_summaries:
                            cm = cm_summaries[0].get('cm', 0.0)
            except json.JSONDecodeError:
                logger.error("Failed to decode JSON for CM")
                return "Failed to decode JSON for CM", None

            # yy
            yy_cost = self.techpack_repo.get_yy_cost_by_techpack(techpack_style_log_instance)
            yy = 0.0
            try:
                if yy_cost:
                    if not first_timestamp_lf_captured:
                        first_timestamp_lf_captured = yy_cost['first_timestamp_lf_captured'] or None
                    yy_res = transform_keys_to_camel_case(json.loads(yy_cost['xts_costing_yy']))

                    if yy_res:
                        yy_units = yy_res.get('units', None)
                        yy_dimension = ''
                        if yy_units:
                            yy_dimension = yy_units.get('dimension', '')

                        yy_consumption = yy_res.get('mainFabricConsumption', {})
                        if yy_consumption:
                            yy_gross_length = yy_consumption.get('grossLength', 0.0)
                            if yy_dimension == "in":
                                yy = yy_gross_length / 36
                            else:
                                yy = yy_gross_length
            except json.JSONDecodeError:
                logger.error("Failed to decode JSON for YY")
                return "Failed to decode JSON for YY", None

            # retail prices ref
            retail_prices_ref = []
            if style_desc:
                data = self.techpack_repo.get_detail_prices_ref(
                    cust_name=customer_name, style_desc=style_desc)
                if data:
                    try:
                        parsed_data = json.loads(data)
                        for d in parsed_data:
                            price_ref = d.get('sales_price_usd', None)
                            if not price_ref:
                                continue

                            retail_prices_ref.append(float(price_ref))
                    except json.JSONDecodeError:
                        logger.error("Failed to decode JSON for detail prices reference")
                        pass

            sorted_retail_prices_ref = sorted(retail_prices_ref)
            retail_prices_ref_range = None
            if sorted_retail_prices_ref:
                min_price = sorted_retail_prices_ref[0]
                if min_price:
                    min_price = round(min_price, 2)
                min_price_notation = f'${min_price}'
                max_price = sorted_retail_prices_ref[-1]
                if max_price:
                    max_price = round(max_price, 2)
                max_price_notation = f'${max_price}'
                retail_prices_ref_range = " - ".join([min_price_notation, max_price_notation])

            style = {
                'techpack_style_log_id': techpack_style_log_id,
                'customer_name': customer_name,
                'display_name': display_name,
                'customer_department': item.get('customer_department', ''),
                'style_no': style_no,
                'style_description': style_desc,
                'season': season,
                'customer_techpack_status': item['customer_techpack_status'] or '',
                "first_timestamp_lf_captured": first_timestamp_lf_captured or '',
                "timestamp_lf_captured": item['timestamp_lf_captured'] or '',
                "mr_receipiant_mapping_info": mr_receipiant_mapping_info,
                "mr_receipiant_mapping_result": mr_receipiant_mapping_result,
                'receipiant_emails_str': cm_yy_final_receipiant_result_str,
                'receipiant_emails': receipiant_emails,
                'cm': cm and round(cm, 2) or 0.00,
                'yy': yy and round(yy, 2) or 0.00,
                'retail_prices_ref_range': retail_prices_ref_range or ''
            }

            _uniq_keys = (
                techpack_style_log_instance.techpack_group_unique_id,
            )
            if _uniq_keys in _uniq_keys_set:
                continue

            res.append(style)

        return None, res

    def compute_report_daily_comparison_data(self, target_customer: str, style_seasons: list, days_back=1, default_send_to=None, context=None) -> Tuple[str, list]:
        if not context:
            context = {}

        res = []
        exception_styles = []

        logger.info("Compute daily ingestion data...")

        # get daily ingestion data
        error_message, report_daily_ingestion_data = self.techpack_repo.report_daily_ingestion_data_oa(target_customer=target_customer, style_seasons=style_seasons, days_back=days_back)
        if not report_daily_ingestion_data:
            return error_message, None, None

        azureStorageContainerService = AzureStorageContainerService()

        # build data
        for item in report_daily_ingestion_data:
            techpack_style_log_id = item['teckpack_style_log_id'] or None
            customer_name = item['customer_name'] or ''
            customer_department = item['customer_department'] or ''
            display_name = item['display_name'] or ''
            season = item['style_season'] or ''
            style_no = item['style_no'] or ''
            style_desc = item['style_description'] or ''
            timestamp_lf_captured = item['timestamp_lf_captured'] or None
            mr_receipiant_mapping_info = item['mr_receipiant_mapping_info'] or None
            mr_receipiant_mapping_result = item['mr_receipiant_mapping_result'] or ''
            is_not_found_mapping = False
            if mr_receipiant_mapping_result is None or mr_receipiant_mapping_result == '':
                is_not_found_mapping = True
            else:
                mr_receipiant_mapping_result_json = json.loads(mr_receipiant_mapping_result)
                lf_org_coordinator = mr_receipiant_mapping_result_json.get('lf_org_coordinator', '')
                lf_staff = mr_receipiant_mapping_result_json.get('lf_staff', '')
                invalid_mapping = mr_receipiant_mapping_result_json.get('invalid_mapping', False)
                # if invalid_mapping:
                #     logger.info(f"Invalid mapping found for style_no: {mr_receipiant_mapping_result_json}")
                if not lf_org_coordinator and not lf_staff:
                    is_not_found_mapping = True
                if invalid_mapping == True:
                    is_not_found_mapping = True
            attchment_pdf_techpack = item['attchment_pdf_techpack'] or None
            techpack_source = item['techpack_source'] or None
            attchment_pdf_techpack_url = get_techpack_file_path(attchment_pdf_techpack, techpack_source == "non-plm", True)[0]
            tpm_url = f"{TPM_DOMAIN}/techpack/detail/{techpack_style_log_id}"
            receipiant_emails_lf_org_coordinator = self._collect_receipiant_emails_base_on_type(mr_receipiant_mapping_info, mr_receipiant_mapping_result, None, email_type="lf_org_coordinator")
            receipiant_emails_lf_staff = self._collect_receipiant_emails_base_on_type(mr_receipiant_mapping_info, mr_receipiant_mapping_result, None, email_type="lf_staff")
            bcc_emails_str = None
            if default_send_to:
                bcc_emails_str = ";".join(default_send_to)

            #receipiant_emails_lf_org_coordinator = self._collect_receipiant_emails_base_on_type(mr_receipiant_mapping_info, None, default_send_to, email_type="lf_org_coordinator")
            #receipiant_emails_lf_staff = self._collect_receipiant_emails_base_on_type(mr_receipiant_mapping_info, None, default_send_to, email_type="lf_staff")

            lf_org_coordinator_final_receipiant_result_str = None
            lf_staff_final_receipiant_result_str = None
            if receipiant_emails_lf_org_coordinator:
                lf_org_coordinator_final_receipiant_result_str = ";".join(receipiant_emails_lf_org_coordinator)
            if receipiant_emails_lf_staff:
                lf_staff_final_receipiant_result_str = ";".join(receipiant_emails_lf_staff)

            mr_receipiant_mapping_info_json = json.loads(mr_receipiant_mapping_info) if mr_receipiant_mapping_info else None
            vendor = None
            if mr_receipiant_mapping_info_json:
                vendor = mr_receipiant_mapping_info_json.get('parent_vendor', None)

            #logger.info(f"Processing cm_yy_final_receipiant_result_str: {cm_yy_final_receipiant_result_str}")
            #logger.info(f"Processing cm_yy_final_receipiant_result_str: {receipiant_emails}")

            techpack_style_log_instance = CustomerTeckpackStyleLogModel(
                customer_name=customer_name,
                customer_department=customer_department,
                style_season=season,
                style_no=style_no,
                style_description=style_desc,
                teckpack_style_log_id=techpack_style_log_id,
                timestamp_lf_captured=timestamp_lf_captured,
                mr_receipiant_mapping_info=mr_receipiant_mapping_info,
                mr_receipiant_mapping_result=mr_receipiant_mapping_result,
                attchment_pdf_techpack=attchment_pdf_techpack
            )

            if (not techpack_style_log_id \
                    or not customer_name):
                continue

            techpack_style_log_instance.techpack_group_unique_id = generate_techpack_group_unique_id(techpack_style_log_instance)

            if error_message:
                logger.error(f"Failed to get last updated style log: {error_message}")
                return error_message, None, None

            # previous version
            last_timestamp_lf_captured = None
            last_teckpack_style_log_id = None
            techpack_comparison_file_url = None
            two_techpack_style_logs = self.techpack_repo.get_top_2_teckpack_styles_order_lf_captured_time(techpack_style_log_instance)
            # logger.info(f"techpack_style_log_instance: {techpack_style_log_instance}")
            # logger.info(f"two_techpack_style_logs: {two_techpack_style_logs}")
            if two_techpack_style_logs is not None and (len(two_techpack_style_logs) >= 2):
                last_timestamp_lf_captured = two_techpack_style_logs[1][6]
                last_teckpack_style_log_id = two_techpack_style_logs[1][0]
                tp_comparison_log_row = self.techpack_comparison_repo.fetchone_success_techpack_comparison_log(techpack_style_log_id, last_teckpack_style_log_id)
                if (tp_comparison_log_row is not None):
                    techpack_comparison_file_url = azureStorageContainerService.get_techpack_comparison_file_url(
                        tp_comparison_log_row[7],
                        tp_comparison_log_row[8],
                        tp_comparison_log_row[9])

            # current techpack datetime
            current_datetime = None
            format_last_timestamp_lf_captured = ''
            if timestamp_lf_captured:
                current = convert_timezone(timestamp_lf_captured, 'Asia/Hong_Kong')
                current_datetime = format_timestamp(current) if current else ''
            if last_timestamp_lf_captured:
                last_timestamp_lf_captured = convert_timezone(last_timestamp_lf_captured, 'Asia/Hong_Kong')
                format_last_timestamp_lf_captured = format_timestamp(last_timestamp_lf_captured) if last_timestamp_lf_captured else ''

            style = {
                'techpack_style_log_id': techpack_style_log_id,
                'customer_name': customer_name,
                'display_name': display_name,
                'customer_department': item.get('customer_department', ''),
                'style_no': style_no,
                'season': season,
                'style_description': style_desc,
                'customer_techpack_status': item['customer_techpack_status'] or '',
                "timestamp_lf_captured": current_datetime or '',
                "last_timestamp_lf_captured": format_last_timestamp_lf_captured or '',
                "mr_receipiant_mapping_info": vendor,
                "is_not_found_mapping": is_not_found_mapping,
                "lf_org_coordinator_final_receipiant_result_str": lf_org_coordinator_final_receipiant_result_str,
                'lf_staff_final_receipiant_result_str': lf_staff_final_receipiant_result_str,
                'bcc_emails_str': bcc_emails_str,
                'attchment_pdf_techpack': attchment_pdf_techpack_url,
                'comparison_url': techpack_comparison_file_url,
                'tpm_url': tpm_url
            }

            if is_not_found_mapping:
                exception_styles.append(style)
            else:
                res.append(style)

        return None, res, exception_styles

