class TechPackSecurity:
    def __init__(self, curr_user_session):
        self.curr_user_session = curr_user_session

    def has_permission(self, permission_key):
        current_user = self.curr_user_session['info']
        if not current_user:
            return False

        if current_user.is_admin():
            return True

        if current_user.root == User.XTS_USER_ROOT:
            return True

        if not current_user.permissions:
            return False

        if permission_key not in current_user.permissions:
            return False

        return True

services/traceability.py::BoundedThreadP.source_code:
class BoundedThreadPoolExecutor(ThreadPoolExecutor):
    """
    A ThreadPoolExecutor that uses a bounded queue to prevent unbounded memory growth.
    """
    def __init__(self, max_workers=None, thread_name_prefix='', *args, **kwargs):
        super().__init__(max_workers, thread_name_prefix, *args, **kwargs)
        # Replace the default unbounded queue with a bounded one
        self._work_queue = queue.Queue(maxsize=TRACEABILITY_QUEUE_MAX_SIZE)

    def submit_nonblocking(self, fn, *args, **kwargs):
        """
        Submits a task to the pool. If the queue is full, it drops the task
        and returns False instead of blocking.
        """
        try:
            future = super().submit(fn, *args, **kwargs)
            return future
        except queue.Full:
            logger.info(
                f"Traceability queue is full (max size: {TRACEABILITY_QUEUE_MAX_SIZE}). Dropping new log task."
            )
            return None

    def get_queue_size(self):
        return self._work_queue.qsize()

