def extract_images_ship_to_xts(techpack_style_log_instance):
    logger.info("Start extract_images_ship_to_xts")
    results = []
    style_images = techpack_style_log_instance.attchment_image_style
    design_intents = techpack_style_log_instance.attchment_image_design_intents

    # Get cover image
    techpack_img_svc = TechPackImageService()
    cover_image_filename = None
    cover_image_urls = techpack_img_svc.get_cover_images_by_techpack_style_log_ids([techpack_style_log_instance.teckpack_style_log_id])
    if cover_image_urls and len(cover_image_urls) > 0:
        cover_image_url = cover_image_urls[techpack_style_log_instance.teckpack_style_log_id]
        cover_image_filename = cover_image_url.split("/")[-1]

    try:
        if style_images:
            for idx, style in enumerate(style_images):
                path = style['path']
                if path:
                    if techpack_style_log_instance.techpack_source == 'non-plm':
                        is_cover_image = "N"
                        if not cover_image_filename:
                             is_cover_image = "Y"
                        else:
                            if path.endswith(cover_image_filename):
                                is_cover_image = "Y"

                        results.append({
                            "IS_COVER_IMAGE": is_cover_image,
                            "IMAGE_FILE_URL": f"{AZURE_STORAGE_HOST}{AZURE_STORAGE_CONTAINER_TECHPACK_NONPLM}/{path}"
                        })
                    else:
                        is_cover_image = "N"
                        if idx == 0:
                            is_cover_image = "Y" # for PLM, first image is cover image 

                        results.append({
                            "IS_COVER_IMAGE": is_cover_image,
                            "IMAGE_FILE_URL": f"{AZURE_STORAGE_HOST}{AZURE_STORAGE_CONTAINER_TECHPACK_STYLE}/{path}"
                        })
        if design_intents:
            for design in design_intents:
                path = design['path']
                if path:
                    if techpack_style_log_instance.techpack_source == 'non-plm':
                        results.append({
                            "IS_COVER_IMAGE": "N",
                            "IMAGE_FILE_URL": f"{AZURE_STORAGE_HOST}{AZURE_STORAGE_CONTAINER_TECHPACK_NONPLM}/{path}"
                        })
                    else:
                        results.append({
                            "IS_COVER_IMAGE": "N",
                            "IMAGE_FILE_URL": f"{AZURE_STORAGE_HOST}{AZURE_STORAGE_CONTAINER_TECHPACK_STYLE}/{path}"
                        })
    except Exception as e:
        logger.error("extract_images_ship_to_xts:: Exception type: " + str(type(e)))
        logger.error("extract_images_ship_to_xts:: Unexpected: " + str(e))

    logger.info("End extract_images_ship_to_xts")
    return results

