def _to_camel_case(text):
    """Convert string to camelCase"""
    if not text or not isinstance(text, str):
        return text

    words = re.findall(r'[A-Z]*[a-z]+|[A-Z]+(?=[A-Z][a-z]|\b)|[0-9]+', text)
    if not words:
        return text

    return words[0].lower() + ''.join(word.capitalize() for word in words[1:])

utils/CommonUtil.py::transform_keys_to_c.source_code:
def transform_keys_to_camel_case(obj):
    """
    Recursively transform all dictionary keys to camelCase regardless of nesting depth
    """
    if isinstance(obj, dict):
        # Transform dictionary keys recursively
        return {
            _to_camel_case(key): transform_keys_to_camel_case(value)
            for key, value in obj.items()
        }
    elif isinstance(obj, list):
        # Transform each item in the list
        return [transform_keys_to_camel_case(item) for item in obj]
    elif isinstance(obj, tuple):
        # Transform each item in the tuple
        return tuple(transform_keys_to_camel_case(item) for item in obj)
    else:
        # Return primitive values as-is
        return obj

